INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1771860909898', 'CHEMINÉE SOLAIRE DU COLONEL ISIDORO CABANYES', 'SOLAR CHIMNEY BY COLONEL ISIDORO CABANYES', '1903',
  'De l’air est chauffé par effet de serre dans un vaste collecteur situé au niveau d’une plaine et conduit par une cheminée qui débouche en altitude, permettant ainsi de tirer profit de la différence de température et de l’énergie potentielle de convection disponible. À la base de la cheminée se trouvent des turbines entraînant des générateurs électriques permettant de produire de l’électricité.\n\nC’est l’Anglais Alfred Rosling Bennett qui publie le premier un brevet sur cette invention en 1897. Mais de nombreux ingénieurs y travaillent aussi par la suite. Un militaire espagnol, le colonel Isidoro Cabanyes, proposa en 1903 un modèle de tour solaire dans la revue La Energía eléctrica. Un modèle, construit en 1919 par Albert H. Holmes & Son est exposé au Science Museum de Londres.', 'Air is heated by the greenhouse effect in a large collector located on a plain and conducted through a chimney that opens at high altitude, thus taking advantage of the temperature difference and the potential convection energy available. At the base of the chimney are turbines that drive electric generators to produce electricity.\n\nThe Englishman Alfred Rosling Bennett was the first to publish a patent for this invention in 1897. However, many engineers also worked on it subsequently. In 1903, Spanish military officer Colonel Isidoro Cabanyes proposed a model of a solar tower in the journal La Energía eléctrica. A model built in 1919 by Albert H. Holmes & Son is on display at the Science Museum in London.', 'Mathieu Farges',
  'Espagne', 'Spain', 39.3260685, -4.8379791,
  'images/IMG_3709.jpeg', '', '', '2026-02-23', 'published', 1, '2026-02-23 15:35:09', '2026-02-23 15:35:09'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771860909898', 'solaire');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771860909898', 'electricite');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1771860985015', 'LE CHARIOT ÉLECTROMAGNÉTIQUE', 'THE ELECTROMAGNETIC TROLLEY', '1906',
  'En 1889, Jules Verne imaginait que, d’ici 2889, nos voyages se feraient dans des “tubes pneumatiques jetés à travers les océans”, filant à 1500 km/h. Bien mieux que nos TGV !\n\nEn 1906, Franklin Smith inventa un véhicule plus léger que les voitures de l’époque. Il supprima plusieurs pièces, ajouta un système d’électro-aimant sous le chariot, et proposa un moyen de le faire léviter grâce à un courant alternatif. À condition d’ajouter un certain poids, le chariot restait en suspension, sa vitesse dépendant du champ magnétique — constant, donc prévisible.\n\nL’Electric Carrier Co racheta ses brevets avec une idée : faire circuler courrier et colis d’une ville à l’autre grâce à ces chariots suspendus, chacun contrôlé individuellement pour éviter les collisions. Une ligne d’essai de 550 m fut installée à Paterson (New Jersey)… mais l’industrie ne suivit pas.\n\nL’idée, pourtant, persiste. En 2013, Elon Musk relance le rêve avec l’Hyperloop : des capsules supersoniques censées désengorger Los Angeles. Dix ans plus tard, le projet n’a toujours pas vu le jour.\nEt vous, quelles seraient vos idées de transport pour demain ?', 'In 1889, Jules Verne imagined that by 2889, we would be traveling in "pneumatic tubes shot across the oceans" at speeds of 1,500 km/h. Much better than our high-speed trains!\n\nIn 1906, Franklin Smith invented a vehicle that was lighter than the cars of the time. He removed several parts, added an electromagnet system under the carriage, and proposed a way to make it levitate using alternating current. Provided that a certain amount of weight was added, the carriage remained suspended, its speed depending on the magnetic field—which was constant and therefore predictable.\n\nThe Electric Carrier Co. bought his patents with an idea: to transport mail and parcels from one city to another using these suspended carriages, each controlled individually to avoid collisions. A 550-meter test line was installed in Paterson, New Jersey... but the industry did not follow suit.\n\nThe idea, however, persisted. In 2013, Elon Musk revived the dream with the Hyperloop: supersonic capsules designed to relieve traffic congestion in Los Angeles. Ten years later, the project has still not seen the light of day. What would be your ideas for the transport of tomorrow?', 'Vincent Muller',
  'New Jersey', 'New Jersey', 40.0757384, -74.4041622,
  'images/IMG_3710.jpeg', '', '', '2026-02-23', 'published', 1, '2026-02-23 15:36:25', '2026-02-23 15:36:25'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771860985015', 'electricite');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771860985015', 'deplacement');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1771861047777', 'LA PETITE COURONNE MARAÎCHÈRE DE PARIS', 'THE SMALL GREENBELT OF PARIS', '1912',
  'En 1912, la petite couronne parisienne comptait 2 500 maraîchers, formant une ceinture nourricière autour de la capitale. Ces exploitations, souvent installées sur des terrains peu fertiles, utilisaient des techniques innovantes et recyclaient les déchets urbains pour obtenir des rendements exceptionnels. Toutefois, l’urbanisation progressive a entraîné une diminution de ces activités, avec seulement 74 maraîchers recensés en 2010.\n\nAujourd’hui, un regain d’intérêt pour l’agriculture urbaine se manifeste en Île-de-France. Le nombre d’exploitations maraîchères a doublé entre 2010 et 2020, passant de 74 à 139, et les surfaces en maraîchage diversifié ont également augmenté. Des initiatives soutenues par les collectivités locales visent à réintroduire des formes d’agriculture de proximité, adaptées aux besoins contemporains en matière de durabilité et de souveraineté alimentaire.', 'In 1912, the inner suburbs of Paris were home to 2,500 market gardeners, forming a food belt around the capital. These farms, often located on less fertile land, used innovative techniques and recycled urban waste to achieve exceptional yields. However, gradual urbanization led to a decline in these activities, with only 74 market gardeners recorded in 2010. Today, there is a renewed interest in urban agriculture in the Île-de-France region. The number of market gardens doubled between 2010 and 2020, from 74 to 139, and the area devoted to diversified market gardening has also increased. Initiatives supported by local authorities aim to reintroduce forms of local agriculture adapted to contemporary needs in terms of sustainability and food sovereignty.', 'Raphaël Luciani-galais',
  'Paris', 'Paris', 48.8534951, 2.3483915,
  'images/IMG_3711.jpeg', '', 'https://www.inrae.fr/actualites/quand-petite-couronne-paris-etait-maraichere?utm_source=chatgpt.com', '2026-02-23', 'published', 1, '2026-02-23 15:37:27', '2026-02-23 15:37:27'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771861047777', 'agriculture');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1771861110085', 'TRANSPORT PAR TRACTEUR ÉLECTRIQUE', 'TRANSPORT BY ELECTRIC TRACTOR', '1920',
  'Depuis quelques années, la Société Les Transports Electriques de Paris a obtenu des services municipaux l’autorisation de mettre en service des chariots à accumulateurs, qui augmentent dans de grandes proportions la rapidité de la manutention.\n\nElle possède une quarantaine de chariots loués sans conducteur soit à des commerçants du quartier, soit à des entrepreneurs qui se chargent des transports à forfait. Ils servent à porter la viande, les pommes de terre (photographie), les primeurs, etc., effectuent des livraisons aux magasins d’alentour, aux voitures, qui stationnent en dehors du périmètre, aux gares. \n\nLa circulation de ces véhicules dans les endroits encombrés est des plus faciles ; pas d’à-coup, pas de bruit, pas d’odeur ni de dégagement gazeux susceptible de polluer les marchandises.', 'In recent years, the Paris Electric Transport Company has obtained authorization from municipal authorities to use battery-powered carts, which greatly increase the speed of handling.\n\nIt has around forty trucks rented without drivers to either local merchants or contractors who handle flat-rate transport. They are used to carry meat, potatoes (photograph), early produce, etc., and make deliveries to nearby stores, cars parked outside the perimeter, and train stations. \n\nThese vehicles are very easy to maneuver in congested areas; there are no jolts, no noise, no odors, and no gas emissions that could contaminate the goods.', 'Gilles Gallo',
  'Paris', 'Paris', 48.8534951, 2.3483915,
  'images/IMG_3712.jpeg', '', '', '2026-02-23', 'published', 1, '2026-02-23 15:38:30', '2026-02-23 15:38:30'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771861110085', 'deplacement');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771861110085', 'electricite');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771861110085', 'agriculture');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1771861173540', 'CAMIONS ÉLECTRIQUES LAPORTE & FILS & CIE', 'LAPORTE & FILS & CIE ELECTRIC TRUCKS', '1922 - 1925',
  'De 1922 à 1925, l’entreprise Laporte & Fils fut à l’origine des premiers camions électriques en France. Ils fonctionnaient uniquement grâce à des accumulateurs et des moteurs électriques. Il s’agissait de camions électriques lourds d’une capacité de 5 tonnes, mus par deux moteurs de 7 chevaux, montés directement sur l’essieu arrière. L’autonomie de ces véhicules était de 90 km. Ainsi, dans les années 1920, Paris utilisait des véhicules électriques pour ramasser les poubelles, mais aussi comme modes de transport en commun, comme camions de Poste… Cet usage fréquent de l’électricité pour les véhicules urbains décline néanmoins dans la seconde partie du XXe siècle.', 'From 1922 to 1925, the Laporte & Fils company was behind the first electric trucks in France. They ran solely on batteries and electric motors. These were heavy electric trucks with a capacity of 5 tons, powered by two 7-horsepower motors mounted directly on the rear axle. These vehicles had a range of 90 km. In the 1920s, Paris used electric vehicles to collect garbage, but also as public transportation, postal trucks, and more. However, this frequent use of electricity for urban vehicles declined in the second half of the 20th century.', 'Alexandre Barre',
  'France', 'France', 46.603354, 1.8883335,
  'images/IMG_3713.jpeg', '', '', '2026-02-23', 'published', 1, '2026-02-23 15:39:33', '2026-02-23 15:39:33'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771861173540', 'electricite');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771861173540', 'deplacement');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1771861391206', 'LES CENTRALES ÉLECTRIQUES GÉOTHERMIQUES AU JAPON', 'GEOTHERMAL POWER PLANTS IN JAPAN', '1925',
  'Le Japon possède la 3e réserve géothermique mondiale. Les sources chaudes y sont utilisées depuis plus de 3000 ans, notamment à travers les onsen, bains thermaux au cœur de la culture nippone. Les débuts de la géothermie électrique remontent à 1904 en Italie. Au Japon, c’est en 1919 que le directeur de la marine, Mansuji Yamauchi, lance une étude sur le potentiel de Beppu. Un premier générateur expérimental y voit le jour en 1925 (1,12 kW), suivi par la centrale de Matsukawa en 1966 (9,5 MW).\n\nAujourd’hui, le pays compte 18 centrales géothermiques et de nombreuses micro-installations. Pour un potentiel estimé à 23 GW, seules 535 MW sont installés, dont 500 MW depuis 1996. La géothermie représente à peine 0,2 % de l’électricité consommée, mais l’objectif pour 2030 est d’atteindre 1 %, avec 25 % d’énergies renouvelables dans le mix énergétique.\n\nLe développement de cette énergie est freiné par l’industrie du spa, qui occupe de nombreux sites exploitables, ainsi que par la protection des parcs nationaux, où se trouvent souvent les gisements. Pourtant, en 2015, la centrale de Tsuchiyu ouvre dans un parc national, en cohabitation avec un spa. Elle incarne une nouvelle orientation énergétique pour le Japon.', 'Japan has the third largest geothermal reserves in the world. Hot springs have been used there for over 3,000 years, particularly in onsen, thermal baths that are central to Japanese culture. The beginnings of geothermal power date back to 1904 in Italy. In Japan, it was in 1919 that the director of the navy, Mansuji Yamauchi, launched a study on the potential of Beppu. The first experimental generator was built there in 1925 (1.12 kW), followed by the Matsukawa power plant in 1966 (9.5 MW).\n\nToday, the country has 18 geothermal power plants and numerous micro-installations. With an estimated potential of 23 GW, only 535 MW have been installed, including 500 MW since 1996. Geothermal energy accounts for barely 0.2% of electricity consumption, but the target for 2030 is to reach 1%, with 25% of the energy mix coming from renewable sources.\n\nThe development of this energy source is hampered by the spa industry, which occupies many exploitable sites, as well as by the protection of national parks, where deposits are often found. However, in 2015, the Tsuchiyu power plant opened in a national park, coexisting with a spa. It embodies a new energy direction for Japan.', 'Thomas Ortiz',
  'Japon', 'Japanese', 36.5748441, 139.2394179,
  'images/IMG_3714.jpeg', '', '', '2026-02-23', 'published', 1, '2026-02-23 15:43:11', '2026-02-23 15:43:11'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771861391206', 'geothermie');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771861391206', 'electricite');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1771861547672', 'ÉOLIENNE POUR LA PRODUCTION D’ÉLECTRICITÉ', 'WIND TURBINE FOR ELECTRICITY GENERATION', '1928',
  'Le vent est traditionnellement exploité pour broyer le grain et pomper de l’eau, alors pourquoi ne pas l’utiliser pour produire de l’électricité ? Il y a 100 ans deux ingénieurs américains y avaient déjà pensé.\n\nMarcellus et Joe Jacobs développent en 1928 la première éolienne vendue en commerce pour la production d’électricité. Les deux frères ont commencé à s’intéresser aux dispositifs énergétiques décentralisés dès les années 1920, tout d’abord pour leur ferme.\n\nGrâce à leur expérience de fermiers, ils savent que de nombreuses exploitations éloignées ne peuvent pas être électrifiées sans utiliser de générateurs à essence. Or ces derniers étaient trop coûteux et comportaient trop d’inconvénients pour de nombreuses exploitations, car l’essence devait être constamment transportée en vrac sur de grandes distances.\n\nEn 1928, Jacobs Wind Electric Company est créée et la première usine voit le jour à Minneapolis en 1932. Entre 1928 et 1957, la société vendit plus de 30 000 unités. Le paysage agricole américain change : un nouveau type d’arbre y pousse.', 'Wind has traditionally been used to grind grain and pump water, so why not use it to generate electricity? Two American engineers had already thought of this 100 years ago.\n\nIn 1928, Marcellus and Joe Jacobs developed the first commercially available wind turbine for electricity generation. The two brothers became interested in decentralized energy systems in the 1920s, initially for their own farm.\n\nThanks to their experience as farmers, they knew that many remote farms could not be electrified without using gasoline generators. However, these were too expensive and had too many drawbacks for many farms, as gasoline had to be constantly transported in bulk over long distances.\n\nIn 1928, Jacobs Wind Electric Company was founded, and the first factory was established in Minneapolis in 1932. Between 1928 and 1957, the company sold more than 30,000 units. The American agricultural landscape was changing: a new type of tree was growing there.', 'Loïc Rogard',
  'Minneapolis', 'Minneapolis', 44.9772995, -93.2654692,
  'images/IMG_3715.jpeg', '', '', '2026-02-23', 'published', 1, '2026-02-23 15:45:47', '2026-02-23 15:45:47'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771861547672', 'eolien');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771861547672', 'electricite');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1771861621848', 'CELLULES SOLAIRES PHOTOVOLTAÏQUES', 'PHOTOVOLTAIC SOLAR CELLS', '1928',
  'En 1928, Hassan Kamel Al-Sabbah déclare “j’utiliserai le sable du désert pour produire des cellules solaires afin de générer une énorme quantité d’électricité et transformer ainsi le désert en paradis”.\n\n27 brevets lui sont délivrés entre 1928 et 1935 qui trouveront des applications dans les projets spatiaux. La cellule solaire d''origine qui a été inventée et testée par Al-Sabbah a été ensuite développée par Bell Telephone Laboratories en 1955. Un examen attentif des aéronefs et des satellites révèle que de nombreux instruments et équipements électroniques tels que les intégrateurs, les régulateurs, les onduleurs, les minuteries, les émetteurs et les capteurs ont été développés à partir de ses inventions originales de redresseurs et de convertisseurs.', 'In 1928, Hassan Kamel Al-Sabbah declared, "I will use desert sand to produce solar cells to generate a huge amount of electricity and thus transform the desert into a paradise."\n\nBetween 1928 and 1935, he was granted 27 patents that would find applications in space projects. The original solar cell invented and tested by Al-Sabbah was subsequently developed by Bell Telephone Laboratories in 1955. A careful examination of aircraft and satellites reveals that many electronic instruments and equipment such as integrators, regulators, inverters, timers, transmitters, and sensors were developed from his original inventions of rectifiers and converters.', 'Cédric Carles',
  '', '', NULL, NULL,
  'images/IMG_3717.jpeg', '', '', '2026-02-23', 'published', 1, '2026-02-23 15:47:01', '2026-02-23 15:47:01'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771861621848', 'electricite');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771861621848', 'solaire');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1771861725604', 'LE BÉLIER-SIPHON DE BIARRITZ DE PAUL GRASSET', 'THE BIARRITZ SIPHON BY PAUL GRASSET', '1930',
  'Au cap Saint-Martin, aux pieds du phare de Biarritz, un étrange cylindre de béton affronte les assauts de l’océan. Il abrita, dans les années 30, un « bélier-siphon maritime à chambre barométrique » conçu par l’ingénieur civil Paul Grasset pour produire de l’électricité à partir de l’énergie des vagues. Voici comment l’ingénieur décrit son procédé destiné à fournir « une énergie illimitée, nuit et jour, sans emploi de combustible » : « Cet appareil tient à la fois du Bélier hydraulique de Montgolfier, du Siphon et du baromètre à colonne liquide, équilibrée par la pression atmosphérique. Le réservoir barométrique sert à la fois d’accumulateur de l’énergie, de régulateur de la hauteur de chute et de distributeur permanent d’eau dans les turbines. Les deux colonnes, la première munie d’un clapet, la seconde comportant des turbines, sont en équilibre entre elles. Réunies par l’eau du réservoir, elles constituent un siphon à branches égales. Toutes les 10 secondes environ, l’impulsion venant de la mer soulève la colonne d’eau de la branche ascendante, rompant ainsi l’équilibre et permettant l’écoulement à travers les turbines de la branche descendante. Toutes les impulsions fortes ou faibles déséquilibrent le siphon et sont donc efficaces !”', 'At Cap Saint-Martin, at the foot of the Biarritz lighthouse, a strange concrete cylinder braves the onslaught of the ocean. In the 1930s, it housed a "maritime siphon ram with a barometric chamber" designed by civil engineer Paul Grasset to generate electricity from wave energy. Here is how the engineer described his process, designed to provide "unlimited energy, night and day, without the use of fuel": "This device is a combination of Montgolfier''s hydraulic ram, a siphon, and a liquid column barometer, balanced by atmospheric pressure. The barometric reservoir serves as an energy accumulator, a regulator of the height of fall, and a permanent distributor of water to the turbines. The two columns, the first equipped with a valve and the second containing turbines, are in equilibrium with each other. Connected by the water in the reservoir, they form a siphon with equal branches. Approximately every 10 seconds, the impulse from the sea lifts the water column in the ascending branch, breaking the balance and allowing the water to flow through the turbines in the descending branch. All impulses, whether strong or weak, unbalance the siphon and are therefore effective!', 'Guillaume Tixier',
  'Biarritz', 'Biarritz', 43.4711438, -1.5527266,
  'images/IMG_3716.jpeg', '', '', '2026-02-23', 'published', 1, '2026-02-23 15:48:45', '2026-02-23 15:48:45'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771861725604', 'electricite');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771861725604', 'h2o');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1771861824327', 'LE TRAVAIL DE RECHERCHE APPLIQUÉE DE MARIA TELKES', 'MARIA TELKES'' APPLIED RESEARCH WORK', '1937',
  'Mária Telkes, chimiste et biophysicienne américaine d’origine hongroise, est connue pour avoir inventé le distillateur solaire et conçu le premier système de chauffage solaire pour habitations. En 1937, elle rejoint Westinghouse Electric où elle développe des instruments convertissant la chaleur en électricité. En 1939, au MIT, elle débute ses recherches sur l’énergie solaire à travers des dispositifs thermoélectriques alimentés par la lumière du soleil.\n\nPendant la Seconde Guerre mondiale, au sein de l’US Office of Scientific Research and Development, elle met au point un distillateur solaire capable de transformer l’eau de mer en eau potable. En 1948, avec l’architecte Eleanor Raymond, elle conçoit la première maison moderne chauffée à l’énergie solaire, à Douvres (Massachusetts). Des capteurs solaires y réchauffent de l’air transmis à des sels de Glauber (sulfate de sodium) pour emmagasiner la chaleur.\n\nElle perfectionne aussi les échangeurs thermiques pour créer poêles et chauffages solaires. En 1980, elle participe à la construction de la première maison solaire-électrique, à Carlisle. Jusqu’à la fin de sa carrière, elle développe des technologies solaires innovantes, obtenant plusieurs brevets. Son parcours incarne l’ingéniosité appliquée aux énergies renouvelables.', 'Mária Telkes, an American chemist and biophysicist of Hungarian origin, is known for inventing the solar distiller and designing the first solar heating system for homes. In 1937, she joined Westinghouse Electric, where she developed instruments that converted heat into electricity. In 1939, at MIT, she began her research on solar energy using thermoelectric devices powered by sunlight. During World War II, while working for the US Office of Scientific Research and Development, she developed a solar distiller capable of converting seawater into drinking water. In 1948, with architect Eleanor Raymond, she designed the first modern solar-heated house in Dover, Massachusetts. Solar collectors heated air that was transferred to Glauber''s salt (sodium sulfate) to store the heat.\n\nShe also perfected heat exchangers to create solar stoves and heaters. In 1980, she participated in the construction of the first solar-electric house in Carlisle. Until the end of her career, she developed innovative solar technologies, obtaining several patents. Her career embodies ingenuity applied to renewable energy.', 'Sylvain Roche',
  'Etats-unis', 'United States', 39.7837304, -100.445882,
  'images/IMG_3718.jpeg', '', '', '2026-02-23', 'published', 1, '2026-02-23 15:50:24', '2026-02-23 15:50:24'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771861824327', 'rechauffer');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771861824327', 'solaire');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771861824327', 'electricite');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1771861916146', 'LA VOITURE LÉGÈRE DE VILLE PEUGEOT', 'THE PEUGEOT CITY CAR', '1941',
  'Face à une pénurie de carburant due à l’occupation allemande, Peugeot présente son VLV électrique en 1941. Cette petite voiture légère de ville a une autonomie maximale pour un coût minimal par kilomètre : “rayon d’action : 75 kilomètres, dépense pour la charge des batteries : 5 francs. Soit le kilomètre à 6 centimes 6”, note l’Argus de mai 1942. \n\nCe coupé décapotable deux places est réservé aux petits conducteurs - les grands gabarits doivent impérativement rouler capote ouverte - atteint une pointe à 36 km/h ! \n\nCe véhicule est très léger et minimaliste : 160 kilos des 4 batteries de 12V reliées en séries sous le capot avant, 180 kilos pour la structure en aluminium. Conçue pour un usage urbain, cette voiture sera utilisée en priorité par les postiers et les médecins. \n\nProduites à 377 exemplaires de 1941 à 1945 - on en connaît aujourd’hui une demi-douzaine-, elle fut construite non pas à Sochaux, occupé par les Allemands, mais en région parisienne. Petite, légère, maniable, économique et propre… Une parfaite citadine pour affronter la pénurie de carburant pétrole. ', 'Faced with a fuel shortage due to the German occupation, Peugeot unveiled its electric VLV in 1941. This small, lightweight city car offered maximum range at minimum cost per kilometer: "range: 75 kilometers, battery charging cost: 5 francs. That''s 6.6 cents per kilometer," noted L''Argus in May 1942. \n\nThis two-seater convertible coupe was designed for small drivers—taller drivers had to drive with the top down—and reached a top speed of 36 km/h! \n\nThis vehicle was very light and minimalist: 160 kilos for the four 12V batteries connected in series under the front hood, 180 kilos for the aluminum structure. Designed for urban use, this car was primarily used by postal workers and doctors. \n\nA total of 377 were produced between 1941 and 1945—half a dozen are known to exist today—and it was built not in Sochaux, which was occupied by the Germans, but in the Paris region. Small, light, maneuverable, economical, and clean... A perfect city car to cope with the fuel shortage. ', 'Alan Danglades',
  'Paris', 'Paris', 48.8534951, 2.3483915,
  'images/IMG_3719.jpeg', '', '', '2026-02-23', 'published', 1, '2026-02-23 15:51:56', '2026-02-23 15:51:56'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771861916146', 'deplacement');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771861916146', 'electricite');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1771861997855', 'LA VOITURE ÉLECTRIQUE CGE-TUBOR', 'THE CGE-TUBOR ELECTRIC CAR', '1942',
  'Jean-Albert Grégoire, ingénieur automobile français, est un pionnier de la traction avant et des carrosseries en alliages d’aluminium, allégeant ainsi les véhicules. Durant la Seconde Guerre mondiale, face à la pénurie d’essence, la Compagnie Générale d’Électricité (CGE) lui commande une voiture électrique. Produite à 200 exemplaires en 1941, la CGE-Tudor est vendue à un prix équivalent à 35 000 euros. Sans les batteries, elle ne pèse que 510 kg. Son moteur et ses 400 kg de batteries Tudor lui permettent d’atteindre 55 km/h, avec une autonomie record de 300 km. Elle dispose aussi d’un système de récupération d’énergie au freinage. Malgré ses innovations, la production s’arrête après la guerre. Jugées peu compétitives, la majorité des voitures sont envoyées à la casse. Ce véhicule oublié montre pourtant qu’en période de pénurie, l’innovation explore d’autres voies énergétiques. Fruit d’une collaboration entre acteurs publics et privés, il est regrettable qu’aucun effort n’ait été fait pour poursuivre sa production à moindre coût. À la fin des années 1960, Grégoire conçoit un nouveau modèle électrique : la Grégoire-Charbonneaux.', 'Jean-Albert Grégoire, a French automotive engineer, was a pioneer in front-wheel drive and aluminum alloy bodywork, which made vehicles lighter. During World War II, faced with a fuel shortage, the Compagnie Générale d''Électricité (CGE) commissioned him to design an electric car. Produced in 200 units in 1941, the CGE-Tudor was sold at a price equivalent to €35,000. Without the batteries, it weighed only 510 kg. Its engine and 400 kg of Tudor batteries enabled it to reach 55 km/h, with a record range of 300 km. It also had a braking energy recovery system. Despite its innovations, production ceased after the war. Deemed uncompetitive, most of the cars were sent to the scrapyard. However, this forgotten vehicle shows that in times of scarcity, innovation explores other energy sources. The result of collaboration between public and private actors, it is regrettable that no effort was made to continue its production at a lower cost. At the end of the 1960s, Grégoire designed a new electric model: the Grégoire-Charbonneaux.', 'Pierre-Antoine Gombeaud',
  'France', 'France', 46.603354, 1.8883335,
  'images/IMG_3721.jpeg', '', '', '2026-02-23', 'published', 1, '2026-02-23 15:53:17', '2026-02-23 15:53:17'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771861997855', 'electricite');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771861997855', 'deplacement');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1771862071905', '1ÈRE CAMPAGNE TÉLÉVISUELLE D’ÉCONOMIE', 'FIRST TELEVISION CAMPAIGN ON SAVING MONEY', '1943',
  'A l’occasion de la mise en service d’une centrale à charbon de 200 000 kilowatts, une campagne d’économie d’énergie est diffusée en France. Le speaker propose de “ne pas gaspiller cette énergie vitale” et insiste : “cependant n’oubliez pas que toute consommation d’électricité est une consommation de charbon”. On y apprend aussi des mesures d’équivalences énergétiques.', 'To mark the commissioning of a 200,000-kilowatt coal-fired power plant, an energy-saving campaign is being launched in France. The speaker urges people "not to waste this vital energy" and insists: "However, don''t forget that all electricity consumption is coal consumption." The campaign also teaches people about energy equivalence measures.', 'Cédric Carles',
  'France', 'France', 46.603354, 1.8883335,
  'images/IMG_3722.jpeg', '', '', '2026-02-23', 'published', 1, '2026-02-23 15:54:31', '2026-02-23 15:54:31'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771862071905', 'electricite');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771862071905', 'politique-publique');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1771862207536', 'CAMION À L’HYDROGÈNE', 'HYDROGEN-POWERED TRUCK', '1945',
  'M. Louis Hubault et M.G. Dubled ont mis au point un camion Saurer 1929 roulant à l’hydrogène. Ils produisaient eux-mêmes l’hydrogène avec un moulin à eau, une turbine de 35cv, un électrolyseur, deux dynamos, une installation de distillation pour obtenir de l’eau très pure, deux gazomètres (un pour l‘oxygène et un pour l’hydrogène) et un compresseur. L’hydrogène était alors compressé à 350 atmosphères dans des réservoirs fixes pour ensuite alimenter les bouteilles du camion à 200 atmosphères. En 1950, avec un professeur du lycée technique de Narcet, M. Maxence de Feyter, ils ont construit un arbre à cames pour entraîner les soupapes amenant l’hydrogène. En 6 ans ils ont parcouru plusieurs milliers de kilomètres sans incident (sans que le corps des Mines ne soit jamais au courant).', 'Mr. Louis Hubault and Mr. G. Dubled developed a 1929 Saurer truck that ran on hydrogen. They produced the hydrogen themselves using a water mill, a 35 hp turbine, an electrolyzer, two dynamos, a distillation system to obtain very pure water, two gasometers (one for oxygen and one for hydrogen) and a compressor. The hydrogen was then compressed to 350 atmospheres in fixed tanks and used to fill the truck''s cylinders at 200 atmospheres. In 1950, with a teacher from the technical high school in Narcet, Mr. Maxence de Feyter, they built a camshaft to drive the valves supplying the hydrogen. In six years, they traveled several thousand kilometers without incident (without the Corps des Mines ever knowing).', 'Marcel Robert',
  '', '', NULL, NULL,
  'images/IMG_3723.jpeg', '', '', '2026-02-23', 'published', 1, '2026-02-23 15:56:47', '2026-02-23 15:56:47'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771862207536', 'hydrogene');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771862207536', 'deplacement');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771862207536', 'h2o');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1771862293265', 'LA VOITURE ÉLECTRIQUE TAMA', 'THE TAMA ELECTRIC CAR', '1947',
  'Les 1ères importations d’automobiles, dont une électrique, débutent à la fin du XIXe siècle au Japon. À partir de 1910, les prototypes de véhicules électriques japonais sont créées. En 1930, une collaboration entre une société de production électrique, une de batteries et un équipementier conçoit des bus électriques pour le transport urbain. Ils sont expérimentés dans la ville de Nagoya, leurs batteries sont rechargées avec les surplus de production des heures creuses nocturnes. Avec un système ingénieux de glissières, on peut remplacer les batteries en 10 minutes. En 1938, on en compte 27 dans tout le pays. Après la 2nd guerre mondiale, l’essence est rationnée au Japon. Le pays est détruit, mais des centrales électriques continuent de tourner. \n\nEn 1947, la société Tachikawa arrête la production d’avions militaires pour des véhicules électriques, elle devient la Tokyo Electric Car Company. Elle conçoit la 1ère voiture électrique, fabriquée en série, au Japon : la Tama. Elle peut rouler à une vitesse maximum de 35 km/h et dispose d’une autonomie de 65 km. En 1949, un nouveau modèle peut atteindre une vitesse de 55 km/h pour une autonomie de 200 km. Toutefois, en 1950, les conséquences géopolitiques de la guerre de Corée provoquent la flambée du cours du plomb… Le prix des batteries monte en flèche tandis que celui du pétrole dégringole. La mobilité électrique n’est plus compétitive par rapport aux voitures thermiques.', 'The first imports of automobiles, including an electric car, began in Japan at the end of the 19th century. From 1910 onwards, Japanese electric vehicle prototypes were created. In 1930, a collaboration between an electricity production company, a battery manufacturer, and an equipment supplier led to the design of electric buses for urban transport. They were tested in the city of Nagoya, with their batteries recharged using surplus production during off-peak night-time hours. Thanks to an ingenious slide system, the batteries could be replaced in 10 minutes. By 1938, there were 27 of them in operation across the country. After World War II, gasoline was rationed in Japan. The country was destroyed, but the power plants continued to operate. \n\nIn 1947, the Tachikawa company stopped producing military aircraft in favor of electric vehicles and became the Tokyo Electric Car Company. It designed the first mass-produced electric car in Japan: the Tama. It could reach a maximum speed of 35 km/h and had a range of 65 km. In 1949, a new model was able to reach a speed of 55 km/h with a range of 200 km. However, in 1950, the geopolitical consequences of the Korean War caused the price of lead to skyrocket. The price of batteries rose sharply while the price of oil plummeted. Electric mobility was no longer competitive with combustion engine cars.', 'Thomas Ortiz',
  'Japon', 'Japanese', 36.5748441, 139.2394179,
  'images/IMG_3724.jpeg', '', '', '2026-02-23', 'published', 1, '2026-02-23 15:58:13', '2026-02-23 15:58:13'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771862293265', 'electricite');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771862293265', 'deplacement');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1771862540359', 'LE GYROBUS : UN TRANSPORT A VOLANT D’INERTIE', 'THE GYROBUS: TRANSPORTATION USING A FLYWHEEL', '1950',
  'Développés par la société suisse Oerlikon dans les années 50, les gyrobus ont été utilisés pendant environ 7 ans à Yverdon et Grandson en Suisse, Léopoldville au Congo Belge, et Gand en Belgique. Ils fonctionnent avec un moteur électrique alimenté par un grand volant en acier pesant 1500 kg (un volant d’inertie). Une fois que le volant est lancé, son énergie cinétique est convertie en énergie électrique et alimente le moteur de propulsion. Lors de la montée et descente des passagers, le volant est rechargé, il est remis en rotation. Ce système permettait d’atteindre une vitesse de 50-60 km/h pour une autonomie de 6 km environ.\n\nLe gyrobus présentait plusieurs avantages : il était peu polluant (hormis la production d’électricité) et peu bruyant. Contrairement aux trolleybus il n’avait pas besoin de lignes de contact sur tout le parcours, se rechargeant uniquement durant les arrêts. Cependant le temps de recharge du volant relativement long, trois à quatres minutes, ainsi que le danger causé par celui-ci, pesant plus d’une tonne et lancé à 3000 tours/minutes furent la cause de l’abandon de ce type de véhicule à la fin des années 60.\n\nAujourd’hui les volants d’inertie sont de plus en plus développés pour le stockage d’énergie. A Rennes par exemple, l’énergie créée par le freinage des rames de métro est stockée dans un volant d’inertie, pour être ensuite réinjectée sous forme d’électricité.', 'Developed by the Swiss company Oerlikon in the 1950s, gyrobus vehicles were used for around seven years in Yverdon and Grandson in Switzerland, Leopoldville in the Belgian Congo, and Ghent in Belgium. They operate using an electric motor powered by a large steel wheel weighing 1,500 kg (a flywheel). Once the flywheel is started, its kinetic energy is converted into electrical energy and powers the propulsion motor. When passengers get on and off, the flywheel is recharged and starts spinning again. This system allowed the gyrobus to reach speeds of 50-60 km/h with a range of about 6 km.\n\nThe gyrobus had several advantages: it was low-polluting (except for electricity production) and quiet. Unlike trolleybuses, it did not need overhead lines along the entire route, recharging only during stops. However, the relatively long recharge time for the flywheel, three to four minutes, as well as the danger posed by the flywheel, weighing over a ton and spinning at 3,000 rpm, led to this type of vehicle being abandoned in the late 1960s.\n\nToday, flywheels are increasingly being developed for energy storage. In Rennes, for example, the energy created by the braking of metro trains is stored in a flywheel, to be then fed back into the grid in the form of electricity.', 'André Rosselet',
  'Congo', 'Congo', -2.9814344, 23.8222636,
  'images/IMG_3725.jpeg', '', '', '2026-02-23', 'published', 1, '2026-02-23 16:02:20', '2026-02-23 16:02:20'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771862540359', 'electricite');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771862540359', 'mecanique');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1771862619327', 'LE MUR TROMBE-MICHEL DE FÉLIX TROMBE', 'THE TROMBE-MICHEL WALL BY FÉLIX TROMBE', '1950 - 1970',
  'Le mur Trombe-Michel est un système de chauffage ou de climatisation solaire passif par circulation d’air. Devant le mur se trouve un vitrage qui piège la chaleur du soleil et se propage pour s’accumuler dans la maçonnerie. Mis en œuvre et expérimenté par le professeur Félix Trombe et l’architecte Jacques Michel, ce dispositif tire parti, par effet de serre, de l’énergie gratuite du soleil. Basé sur une idée originale du naturaliste américain Edward Sylvester Morse de 1881, le concept est aujourd’hui repris par une équipe de jeunes ingénieurs de centrale Lille sous le nom Enar. Le mur fait de canettes récupérées, découpées, puis assemblées, recrée l’action sur l’air décrite par Morse, Trombe et Michel, et ce à moindres frais.', 'The Trombe-Michel wall is a passive solar heating or cooling system that uses air circulation. In front of the wall is a glass panel that traps the sun''s heat and spreads it to accumulate in the masonry. Developed and tested by Professor Félix Trombe and architect Jacques Michel, this device uses the greenhouse effect to harness the sun''s free energy. Based on an original idea by American naturalist Edward Sylvester Morse in 1881, the concept has now been taken up by a team of young engineers from Centrale Lille under the name Enar. The wall, made from recycled cans that have been cut and assembled, recreates the action on the air described by Morse, Trombe, and Michel, at a lower cost.', 'Thomas Ortiz',
  '', '', NULL, NULL,
  'images/IMG_3726.jpeg', '', '', '2026-02-23', 'published', 1, '2026-02-23 16:03:39', '2026-02-23 16:03:39'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771862619327', 'rechauffer');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771862619327', 'rafraichir');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771862619327', 'isolation-thermique');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1771862711836', 'LA MÉTHODE KEYLINE', 'THE KEYLINE METHOD', '1950',
  'La méthode Keyline, développée par P.A. Yeomans, est une approche de gestion de l''eau et du sol en agriculture régénérative. Elle vise à maximiser l''efficacité de l''utilisation de l''eau sur les terres agricoles en favorisant une infiltration et une distribution uniformes de l''eau. \n\nCela est réalisé par le design de paysages avec des barrages, des canaux et des fossés qui suivent les contours naturels du terrain. La méthode met également l''accent sur l''amélioration de la structure du sol et la création de microclimats favorables à la croissance des plantes.', 'The Keyline method, developed by P.A. Yeomans, is an approach to water and soil management in regenerative agriculture. It aims to maximize the efficiency of water use on agricultural land by promoting uniform water infiltration and distribution. \n\nThis is achieved by designing landscapes with dams, channels, and ditches that follow the natural contours of the land. The method also emphasizes improving soil structure and creating microclimates conducive to plant growth.', 'Cédric CARLES',
  '', '', NULL, NULL,
  'images/IMG_3727.jpeg', '', 'https://wiki.tripleperformance.fr/wiki/Keyline_design#:~:text=Le%20keyline%20design%20est%20une,''%C3%A9coulement%20de%20l''eau.', '2026-02-23', 'published', 1, '2026-02-23 16:05:11', '2026-02-23 16:05:11'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771862711836', 'agriculture');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771862711836', 'h2o');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1771862801863', 'DES POMPES SOLAIRES AU SÉNÉGAL', 'SOLAR PUMPS IN SENEGAL', '1950',
  'En pompant de l’eau pour le Sahel sans électricité, le Sénégal s’est imposé il y a plus de cinquante ans comme précurseur de l’énergie solaire – alors thermodynamique, non photovoltaïque. Henri Masson, premier directeur de l’École polytechnique de Dakar, s’y intéresse dès les années 1950. Dans les années 1970, Dakar devient un centre mondial de recherche solaire. C’est dans ce contexte que Jean-Pierre Girardier fonde en 1973 la Sofretes, spécialisée dans le pompage solaire thermodynamique. L’objectif : des pompes solaires villageoises de 1 kW, simples et réparables. Le soleil chauffe une surface noire, créant une différence de température avec l’eau froide du puits. Un fluide intermédiaire en circuit fermé, compressé et détendu, actionne un moteur entraînant la pompe, quasi sans entretien. Près de 70 pompes sont construites, surtout en Afrique et au Mexique. La Sofretes bâtit aussi deux grandes centrales : San Luis (1975) et Diré (1980). Sa première pompe entre au musée des Arts et Métiers en 2018.', 'By pumping water for the Sahel without electricity, Senegal established itself more than fifty years ago as a pioneer in solar energy—at that time thermodynamic, not photovoltaic. Henri Masson, the first director of the École Polytechnique de Dakar, became interested in it in the 1950s. In the 1970s, Dakar became a global center for solar research. It was in this context that Jean-Pierre Girardier founded Sofretes in 1973, specializing in thermodynamic solar pumping. The goal was to develop simple, repairable 1 kW solar pumps for villages. The sun heats a black surface, creating a temperature difference with the cold water in the well. An intermediate fluid in a closed circuit, compressed and expanded, drives a motor that powers the pump, requiring virtually no maintenance. Nearly 70 pumps were built, mainly in Africa and Mexico. Sofretes also built two large power plants: San Luis (1975) and Diré (1980). Its first pump entered the Musée des Arts et Métiers in 2018.', 'Frédéric Caille',
  'Sénégal', 'Senegal', 14.4750607, -14.4529612,
  'images/IMG_3728.jpeg', '', '', '2026-02-23', 'published', 1, '2026-02-23 16:06:41', '2026-02-23 16:06:41'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771862801863', 'h2o');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771862801863', 'solaire');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1771862967161', 'LE PEGASO ÉLECTRIQUE', 'THE ELECTRIC PEGASO', '1952',
  'Le Pegaso est un prototype de camion électrique du constructeur Pegaso.\n\nIl dispose d’une charge utile de 6 tonnes. Le camion pèse 9170 kg et est alimenté par 48 batteries plomb de fabrication française. Malgré cette énorme capacité de stockage de 600Ah, son autonomie n’est que de 75 km, sa vitesse maximale lorsqu’il est rempli atteint 28 km/h.\n\nAu même moment, son homologue roulant au Diesel a une autonomie de 555 km pour un plein de carburant et sa vitesse maximale est de 70 km/h. Incapable de rivaliser avec la version utilisant du carburant, le Pegaso électrique n’a pas été fabriqué en série.', 'The Pegaso is a prototype electric truck from the manufacturer Pegaso. It has a payload capacity of 6 tons. The truck weighs 9,170 kg and is powered by 48 French-made lead batteries. Despite this enormous storage capacity of 600Ah, its range is only 75 km, and its maximum speed when fully loaded is 28 km/h.\n\nAt the same time, its diesel-powered counterpart has a range of 555 km on a full tank of fuel and a top speed of 70 km/h. Unable to compete with the fuel-powered version, the electric Pegaso was not mass-produced.', 'Pierre-Antoine Gombeaud',
  '', '', NULL, NULL,
  'images/IMG_3729.jpeg', '', '', '2026-02-23', 'published', 1, '2026-02-23 16:09:27', '2026-02-23 16:09:27'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771862967161', 'electricite');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771862967161', 'deplacement');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1771926026584', 'L’HISTOIRE DES CELLULES PHOTOVOLTAÏQUES', 'THE HISTORY OF PHOTOVOLTAIC CELLS', '1954',
  'L’histoire de la cellule photovoltaïque est marquée par différents chercheurs qui découvrent et étudient le phénomène photovoltaïque, mais aussi par des contextes historiques qui encouragent son développement.\n\nElle débute en 1839, lorsque le physicien français Antoine Becquerel découvre cet effet qui consiste à transformer une partie du rayonnement solaire en courant électrique par le biais d’une cellule électrolytique exposée au soleil. Elle se poursuit en 1921, par le biais de la remise du prix Nobel de Einstein pour ses travaux sur l’effet photovoltaïque. Et son intérêt se développe considérablement dans les années 1950 en parallèle avec celui de l’industrie spatiale.\n\nLa crise énergétique de 1970 marque, quant à elle, le début d’un réel intérêt pour l’utilisation de l’énergie solaire dans les entreprises et les foyers. La deuxième moitié du XXe siècle est marquée par les premières constructions et véhicules alimentés par des cellules photovoltaïques. Une prise de conscience du caractère épuisable des énergies fossiles qui a accentué l’envie de trouver une énergie alternative … et quoi de mieux qu’une source d’énergie illimitée et inépuisable ?', 'The history of the photovoltaic cell is marked by various researchers who discovered and studied the photovoltaic phenomenon, but also by historical contexts that encouraged its development. It began in 1839, when French physicist Antoine Becquerel discovered this effect, which consists of converting part of the sun''s radiation into electrical current using an electrolytic cell exposed to the sun. It continued in 1921, when Einstein was awarded the Nobel Prize for his work on the photovoltaic effect. Interest in the phenomenon grew considerably in the 1950s, in parallel with the growth of the space industry.\n\nThe energy crisis of 1970 marked the beginning of a real interest in the use of solar energy in businesses and homes. The second half of the 20th century saw the first buildings and vehicles powered by photovoltaic cells. Awareness of the finite nature of fossil fuels heightened the desire to find an alternative energy source... and what could be better than an unlimited and inexhaustible source of energy?', 'Pierre-Antoine Gombeaud',
  'France', 'France', 46.603354, 1.8883335,
  'images/IMG_3731.jpeg', '', '', '2026-02-24', 'published', 1, '2026-02-24 09:40:26', '2026-02-24 09:40:26'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771926026584', 'solaire');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771926026584', 'electricite');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1771926115994', 'L’INVENTION DE LA BATTERIE SOLAIRE PAR BELL LABS', 'THE INVENTION OF THE SOLAR BATTERY BY BELL LABS', '1956',
  'La première conception de cellules solaires, du laboratoire États-Uniens Bell , est testée en 1955. Le système Bell utilise 3 600 cellules solaires pour alimenter le satellite Telstar en 1962, et depuis lors, il est un standard dans la conception pour l''espace. Cependant, il a fallu des décennies pour que le coût des cellules solaires permette de rivaliser avec d''autres formes d''énergie. Elles sont encore lentement adoptées dans les régions où l’ensoleillement est fort. L''efficacité de la technologie solaire s''est également considérablement améliorée ces dernières années.', 'The first solar cell design, from the US Bell Laboratories, was tested in 1955. The Bell system used 3,600 solar cells to power the Telstar satellite in 1962, and since then it has been a standard in space design. However, it took decades for the cost of solar cells to become competitive with other forms of energy. They are still being adopted slowly in regions with high levels of sunshine. The efficiency of solar technology has also improved considerably in recent years.', 'Nicolas Doubet  et David Stauffacher',
  'Etats-unis', 'United States', 39.7837304, -100.445882,
  'images/IMG_3732.jpeg', '', '', '2026-02-24', 'published', 1, '2026-02-24 09:41:55', '2026-02-24 09:41:55'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771926115994', 'solaire');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771926115994', 'electricite');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1771926269691', 'LA VOITURE PORCO-TRACTÉE', 'THE PIG-PULLED CAR', '1963',
  'Voici Harold Bate, inventeur d’une voiture au biogaz, alimentée par ses cochons.\n\nEn 1963, un journaliste titre ainsi son article, non sans ironie : “la voiture porco-tractée d’Harold donne le feu vert à ceux qui conduisent comme des cochons ! ”\n\nS’ensuit un article admirable où l’on présente les différentes vertus de cette voiture miracle, qui “va plus vite, ne s''abîme pas… et ne relâche qu’un peu de vapeur d’eau et de monoxyde de carbone.”\n\nSelon l’inventeur, son véhicule fonctionne parfaitement après 10 ans d’utilisation. Il a développé et breveté ce qu’il appelle un “convertisseur automatique ” qui peut être installé sur n’importe quel moteur pour lui permettre de rouler grâce au fameux gaz inodore.\n\nUne partie des plans sont désormais dans le domaine public.', 'Meet Harold Bate, inventor of a biogas car powered by his pigs. In 1963, a journalist wrote an article with the ironic headline: "Harold''s pig-powered car gives the green light to those who drive like pigs!"\n\nWhat follows is an admirable article presenting the various virtues of this miracle car, which "goes faster, doesn''t break down... and emits only a little water vapor and carbon monoxide."\n\nAccording to the inventor, his vehicle is still running perfectly after 10 years of use. He has developed and patented what he calls an "automatic converter" that can be installed on any engine to enable it to run on the famous odorless gas. Some of the plans are now in the public domain.', 'Loïc Rogard',
  '', '', NULL, NULL,
  'images/IMG_3733.jpeg', '', '', '2026-02-24', 'published', 1, '2026-02-24 09:44:29', '2026-02-24 09:44:29'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771926269691', 'deplacement');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771926269691', 'biogaz');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1771926373459', 'LE COMPOST DE JEAN PAIN', 'JEAN PAIN''S COMPOST', '1969',
  'La méthode Jean Pain consiste à utiliser l’énergie de la biomasse contenue dans un compost. En 1969, alors qu’il s’établit en Haute Provence comme garde forestier, Jean Pain décide d’engranger la broussaille contenue sur les terres dont il a la charge, afin de l’exploiter sous forme de compost. \nIl se sert de celui-ci comme engrais biologique pour un potager d’essai aménagé par ses soins. \n\nLa méthode est très efficace : Jean Pain n’a pas besoin d’arroser le potager, qui donne pourtant des résultats spectaculaires. Mais ce n’est pas tout : Jean Pain utilise son compost pour produire de la chaleur, grâce à l’énergie thermique générée par la biomasse. \n\nCette méthode lui permet d’être autonome en énergie thermique, et de réchauffer de l’eau jusqu’à 45° pendant au moins trois mois de l’année.', 'The Jean Pain method involves using the energy from the biomass contained in compost. In 1969, when he settled in Haute Provence as a forest ranger, Jean Pain decided to collect the brushwood from the land under his care in order to use it as compost. \nHe used it as organic fertilizer for a test vegetable garden he had set up himself. The method was very effective: Jean Pain did not need to water the vegetable garden, which nevertheless produced spectacular results. But that''s not all: Jean Pain used his compost to produce heat, thanks to the thermal energy generated by the biomass. \n\nThis method allows him to be self-sufficient in thermal energy and to heat water to 45°C for at least three months of the year.', 'Cédric CARLES',
  'Haute Provence', 'Upper Provence', 46.8905093, 6.7257208,
  'images/IMG_3734.jpeg', '', 'https://www.consoglobe.com/methode-jean-pain-compost-broussailles-cg', '2026-02-24', 'published', 1, '2026-02-24 09:46:13', '2026-02-24 09:46:13'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771926373459', 'agriculture');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771926373459', 'rechauffer');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1771926482418', 'QUAND PIGANIOL ANTICIPAIT LE VÉLIB’', 'WHEN PIGANIOL ANTICIPATED THE VÉLIB’', '1970',
  'En 1958, sous De Gaulle, Pierre Piganiol (1915-2007) fonde une ambitieuse politique de recherche scientifique, à l’origine notamment du centre d’études spatiales (CNES) et du développement de la biologie moléculaire. Convaincu que la science est un facteur de progrès, il imagine en 1970 le futur des transports, et anticipe même le velib''.\n\nPierre Piganiol disait lui-même : “Peut-on dès aujourd’hui imaginer d’autres solutions que la voiture individuelle ? Nous brûlons en gros en un jour ce que la nature a accumulé en 1 000 ans. Bon ça ne pourra pas durer c’est évident. Donc nous allons nous trouver devant l’obligation de choisir d’autres moyens de transport qui, si possible, n’utilisent plus les formes fossiles de l’énergie. On peut imaginer un jour, une généralisation de la solution que vous rencontrez aux halles de Rungis. Vous louez une clé, moyennant quoi, vous enfourchez un vélo que vous laisserez où vous aurez envie de le laisser et vous trouverez tout le long du trajet les moyens de locomotion dont vous aurez besoin, tout en empruntant quand le besoin en est les moyens collectifs.”', 'In 1958, under De Gaulle, Pierre Piganiol (1915-2007) established an ambitious scientific research policy, which led to the creation of the French National Center for Space Studies (CNES) and the development of molecular biology. Convinced that science was a factor in progress, in 1970 he imagined the future of transport and even anticipated the Velib'' bike-sharing scheme. Pierre Piganiol himself said: "Can we already imagine alternatives to the private car? We burn in a single day what nature has accumulated in 1,000 years. Obviously, this cannot continue. So we will be forced to choose other means of transport that, if possible, no longer use fossil fuels. One day, we may see widespread adoption of the solution you see at the Rungis market. You rent a key, which allows you to hop on a bike that you can leave wherever you want, and you''ll find all the means of transportation you need along the way, while using public transportation when necessary."', 'Cédric Carles',
  'France', 'France', 46.603354, 1.8883335,
  'images/IMG_3735.jpeg', '', '', '2026-02-24', 'published', 1, '2026-02-24 09:48:02', '2026-02-24 09:48:02'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771926482418', 'deplacement');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771926482418', 'politique-publique');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1771926699213', 'MONTPELLIER ADOPTE LA VOITURE EN LIBRE SERVICE', 'Montpellier Embraces Car Sharing', '1971',
  'Il s’agit d’un nouveau mode de location de voiture pour l’époque : une voiture en autopartage. Dans la ville, 150 voitures seront réparties pour 300 places de stationnement réservées. Elles s’ouvrent toutes avec le même type de clé. \n\nPour posséder une clé, il suffit de souscrire un abonnement. Pour mettre la voiture en marche, il faut la clé, mais également un jeton. Il faut placer ce dernier dans le boîtier électronique prévue à cet effet. Une fois le jeton totalement utilisé, il faudra s’en procurer un autre dans un distributeur automatique. Le prix de revient est de 50 centimes par kilomètre. \n\nEn cas de panne, il suffit de changer de véhicule, un signal électronique sera envoyé à une permanence centrale, indiquant l’incident et le lieu du véhicule. ', 'This is a new type of car rental for the time: a car-sharing scheme. In the city, 150 cars will be distributed across 300 reserved parking spaces. They can all be opened with the same type of key. To obtain a key, you simply need to take out a subscription. To start the car, you need the key, but also a token. The token must be placed in the electronic box provided for this purpose. Once the token has been used up, another one must be obtained from a vending machine. The cost is 50 cents per kilometer. In the event of a breakdown, simply change vehicles, and an electronic signal will be sent to a central office, indicating the incident and the location of the vehicle. ', 'Eric Dussert',
  'Montpellier', 'Montpellier', 43.6112422, 3.8767337,
  'images/IMG_3736.jpeg', '', '', '2026-02-24', 'published', 1, '2026-02-24 09:51:39', '2026-02-24 09:51:39'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771926699213', 'deplacement');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1771926785152', 'WITKAR : UN SYSTÈME DE VOITURE PARTAGÉE', 'WITKAR: A CAR SHARING SYSTEM', '1974',
  'Avec dix stations, une centaine de véhicules et 4000 utilisateurs enregistrés, le projet Witkar constitue la première expérience de voiture électrique en autopartage du monde. Porté par l’inventeur et politicien Luud Schimmelpennink, membre du mouvement anarcho-écologiste Provo, l’expérience Witkar visait à réduire le trafic dans le centre d’Amsterdam, mais prit fin au bout de douze ans, faute de soutien municipal. Trop longs à recharger, les véhicules (des tricycles à deux places) avaient également tendance à être tous utilisés dans la même direction. Schimmelpennink était un précurseur : aujourd’hui, la capitale hollandaise a décidé de relancer le projet, en mettant à disposition des habitants de la ville 120 stations d’échanges et un millier de voitures en autopartage.\n', 'With ten stations, around 100 vehicles, and 4,000 registered users, the Witkar project is the world''s first electric car sharing experiment. Led by inventor and politician Luud Schimmelpennink, a member of the anarcho-ecological Provo movement, the Witkar experiment aimed to reduce traffic in central Amsterdam, but ended after twelve years due to a lack of municipal support. The vehicles (two-seater tricycles) took too long to recharge and tended to all be used in the same direction. Schimmelpennink was a pioneer: today, the Dutch capital has decided to relaunch the project, providing city residents with 120 exchange stations and a thousand car-sharing vehicles. ', 'Côme Bastin',
  'Amsterdam', 'Amsterdam', 52.3730796, 4.8924534,
  'images/IMG_3737.jpeg', '', '', '2026-02-24', 'published', 1, '2026-02-24 09:53:05', '2026-02-24 09:53:05'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771926785152', 'deplacement');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771926785152', 'electricite');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1771926878338', 'CITICAR : PRODUCTION EN SÉRIE DE VOITURE ELECTRIQUE', 'CITICAR: SERIES PRODUCTION OF ELECTRIC CARS', '1974',
  'La voiture électrique CitiCar de Sebring – Vanguard a été produite à plus de 4000 exemplaires entre 1974 et 1979. Compacte et au design plutôt angulaire, la CitiCar avait une autonomie de 50 à 60 miles. Jusqu’aux voitures électriques Tesla, elle restera la voiture électrique la plus fabriquée aux Etats-unis.', 'More than 4,000 Sebring-Vanguard CitiCar electric cars were produced between 1974 and 1979. Compact and with a rather angular design, the CitiCar had a range of 50 to 60 miles. Until the advent of Tesla electric cars, it remained the most widely manufactured electric car in the United States.', 'Thomas Ortiz',
  'États-Unis', 'United States', 39.7837304, -100.445882,
  'images/IMG_3738.jpeg', '', '', '2026-02-24', 'published', 1, '2026-02-24 09:54:38', '2026-02-24 09:54:38'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771926878338', 'deplacement');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771926878338', 'electricite');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1771927036037', 'LES MINIBUS À HYDROGÈNE DE L’UNION SOVIÉTIQUE', 'HYDROGEN MINIBUSES IN THE SOVIET UNION', '1975',
  'Dans les années 70, divers organismes liés à l’industrie automobile de l’URSS ont créé et testé des véhicules fonctionnant à l’hydrogène comme par exemple des Jigoulis, des Moskvitch, des GAZ-24 Volga, des GAZ-69, des minibus RAF ou UAZ ainsi que des camions ZiL-130. En 1976, les spécialistes de l’Institut de génie mécanique de l’URSS de Kharkov ont ainsi réalisé un prototype de Moskvitch-412 avec un moteur fonctionnant à l’hydrogène. \n\nOutre le réservoir à essence habituel, ils avaient monté sur la berline soviétique un mini-réacteur rempli d’un catalyseur basé essentiellement sur des oxydes de métaux divers. En passant à travers ce réacteur, l’eau était subdivisée en hydrogène et oxygène brûlés ensuite dans les cylindres du moteur. Il faut noter que le système d’alimentation en hydrogène était monté en parallèle du système d’alimentation de carburant standard. La quantité d’eau et du mélange catalyseur était injectée dans le réacteur en fonction de la puissance nécessaire. La vitesse de la réaction chimique était contrôlée par le conducteur tout simplement en pressant la pédale d’accélérateur.', 'In the 1970s, various organizations linked to the USSR''s automotive industry created and tested hydrogen-powered vehicles such as Zhigulis, Moskvichs, GAZ-24 Volgas, GAZ-69s, RAF or UAZ minibuses, and ZiL-130 trucks. In 1976, specialists at the USSR Institute of Mechanical Engineering in Kharkov built a prototype Moskvitch-412 with a hydrogen-powered engine. \n\nIn addition to the usual gasoline tank, they installed a mini-reactor filled with a catalyst based mainly on various metal oxides in the Soviet sedan. Passing through this reactor, water was split into hydrogen and oxygen, which were then burned in the engine cylinders. It should be noted that the hydrogen supply system was installed in parallel with the standard fuel supply system. The amount of water and catalyst mixture injected into the reactor depended on the power required. The speed of the chemical reaction was controlled by the driver simply by pressing the accelerator pedal.', 'Thomas Ortiz',
  'URSS', 'Soviet Union', 43.4439715, 39.9400928,
  'images/IMG_3740.jpeg', '', 'http://sovietauto.over-blog.com/2015/10/quand-moskvitch-experimentait-la-voiture-a-hydrogene.html', '2026-02-24', 'published', 1, '2026-02-24 09:57:16', '2026-02-24 09:57:16'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771927036037', 'deplacement');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771927036037', 'hydrogene');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1771927095588', 'VÉLO EN AUTOPARTAGE À LA ROCHELLE', 'BIKE SHARING IN LA ROCHELLE', '1976',
  'La municipalité de la Rochelle a mis en place en 1976 un parc de bicyclettes gratuites comptant pas moins de 250 vélos en libre-service. \n\nCe projet est inspiré de la mise à disposition de cadis dans les aéroports ou les magasins, afin d’accéder rapidement aux zones piétonnières. \n\nLe but était de réhabiliter le centre ancien et commerçant en le débarrassant des méfaits de la circulation automobile : pollution, bruit, engorgement... Il s’agissait aussi de générer une prise de conscience collective des biens communs de la municipalité et changer ainsi les mentalités. ', 'In 1976, the municipality of La Rochelle set up a free bicycle park with no fewer than 250 self-service bikes. This project was inspired by the provision of shopping carts in airports and stores, allowing quick access to pedestrian areas. \n\nThe aim was to revitalize the old town and shopping district by ridding it of the negative effects of car traffic: pollution, noise, congestion, etc. It was also about raising collective awareness of the municipality''s common goods and thus changing attitudes. ', 'Eric Dussert',
  'La Rochelle', 'La Rochelle', 46.159732, -1.1515951,
  'images/IMG_3741.jpeg', '', '', '2026-02-24', 'published', 1, '2026-02-24 09:58:15', '2026-02-24 09:58:15'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771927095588', 'politique-publique');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771927095588', 'deplacement');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1771927165427', 'L’AUTOSOLAR DE ARIEL CIRO RIETTI', 'ARIEL CIRO RIETTI''S AUTOSOLAR', '1977',
  'Cette voiturette solaire est l’oeuvre d’Ariel Ciro Rietti, ou M. Soleil comme certains aimaient le surnommer.\n\nTout droit sortie de son laboratoire de recherche sur les énergies renouvelables, cet engin lui permettait d’arpenter les rues de Buenos Aires les jours de grand soleil.\n\nCet enseignant, pilote de planeur, précurseur des énergies propres a travaillé sur de nombreux projets tels qu’un ascenseur solaire et des prototypes d’hélicoptères.\n\nLa fondation Universelle Solar Rietti, créée en 1991, continue de diffuser son travail et de promouvoir l’utilisation de l’énergie solaire en Argentine.', 'This solar-powered car is the brainchild of Ariel Ciro Rietti, or Mr. Sun as some liked to call him. Straight out of his renewable energy research lab, this vehicle allowed him to cruise the streets of Buenos Aires on sunny days.\n\nThis teacher, glider pilot, and pioneer of clean energy worked on numerous projects, such as a solar elevator and helicopter prototypes. The Universal Solar Rietti Foundation, created in 1991, continues to disseminate his work and promote the use of solar energy in Argentina.', 'Joaquin Ezcurra',
  'Argentine', 'Argentina', -34.9964963, -64.9672817,
  'images/IMG_3742.jpeg', '', '', '2026-02-24', 'published', 1, '2026-02-24 09:59:25', '2026-02-24 09:59:25'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771927165427', 'solaire');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771927165427', 'deplacement');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1771927239348', 'CAMPAGNE D’ÉCONOMIE D’ÉNERGIE', 'ENERGY SAVING CAMPAIGN', '1979',
  'En France, le rationnement du fuel vient d’entrer en vigueur. Afin de sensibiliser la population française, une campagne d’information, incarnée par un personnage de bande dessinée, Gaspi, est lancée. Elle contient notamment une description des techniques pour économiser l’essence.', 'In France, fuel rationing has just come into effect. In order to raise awareness among the French population, an information campaign featuring a comic book character named Gaspi has been launched. It includes a description of techniques for saving fuel.', 'Bertrand Lapostolet',
  '', '', NULL, NULL,
  'images/IMG_3743.jpeg', '', '', '2026-02-24', 'published', 1, '2026-02-24 10:00:39', '2026-02-24 10:00:39'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771927239348', 'politique-publique');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1771927305329', 'PANNEAUX SOLAIRES SUR LA MAISON BLANCHE', 'SOLAR PANELS ON THE WHITE HOUSE', '1979',
  'En 1979, Jimmy Carter, dans un geste visionnaire, a installé des panneaux solaires thermiques sur le toit de la Maison Blanche. Cette installation symbolique a été démontée en 1986 dès la présidence Reagan. En 1991, UNITY COLLEGE, un centre d’apprentissage soucieux de l''environnement dans le Maine récupère les panneaux et les installe sur le toit de leur cafétéria. \n\nEn 2010, nos deux paléo-héros zurichois Roman Keller et Cristina Hemauer exhument l''histoire oubliée de ces panneaux solaires définitivement entrés dans l''histoire américaine. Ce projet d''art donnera suite à une campagne populaire "put solar on it" pour la ré-installation de panneaux solaires sur la Maison Blanche. \n', 'In 1979, Jimmy Carter, in a visionary move, installed solar thermal panels on the roof of the White House. This symbolic installation was dismantled in 1986 at the start of Reagan''s presidency. In 1991, UNITY COLLEGE, an environmentally conscious learning center in Maine, recovered the panels and installed them on the roof of their cafeteria. \n\nIn 2010, our two Zurich paleo-heroes Roman Keller and Cristina Hemauer unearthed the forgotten history of these solar panels, which had become part of American history. This art project led to a popular campaign called "put solar on it" to reinstall solar panels on the White House. ', 'Roman Keller et Christina Hemaeur',
  'Washington', 'Washington', 38.8950368, -77.0365427,
  'images/IMG_3744.jpeg', '', '', '2026-02-24', 'published', 1, '2026-02-24 10:01:45', '2026-02-24 10:01:45'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771927305329', 'solaire');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771927305329', 'electricite');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771927305329', 'politique-publique');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1771927454026', 'LES PILES ALCALINES SONT RECHARGABLE', 'ALKALINE BATTERIES ARE RECHARGEABLE', '1979',
  'Les piles alcalines dites « jetables », si présentes dans notre quotidien, ne sont pas réellement à usage unique. Karl Kordesch, l’un des inventeurs de la pile alcaline, l’avait démontré au début des années 1980 et voulait qu’elles soient réutilisables grâce à un régénérateur prévu pour cela. Si on l’avait suivi, on aurait pu réduire le gaspillage énergétique actuel et les impacts environnementaux des piles tout en faisant de grandes économies. Cependant, le régénérateur ne reste que très peu de temps sur le marché, et est très vite oublié.\n\nAvec une nouvelle loi sur l’obsolescence programmée, c’est donc le moment pour l’équipe Paléo-énergétique de se pencher à nouveau sur ces piles alcalines si peu efficaces (une pile alcaline demande à peu près 50 fois plus d’énergie pour sa fabrication qu’elle n’en délivrera lors de son utilisation), et de reprendre l’histoire de la pile alcaline régénérable. C’est le premier brevet exhumé par paléo-énergétique qui a été développé sous forme de projet avec Regenbox.', 'Alkaline batteries, commonly referred to as "disposable," are not truly single-use items. Karl Kordesch, one of the inventors of the alkaline battery, demonstrated this in the early 1980s and wanted them to be reusable with a special regenerator. If his idea had been followed, we could have reduced current energy waste and the environmental impact of batteries, while making significant savings. However, the regenerator remained on the market for only a very short time and was quickly forgotten.\n\nWith a new law on planned obsolescence, it is now time for the Paleo-Energy team to take another look at these inefficient alkaline batteries (an alkaline battery requires about 50 times more energy to manufacture than it will deliver during use) and revisit the history of the regenerable alkaline battery. This is the first patent unearthed by Paleo-Energy that has been developed as a project with Regenbox.', 'Edouard Bertrand',
  'États-Unis', 'United States', 39.7837304, -100.445882,
  'images/IMG_3745.jpeg', '', '', '2026-02-24', 'published', 1, '2026-02-24 10:04:14', '2026-02-24 10:04:14'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771927454026', 'electricite');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771927454026', 'conservation-de-lenergie');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1771927506439', 'VOITURE À HYDROGÈNE PAR JEAN-LUC PERRIER', 'HYDROGEN CAR BY JEAN-LUC PERRIER', '1979',
  'Le concentrateur solaire de Jean-Luc Perrier (50 kw) pouvait transformer l’énergie solaire en hydrogène par électrolyse de l’eau. Le concentrateur chauffait de l’eau en son foyer central et la vapeur sous pression produite faisait tourner une génératrice électrique nécessaire au processus. Son véhicule pouvait ainsi tourner en ne rejetant que de la vapeur d’eau. Perrier publiait en 1979 un ouvrage de référence intitulé “Énergie solaire : état actuel des applications” aux Editions Techniques et Scientifiques Françaises.', 'Jean-Luc Perrier''s solar concentrator (50 kW) could convert solar energy into hydrogen through water electrolysis. The concentrator heated water in its central chamber and the pressurized steam produced turned an electric generator needed for the process. His vehicle could thus run on steam alone. In 1979, Perrier published a reference work entitled "Solar Energy: Current Status of Applications" with Editions Techniques et Scientifiques Françaises.', 'Marcel Robert et Thomas Ortiz',
  'France', 'France', 46.603354, 1.8883335,
  'images/IMG_3746.jpeg', '', '', '2026-02-24', 'published', 1, '2026-02-24 10:05:06', '2026-02-24 10:05:06'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771927506439', 'solaire');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771927506439', 'hydrogene');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771927506439', 'deplacement');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1771927695310', 'LES CHAMPIGNONS DE MORI KISAKU', 'MORI KISAKU''S MUSHROOMS', '1980',
  'Apprécié pour son arôme unique et ses nombreuses propriétés, le shiitaké aurait été cultivé en Chine dès le XIIe siècle avant d’être importé au Japon au XVIe. On lacérait alors l’écorce de bûches pour que les spores s’y développent.\n\nEn 1932, lors d’un séjour à Oita, Mori Kisaku, étudiant agronome à Kyoto, fut marqué par un agriculteur priant devant une bûche pour y voir pousser des shiitakés. Il décida de se consacrer à l’étude de cette manne. Dix ans plus tard, il développa une méthode innovante : cultiver le mycélium – l’appareil végétatif du champignon – sur de petits taquets de bois insérés dans les bûches. Cette technique permettait des récoltes rapides et une sélection génétique optimale.\n\nIl commercialisa ses “semences de champignons” et créa un centre de recherche pionnier sur les bienfaits des champignons pour la santé, faisant du shiitaké un pilier de l’alimentation japonaise. Sa méthode est aujourd’hui un fondement de la culture champignonnière mondiale.', 'Prized for its unique aroma and numerous properties, shiitake mushrooms are believed to have been cultivated in China as early as the 12th century before being imported to Japan in the 16th century. At that time, the bark of logs was slashed so that spores could grow on them.\n\nIn 1932, during a stay in Oita, Mori Kisaku, an agricultural student in Kyoto, was struck by a farmer praying in front of a log to see shiitake mushrooms grow. He decided to devote himself to studying this manna. Ten years later, he developed an innovative method: growing mycelium—the vegetative part of the mushroom—on small pieces of wood inserted into logs. This technique allowed for rapid harvesting and optimal genetic selection.\n\nHe marketed his "mushroom seeds" and created a pioneering research center on the health benefits of mushrooms, making shiitake a staple of the Japanese diet. His method is now a cornerstone of mushroom cultivation worldwide.', 'Cedric Carles',
  'Oita', 'Go', 33.2393864, 131.6096524,
  'images/IMG_3747.jpeg', '', 'kinokologie.com', '2026-02-24', 'published', 1, '2026-02-24 10:08:15', '2026-02-24 10:08:15'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771927695310', 'agriculture');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1771928457017', 'LE VILLAGE DE N’GUELAKH, MODÈLE DE RÉSILIENCE', 'THE VILLAGE OF N’GUELAKH, A MODEL OF RESILIENCE', '1980',
  'Situé à 19 km de Saint-Louis, le village de N’Guelakh, frappé par les sécheresses des années 1970, a amorcé une transformation radicale grâce à l’initiative de deux cousins revenus sur leurs terres. \n\nLe projet, lancé dans les années 1980, a combiné agroécologie, formation, artisanat et autonomie énergétique. Aujourd’hui, le village cultive légumes et céréales, élève bétail et poissons, produit du biogaz, et forme des jeunes à l’agroélevage durable. \nLes femmes, via un atelier textile et des activités de transformation, ont créé une mutuelle de santé et une banque de microcrédit. \n\nN’Guelakh est devenu un modèle de développement intégré, reproduit dans plus de 20 autres localités.', 'Located 19 km from Saint-Louis, the village of N''Guelakh, hit by droughts in the 1970s, has undergone a radical transformation thanks to the initiative of two cousins who returned to their land. The project, launched in the 1980s, combined agroecology, training, crafts, and energy independence. Today, the village grows vegetables and cereals, raises livestock and fish, produces biogas, and trains young people in sustainable agriculture and livestock farming. The women, through a textile workshop and processing activities, have created a health mutual and a microcredit bank. N''Guelakh has become a model of integrated development, replicated in more than 20 other localities.', 'Raphaël Luciani-Galais',
  'Saint-Louis', 'Saint Louis', 38.6254063, -90.190009,
  'images/IMG_3748.jpeg', '', 'http://www.lestissusdeguelack.com/topic/index.html', '2026-02-24', 'published', 1, '2026-02-24 10:20:57', '2026-02-24 10:20:57'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771928457017', 'agriculture');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771928457017', 'electricite');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771928457017', 'biogaz');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1771928634604', 'LE PUIT CANADIEN / PROVENÇAL', 'THE CANADIAN/PROVENCAL WELL', '1981',
  'Le puit canadien diminue la consommation de chauffage l''hiver, tout en procurant un surcroît de confort en été.\n\nEn hiver le système permet d''avoir un air insufflé dans les pièces d''environ + 5° C par rapport à la température externe. (à associer avec une vmc double flux pour encore plus d''efficacité).\n\nEn été le puit canadien permet d''abaisser la température d''environ 2 à 5° C. L''efficacité est plus grande par forte chaleur, c''est à dire au moment où l''on en a le plus besoin (à associer avec une vmc double flux pour encore plus d''efficacité).\n\nPlus de moisissures . Lorsque l''air circule dans la conduite du puits, il se condense à mesure qu’il se réchauffe ou qu’il se refroidit, et dépose de fines gouttelettes d’eau. L’été, le phénomène peut engendrer un litre d’eau par jour. Pour éviter la stagnation des condensats, qui peuvent développer des bactéries et des moisissures et ralentir le flux de l’air, il est important que la gaine possède une pente de 2 à 3 %. Un syphon permettra de récupérer ces condensats au bout du tuyau dans le sous-sol. Si la maison est dépourvue de cave, on pourra utiliser un regard ou un puits perdu au point le plus bas', 'The Canadian well reduces heating consumption in winter, while providing additional comfort in summer. In winter, the system allows air to be blown into rooms at a temperature approximately +5°C higher than the outside temperature. (Combine with a dual-flow CMV for even greater efficiency).\n\nIn summer, the Canadian well lowers the temperature by around 2 to 5°C. It is most effective in very hot weather, i.e. when it is most needed (combine with a dual-flow CMV system for even greater efficiency).\n\nNo more mold. As air circulates through the well duct, it condenses as it warms or cools, depositing fine water droplets. In summer, this phenomenon can generate up to one liter of water per day. To prevent condensation from stagnating, which can lead to the growth of bacteria and mold and slow down the flow of air, it is important that the duct has a slope of 2 to 3%. A siphon will collect this condensation at the end of the pipe in the basement. If the house does not have a basement, a manhole or a drain well at the lowest point can be used.', 'Jean Dard',
  '', '', NULL, NULL,
  'images/IMG_3749.jpeg', '', '', '2026-02-24', 'published', 1, '2026-02-24 10:23:54', '2026-02-24 10:23:54'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771928634604', 'h2o');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771928634604', 'rafraichir');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771928634604', 'rechauffer');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1771928686758', 'UN CHAUFFAGE SOLAIRE À BOGOTÀ', 'SOLAR HEATING IN BOGOTÁ', '1983',
  'De par sa géographie et sa diversité climatique, la Colombie est le pays d’Amérique du sud avec le plus haut potentiel énergétique. L’énergie solaire ne fait pas exception.\n\nVoici le chauffage de la cafétéria de l''ancienne Bogotá Energy Company (EEB). Construit en 1983 par le Centre Las Gaviotas, il est constitué de 140 m2 de collecteurs et d’un réservoir de 12 000 litres.\n\nLes études de conception et les calculs d''efficacité ont été réalisés par l''Université nationale de Colombie. Cette installation est toujours en exploitation.', 'Due to its geography and climatic diversity, Colombia is the South American country with the highest energy potential. Solar energy is no exception. Here is the heating system for the cafeteria of the former Bogotá Energy Company (EEB). Built in 1983 by the Las Gaviotas Center, it consists of 140 m² of collectors and a 12,000-liter tank. The design studies and efficiency calculations were carried out by the National University of Colombia. This facility is still in operation.', 'Marcelo Roberto',
  'Bogota', 'Bogotá', 4.6533817, -74.0836331,
  'images/IMG_3750.jpeg', '', '', '2026-02-24', 'published', 1, '2026-02-24 10:24:46', '2026-02-24 10:24:46'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771928686758', 'rechauffer');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771928686758', 'solaire');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1771928827958', 'L’EXPÉRIENCE DE NDEM DANS LE SAHEL SÉNÉGALAIS', 'NDEM''s experience in the Senegalese Sahel', '1985',
  'Au cœur du Sahel sénégalais, le village de Ndem s’est transformé en un écovillage exemplaire, alliant traditions locales et solutions durables. Fondée en 1985, l’Association des Villageois de Ndem (AVND) a fédéré une vingtaine de villages autour d’un projet global : restaurer les sols par le compostage, assurer l’accès à l’eau potable via des forages solaires, et produire de l’énergie renouvelable pour les besoins domestiques et artisanaux. \n\nL’artisanat est devenu un pilier économique, notamment à travers les ateliers Maam Samba, qui emploient plus de 300 artisans, majoritairement des femmes, dans des filières textiles, cuir, métal ou vannerie. Les produits, certifiés commerce équitable, sont exportés à l’international. \n\nL’ONG a également investi dans l’éducation, la santé, l’agroécologie et la reforestation, créant un modèle intégré de développement endogène. Aujourd’hui, Ndem est reconnu comme un laboratoire vivant de transition écologique et sociale.', 'In the heart of Senegal''s Sahel region, the village of Ndem has been transformed into an exemplary ecovillage, combining local traditions with sustainable solutions. Founded in 1985, the Association des Villageois de Ndem (AVND) has brought together some 20 villages around a global project: restoring soil through composting, ensuring access to drinking water via solar boreholes, and producing renewable energy for domestic and artisanal needs. \n\nCraftsmanship has become an economic pillar, particularly through the Maam Samba workshops, which employ more than 300 artisans, mostly women, in the textile, leather, metal, and basketry sectors. The products, which are certified fair trade, are exported internationally. \n\nThe NGO has also invested in education, health, agroecology, and reforestation, creating an integrated model of endogenous development. Today, Ndem is recognized as a living laboratory for ecological and social transition.', 'Raphaël Luciani-Galais',
  'Sénégal', 'Senegal', 14.4750607, -14.4529612,
  'images/IMG_3751.jpeg', '', 'https://ong-ndem.solidarite-ndem-france.fr/agroecologie-rapport-dactivite-2022/', '2026-02-24', 'published', 1, '2026-02-24 10:27:07', '2026-02-24 10:27:07'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771928827958', 'politique-publique');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771928827958', 'agriculture');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1771928913225', 'RETOUR AU « TASSA » POUR RESTAURER LA FERTILITÉ', 'RETURN TO THE "TASSA" TO RESTORE FERTILITY', '1989',
  'La technique ancestrale du tassa consiste à creuser des trous de 10 à 40 cm de diamètre et de 10 à 25 cm de profondeur, disposés en quinconce à intervalles réguliers d’environ 80 cm. Ces poches captent l’eau de pluie, réduisent le ruissellement et l’érosion, et conservent l’humidité. En y ajoutant du compost ou du fumier, on stimule l’activité des termites, qui améliorent la structure et la fertilité du sol. Vulgarisée dans les années 1990 par des projets de développement agricole, cette méthode a multiplié par plus de deux les rendements. Peu coûteuse, adaptée aux conditions locales et reproductible, elle donne de bonne perspectives à des terre réputé comme peu fertile..', 'The ancestral technique of tassa involves digging holes 10 to 40 cm in diameter and 10 to 25 cm deep, arranged in a staggered pattern at regular intervals of about 80 cm. These pockets capture rainwater, reduce runoff and erosion, and conserve moisture. Adding compost or manure stimulates termite activity, which improves soil structure and fertility. Popularized in the 1990s by agricultural development projects, this method has more than doubled yields. Inexpensive, adapted to local conditions, and reproducible, it offers good prospects for land considered to be infertile.', 'Raphaël Luciani-Galais',
  '', '', NULL, NULL,
  'images/IMG_3752.jpeg', '', 'https://sciences2d.wordpress.com/2013/06/10/le-tassa-fait-le-bonheur-des-paysans-au-niger/', '2026-02-24', 'published', 1, '2026-02-24 10:28:33', '2026-02-24 10:28:33'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771928913225', 'agriculture');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771928913225', 'h2o');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1771928972661', 'PREMIERS EXCÈS DE VITESSE SOLAIRE DE L’HISTOIRE', 'FIRST SOLAR SPEED EXCESSES IN HISTORY', '1989',
  'Lors d’une course d’essai, la voiture de l’Ecole d’ingénieurs de Bienne (Suisse), a été interpellée par la maréchaussée pour excès de vitesse.\n\nCette voiture solaire était destinée au championnat du monde des voitures solaires, organisé la même année. La sortie du prototype s’est soldée par une amende de 20 francs, conclut le journaliste.', 'During a test run, the car from the Biel School of Engineering (Switzerland) was stopped by the police for speeding. This solar car was intended for the world solar car championship, held that same year. The prototype''s outing resulted in a fine of 20 francs, the journalist concludes.', 'Raphaël Domjan et Louis Palmer',
  'Bienne', 'Bienne', 47.1402077, 7.2439029,
  'images/IMG_3753.jpeg', '', '', '2026-02-24', 'published', 1, '2026-02-24 10:29:32', '2026-02-24 10:29:32'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771928972661', 'electricite');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771928972661', 'deplacement');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1771929029984', 'IRRIGATION PAR LES RACINES', 'ROOT IRRIGATION', '1990',
  'L’irrigation par les racines est un système de culture surélevée combinant un réservoir d’eau souterrain et un substrat de culture. L’eau remonte par capillarité jusqu’aux racines des plantes, ce qui permet une irrigation passive et maîtrisée. \n\nCette méthode réduit l’évaporation et l’utilisation d’eau, tout en assurant une alimentation hydrique constante. Elle a été conçue à l’origine pour les zones arides, et peut être construite à partir de matériaux simples (graviers, géotextile, compost). \n\nCe procédé est utilisé en agriculture urbaine, en permaculture et dans des contextes à ressources hydriques limitées', 'Root irrigation is a raised growing system that combines an underground water reservoir with a growing medium. Water rises through capillary action to the plant roots, providing passive and controlled irrigation. \n\nThis method reduces evaporation and water use, while ensuring a constant water supply. It was originally designed for arid areas and can be constructed from simple materials (gravel, geotextile, compost). This process is used in urban agriculture, permaculture, and in contexts with limited water resources.', 'Cedric Carles ',
  '', '', NULL, NULL,
  'images/IMG_3754.jpeg', '', '', '2026-02-24', 'published', 1, '2026-02-24 10:30:29', '2026-02-24 10:30:29'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771929029984', 'h2o');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771929029984', 'agriculture');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772189723023', 'Le projet de redécouverte de la Vielle-Mer', 'The Vielle-Mer Rediscovery Project', '2025',
  'La Vieille Mer est un petit cours d’eau d’une longueur de 6,5 km de Seine-Saint-Denis qui se jette dans la Seine au niveau du canal Saint-Denis. À cause de l’activité industrielle et de l’urbanisation cause une forte pollution au cours du XXe siècle. En 1957, la Vieille Mer est canalisée, busée puis recouverte. Elle sert aujourd’hui d’écoulement pour les eaux pluviales. \nDès 1998, le Syndicat interdépartemental d’Assainissement de l’Agglomération parisienne étudie la faisabilité de la redécouverte de la rivière. \nCette redécouverte répondrait à des enjeux patrimoniaux, environnementaux ou encore paysagers. Ce projet était présent dans le plan d’investissement bassin 2018-2024 du Département Seine-Saint-Denis, avec l’étude de la possibilité de découvrir une portion de 3 km au sein du parc Georges-Valbon à La Courneuve.', 'The Vieille Mer is a small 6.5 km long watercourse in Seine-Saint-Denis that flows into the Seine at the Saint-Denis canal. Industrial activity and urbanization caused severe pollution during the 20th century. In 1957, the Vieille Mer was channeled, culverted, and then covered over. Today, it serves as a drainage system for rainwater. Since 1998, the Interdepartmental Sanitation Syndicate of the Paris Agglomeration has been studying the feasibility of rediscovering the river. \nThis rediscovery would address heritage, environmental, and landscape issues. The project was included in the Seine-Saint-Denis Department''s 2018-2024 basin investment plan, with a study of the possibility of uncovering a 3 km section within the Georges-Valbon park in La Courneuve.', 'Khadidiatou Sy (d''après son mémoire)',
  'Seine-Saint-Denis', 'Seine-Saint-Denis', 48.9098125, 2.4528635,
  'images/Confluence_du_Croult_du_Canal_St_Denis_et_de_la_Seine.jpg', 'Confluence de la Vieille Mer (au niveau du pont jaune), du canal Saint-Denis et de la Seine, 25/11/06, Claude Shoshany, Wikimedia Commons. https://commons. wikimedia.org/wiki/File:Confluence_du_Croult,_du_Canal_St_ Denis_et _de_la_Seine.JPG', 'https://www.gpmetropole-infos.fr/la-vieille-mer-redecouverte-en-2024%E2%80%89/', '2026-02-26', 'published', 1, '2026-02-26 15:44:20', '2026-02-26 15:44:20'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772189723023', 'h2o');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772525640528', 'FILTRE À EAU EN CÉRAMIQUE (CWF)', 'CERAMIC WATER FILTER (CWF)', '1990',
  'L’idée d’utiliser la céramique pour filtrer l’eau remonte à des pratiques ancestrales. La version moderne des filtres à eau en céramique, adaptée à la purification de l’eau dans des contextes de développement et de randonnée, a été popularisée dans les années 1990.\n\nLes filtres à eau en céramique (CWF) reposent sur l’utilisation d’un matériau céramique poreux dont la petite taille des pores permet de retenir la saleté, les débris et même les bactéries présentes dans l’eau.\nL’eau passe à travers le filtre, où les impuretés sont bloquées par les pores microscopiques du matériau céramique, offrant ainsi une eau plus propre et plus sûre pour la consommation.\n\nCe dispositif est particulièrement adapté aux pays en développement, où il offre une solution peu coûteuse et accessible pour la purification de l’eau. Il est également décliné en version portable, largement utilisé lors de randonnées ou en situations d’urgence. La fabrication des filtres repose sur des procédés artisanaux utilisant des matériaux locaux, ce qui les rend accessibles et faciles à produire sans besoin d’énergie sophistiquée. Leur fonctionnement ne nécessite pas d’électricité et demande peu d’entretien, ce qui en fait une solution résiliente et écologique pour garantir l’accès à une eau potable.\n\nQue ce soit dans un contexte rural de pays en développement ou dans des activités de plein air comme la randonnée, ces filtres illustrent parfaitement comment une technologie low-tech peut répondre efficacement à un bes', 'The idea of using ceramics to filter water dates back to ancient practices. The modern version of ceramic water filters, adapted for water purification in development and hiking contexts, was popularized in the 1990s.\n\nCeramic water filters (CWFs) rely on the use of a porous ceramic material whose small pore size traps dirt, debris, and even bacteria present in the water.\nWater passes through the filter, where impurities are blocked by the microscopic pores of the ceramic material, providing cleaner and safer water for consumption. This device is particularly suitable for developing countries, where it offers an inexpensive and accessible solution for water purification. It is also available in a portable version, widely used during hiking or in emergency situations. The filters are manufactured using traditional methods and local materials, making them accessible and easy to produce without the need for sophisticated energy sources. They do not require electricity to operate and need little maintenance, making them a resilient and environmentally friendly solution for ensuring access to safe drinking water.\n\nWhether in rural areas of developing countries or in outdoor activities such as hiking, these filters perfectly illustrate how low-tech technology can effectively meet a need.', 'Lola Baron',
  '', '', NULL, NULL,
  'images/IMG_3787.jpeg', '', '', '2026-03-03', 'published', 1, '2026-03-03 08:14:00', '2026-03-03 08:14:00'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772525640528', 'h2o');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772525746291', 'BATIMENT TERMITE DE AU ZIMBABWE DE MIKE PEARCE', 'MIKE PEARCE''S TERMITE BUILDING IN ZIMBABWE', '1991',
  'Mike Pearce, en 1991, s''est retrouvé face à un challenge : devoir construire un immeuble de 7 étages sans utiliser l''air-conditionné ! Situé au Zimbabwe, le Eastgate Center est inspiré des grandes termitières pour faire des économies d''énergie et d''argent.\n\nUne termitière atteint jusqu''à 9 mètres de haut et dispose d’un système ingénieux : elle est couverte de petits trous qui permettent à l''air de passer, stocker l''air frais pour le redistribuer et évacuer la chaleur à l''extérieur.\n\nLe Eastgate Center est en béton et en briques. Comme le sol des termitières, ces matériaux ont une forte masse thermique, c''est-à-dire qu''ils absorbent beaucoup de chaleur.\n\nL’architecte a muni l''extérieur du building de surfaces supplémentaires en forme de petites cloisons ouvertes pour contrôler la température.\n\nAvec de nombreux systèmes souterrains de ventilations, l''air frais est redistribué sur l''ensemble des 7 étages de l''immeuble. Quant à l''air chaud, il est évacué à travers des cheminées. La température avoisine les 27°C à l''intérieur lorsqu''il fait 40°C à l''extérieur.', 'In 1991, Mike Pearce faced a challenge: to build a seven-story building without using air conditioning! Located in Zimbabwe, the Eastgate Center was inspired by large termite mounds to save energy and money.\n\nA termite mound can reach up to 9 meters high and has an ingenious system: it is covered with small holes that allow air to pass through, store cool air for redistribution, and evacuate heat to the outside.\n\nThe Eastgate Center is made of concrete and brick. Like the ground of termite mounds, these materials have a high thermal mass, meaning they absorb a lot of heat. The architect equipped the exterior of the building with additional surfaces in the form of small open partitions to control the temperature.\n\nWith numerous underground ventilation systems, cool air is redistributed throughout the building''s seven floors. Hot air is evacuated through chimneys. The temperature inside is around 27°C when it is 40°C outside.', 'Fabien Lyraud',
  'Zimbabwe', 'Zimbabwe', -18.4554963, 29.7468414,
  'images/IMG_3788.jpeg', '', '', '2026-03-03', 'published', 1, '2026-03-03 08:15:46', '2026-03-03 08:15:46'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772525746291', 'eolien');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772525746291', 'rafraichir');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772525889988', 'SÉCHOIRS SOLAIRES DU GRET', 'SOLAR DRYERS FROM GRET', '1996',
  'Le GRET accompagne depuis plusieurs années l’implantation de séchoirs solaires auprès d’acteurs agroalimentaires artisanaux, notamment au Togo, au Burkina Faso, en Guinée et au Sénégal. Ces dispositifs, conçus pour améliorer la conservation post-récolte de produits agricoles (mangues, tomates, oignons, poissons), s’inscrivent dans une logique d’autonomisation énergétique et de valorisation des productions locales.\n\nEn remplaçant les séchages à l’air libre (soumis aux intempéries et à la contamination) ou au feu de bois (gourmand en ressources), les séchoirs solaires permettent un séchage hygiénique, plus rapide et constant. Cela améliore non seulement la qualité des produits mais également leur valeur marchande, favorisant la structuration de filières économiques locales.', 'For several years, GRET has been supporting the installation of solar dryers for small-scale food producers, particularly in Togo, Burkina Faso, Guinea, and Senegal. These devices, designed to improve post-harvest preservation of agricultural products (mangoes, tomatoes, onions, fish), are part of a strategy to promote energy independence and add value to local production.\n\nBy replacing open-air drying (subject to weather conditions and contamination) or wood-fired drying (resource-intensive), solar dryers enable hygienic, faster, and more consistent drying. This not only improves product quality but also their market value, promoting the structuring of local economic sectors.', 'Raphaël Luciani-Galais',
  'Togo', 'Go to', 8.7800265, 1.0199765,
  'images/IMG_3789.jpeg', '', 'https://sciences2d.wordpress.com/2013/06/10/le-tassa-fait-le-bonheur-des-paysans-au-niger/', '2026-03-03', 'published', 1, '2026-03-03 08:18:09', '2026-03-03 08:18:09'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772525889988', 'solaire');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772525889988', 'agriculture');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772525889988', 'conservation-alimentaire');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772526010895', 'S’INSPIRER DU VIVANT POUR ADAPTER L’ARCHITECTURE', 'TAKING INSPIRATION FROM LIFE TO ADAPT ARCHITECTURE', '1996',
  'Le pôle d''excellence en biomimétisme marin est un projet qui a été lancé par la Communauté d''agglomération du Pays Basque qui demandait une construction biomimétique. Le projet est inspiré d''Epleuctella aspergillum, une éponge de verre. Les éponges de verre génèrent un squelette adapté aux conditions environnementales. Ce squelette permet de filtrer, absorber, oxygéner l''eau et d''apporter des nutriments.\n\nInspiré du même principe, une brique de terre crue est utilisée et assemblée sous forme de voûtes maçonnées. La forme de ces voûtes permet la circulation de l''eau, sa filtration, sa rétention, son traitement pour la rendre propre à l''océan, et permettre d''avoir une régulation de la température, de l''hygrométrie, de l''ensoleillement.', 'The marine biomimicry center of excellence is a project launched by the Basque Country Urban Community, which requested a biomimetic construction. The project is inspired by Epleuctella aspergillum, a glass sponge. Glass sponges generate a skeleton adapted to environmental conditions. This skeleton filters, absorbs, oxygenates the water, and provides nutrients.\n\nInspired by the same principle, raw earth bricks are used and assembled in the form of masonry vaults. The shape of these vaults allows water to circulate, be filtered, retained, and treated to make it suitable for the ocean, and allows for the regulation of temperature, humidity, and sunlight.', 'Cédric Carles',
  'Pays basque', 'Basque Country', 42.9911816, -2.5543023,
  'images/IMG_3790.jpeg', '', '', '2026-03-03', 'published', 1, '2026-03-03 08:20:10', '2026-03-03 08:20:10'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772526010895', 'solaire');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772526010895', 'biomimetisme');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772526010895', 'h2o');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772526074240', ' CITERNE HIPPO WATER ROLLER', ' HIPPO WATER ROLLER TANK', '1997',
  'Dans de très nombreux pays d''Afrique et en Inde, près de 750 millions de personnes n''ont pas accès à l''eau potable. Sur des distances plus ou moins grandes, il est nécessaire de transporter l''eau.\n\nPettie Petzer et Johan Jonker mettent au point un outil qui facilite cette tâche éreintante souvent exécutée par les femmes.\n\nFabriqué en Afrique, ce tonneau de 90L en Polyéthylène protecteur d''UV est conçu pour pouvoir rouler facilement sur des surfaces difficiles.\n\nAujourd''hui c''est plus de 65 000 Hippo Roller distribués dans 56 pays.', 'In many countries in Africa and India, nearly 750 million people do not have access to drinking water. Water must be transported over varying distances. Pettie Petzer and Johan Jonker are developing a tool to facilitate this exhausting task, which is often performed by women.\n\nManufactured in Africa, this 90-liter barrel made of UV-protective polyethylene is designed to roll easily over rough surfaces. Today, more than 65,000 Hippo Rollers have been distributed in 56 countries.', 'Simon Bouchaudy',
  'Afrique', 'Africa', 11.5024338, 17.7578122,
  'images/IMG_3791.jpeg', '', '', '2026-03-03', 'published', 1, '2026-03-03 08:21:14', '2026-03-03 08:21:14'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772526074240', 'h2o');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772526168957', 'RÉENSAUVAGEMENT HYDRIQUE', 'WATER REWILDING', 'XXI siècle',
  'Cette méthode de réensauvagement hydrique s’inspire des castors pour restaurer les écosystèmes aquatiques et réhydrater les prairies. Sur une ferme, les pratiques de construction de barrages de castors ont été imitées pour ralentir l’écoulement de l’eau d’une rivière asséchée, permettant à celle-ci de retrouver son lit naturel et de revitaliser les sols adjacents. Ces "barrages artificiels" recréent des zones humides en piégeant l’eau et en l’infiltrant lentement dans les terres, favorisant ainsi une biodiversité riche et résiliente.\n\nLes barrages ralentissent le débit de l’eau et créent des retenues naturelles, imitant l’habitat du castor et recréant des micro environnements humides. Cela aide à restaurer les nappes phréatiques, régénère les prairies et renforce la résilience des écosystèmes en période de sécheresse. ', 'This method of water rewilding takes inspiration from beavers to restore aquatic ecosystems and rehydrate grasslands. On a farm, beaver dam construction practices were imitated to slow the flow of water from a dried-up river, allowing it to return to its natural bed and revitalize the adjacent soils. These "artificial dams" recreate wetlands by trapping water and slowly infiltrating it into the land, promoting rich and resilient biodiversity.\n\nThe dams slow the flow of water and create natural reservoirs, mimicking the beaver''s habitat and recreating micro-wetland environments. This helps restore groundwater levels, regenerates grasslands, and strengthens the resilience of ecosystems during periods of drought. ', 'Cédric Carles',
  '', '', NULL, NULL,
  'images/IMG_3792.jpeg', '', '', '2026-03-03', 'published', 1, '2026-03-03 08:22:48', '2026-03-03 08:22:48'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772526168957', 'biomimetisme');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772526168957', 'h2o');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772526168957', 'agriculture');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772526251926', 'FILETS PHOTOSELECTIFS : FILTRER POUR CULTIVER', 'PHOTOSELECTIVE NETS: FILTERING FOR CULTIVATION', 'XXI siècle',
  'Conçus pour répondre aux stress thermiques croissants dans les zones agricoles arides ou semi-arides, les filets photoselectifs sont des dispositifs textiles posés au-dessus des cultures maraîchères. \nLeur composition en polymères spécifiques permet de filtrer certaines longueurs d’onde du spectre solaire, réduisant la chaleur excessive, les ultraviolets nuisibles ou encore l’intensité lumineuse directe.\n\nContrairement aux filets d’ombrage classiques, ils sont conçus pour optimiser à la fois la croissance végétale et la photosynthèse. Cette technologie améliore les rendements, protège les plants des coups de chaleur, limite l’évapotranspiration et contribue à une gestion plus fine de l’irrigation. \n\nTestés notamment en Afrique du Nord et en Israël, ils représentent une adaptation agricole prometteuse aux dérèglements climatiques, conciliant innovation technologique et sobriété énergétique.\n', 'Designed to respond to increasing heat stress in arid or semi-arid agricultural areas, photoselective nets are textile devices placed over vegetable crops. Their specific polymer composition filters certain wavelengths of the solar spectrum, reducing excessive heat, harmful ultraviolet rays, and direct light intensity.\n\nUnlike conventional shade nets, they are designed to optimize both plant growth and photosynthesis. This technology improves yields, protects plants from heat stress, limits evapotranspiration, and contributes to more precise irrigation management. \n\nTested in North Africa and Israel, among other places, they represent a promising agricultural adaptation to climate change, combining technological innovation and energy efficiency. ', 'Raphael Luciani-Galais',
  'Afrique du nord', 'North Africa', 41.362599, 2.159665,
  'images/IMG_3793.jpeg', '', '', '2026-03-03', 'published', 1, '2026-03-03 08:24:11', '2026-03-03 08:24:11'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772526251926', 'agriculture');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772526251926', 'solaire');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772526318453', 'MARAÎCHAGE VERTICAL À GRAVITÉ PASSIVE', 'PASSIVE GRAVITY VERTICAL FARMING', 'XXI siècle',
  'Le maraîchage vertical à gravité passive est une technique qui permet de cultiver des plantes en hauteur tout en utilisant la gravité pour l’irrigation, éliminant ainsi le besoin de pompes ou d’électricité. Ce système repose sur un réservoir d’eau placé en hauteur, d’où l’eau s’écoule lentement vers les plantes via un réseau de tuyaux ou de goutteurs. Cette méthode optimise l’utilisation de l’espace, réduit la consommation d’eau et est particulièrement adaptée aux environnements urbains ou aux zones à ressources limitées. Des projets tels que le Passive Gravity Irrigated Planter démontrent la faisabilité de cette approche, offrant une solution accessible et durable pour l’agriculture urbaine.\n', 'Passive gravity vertical farming is a technique that allows plants to be grown at height while using gravity for irrigation, eliminating the need for pumps or electricity. This system relies on a water reservoir placed at height, from which water slowly flows to the plants via a network of pipes or drippers. This method optimizes space utilization, reduces water consumption, and is particularly suitable for urban environments or areas with limited resources. Projects such as the Passive Gravity Irrigated Planter demonstrate the feasibility of this approach, offering an accessible and sustainable solution for urban agriculture. ', 'Raphael Luciani-Galais ',
  '', '', NULL, NULL,
  'images/IMG_3794.jpeg', '', 'https://www.instructables.com/Gravity-Irrigated-Planter/', '2026-03-03', 'published', 1, '2026-03-03 08:25:18', '2026-03-03 08:25:18'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772526318453', 'h2o');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772526318453', 'agriculture');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772526398245', 'LES BÂTIMENTS “ÉPONGES”', 'SPONGE BUILDINGS', 'XII siècle',
  'Les bâtiments « éponges » sont des constructions conçues pour absorber, stocker et redistribuer l’eau de manière intelligente, s’adaptant ainsi aux variations climatiques et aux risques d’inondation. Ce concept repose sur l’utilisation de matériaux poreux, de toitures et façades végétalisées, ainsi que de bassins de rétention intégrés aux infrastructures urbaines.\n\nDéveloppé dans les années 2010, notamment en Chine avec le programme des « Sponge Cities », ce modèle d’urbanisme vise à réduire le ruissellement et améliorer la résilience des villes face aux épisodes de fortes pluies. Des pays comme Singapour et les Pays-Bas ont également intégré cette approche à leurs stratégies d’aménagement. \n\nCes bâtiments représentent une réponse aux défis posés par l’urbanisation croissante et le changement climatique, en favorisant une utilisation plus efficace et durable de l’eau dans l’espace urbain.', 'Sponge buildings are structures designed to absorb, store, and redistribute water in an intelligent way, adapting to climate variations and flood risks. This concept is based on the use of porous materials, green roofs and facades, and retention basins integrated into urban infrastructure.\n\nDeveloped in the 2010s, particularly in China with the "Sponge Cities" program, this urban planning model aims to reduce runoff and improve the resilience of cities in the face of heavy rainfall. Countries such as Singapore and the Netherlands have also incorporated this approach into their development strategies. \n\nThese buildings represent a response to the challenges posed by increasing urbanization and climate change, promoting more efficient and sustainable water use in urban areas.', 'Simona Iliycheva',
  'Chine', 'China', 35.000074, 104.999927,
  'images/IMG_3795.jpeg', '', '', '2026-03-03', 'published', 1, '2026-03-03 08:26:38', '2026-03-03 08:26:38'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772526398245', 'agriculture');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772526398245', 'h2o');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772526522269', 'QUARTIERS RÉGÉNÉRATIFS EN GESTION DE L’EAU', 'REGENERATIVE NEIGHBORHOODS IN WATER MANAGEMENT', 'XXI siècle',
  'Les quartiers régénératifs sont des espaces urbains conçus pour produire, capter, recycler et réutiliser leur propre eau, réduisant ainsi leur dépendance aux réseaux d’approvisionnement classiques. Inspirés des principes de l’économie circulaire et du biomimétisme, ces projets intègrent des infrastructures intelligentes permettant une gestion locale et durable des ressources hydriques.\n\nDéveloppés dès les années 2010, ces quartiers combinent des toitures végétalisées et systèmes de récupération des eaux pluviales, de phyto épuration et filtration naturelle, des bâtiments à consommation d’eau optimisée, Stockage et réutilisation des eaux grises et noires sur place.\n\nDes initiatives pionnières comme Waternet à Amsterdam, les districts autonomes de Singapour ou encore les écoquartiers en Allemagne et aux États-Unis démontrent qu’une ville capable de gérer ses propres cycles de l’eau est non seulement possible, mais constitue une solution d’avenir face au changement climatique et à la raréfaction des ressources en eau.', 'Regenerative neighborhoods are urban spaces designed to produce, capture, recycle, and reuse their own water, thereby reducing their dependence on traditional supply networks. Inspired by the principles of the circular economy and biomimicry, these projects incorporate smart infrastructure that enables local and sustainable water resource management.\n\nDeveloped since the 2010s, these neighborhoods combine green roofs and rainwater harvesting systems, phytopurification and natural filtration, buildings with optimized water consumption, and on-site storage and reuse of gray and black water.\n\nPioneering initiatives such as Waternet in Amsterdam, Singapore''s autonomous districts, and eco-neighborhoods in Germany and the United States demonstrate that a city capable of managing its own water cycles is not only possible, but also a solution for the future in the face of climate change and water scarcity.', 'Simona Iliycheva',
  'Amsterdam', 'Amsterdam', 52.3730796, 4.8924534,
  'images/IMG_3796.jpeg', '', '', '2026-03-03', 'published', 1, '2026-03-03 08:28:42', '2026-03-03 08:28:42'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772526522269', 'agriculture');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772526522269', 'h2o');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772526522269', 'biomimetisme');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772526705371', 'MICRO MÉTHANISATION', 'MICRO METHANIZATION', '2009',
  'Les biodéchets, déchets alimentaires et autres déchets naturels biodégradables, représentent un tiers des ordures ménagères des Français.\n\nLimitée en 2016 aux plus gros acteurs économiques, l’obligation de collecte et valorisation des biodéchets s’étendra en 2025 à tous, même les plus petits. Avec la volonté de développer les filières alternatives d’énergie, la question de la méthanisation en milieu urbain prend de l’ampleur, le compostage ne pouvant répondre seul au flux urbain.\n\nMais le sujet reste complexe : au-delà de la gestion des tournées, les biodéchets sont composés à 80 % d’eau, ce qui rend leur transport sur de longues distances incohérent. D’où le développement d’unités de micro-méthanisation, souvent conteneurisées, déployables localement pour mailler un territoire au plus près des circuits de collecte.\n\nUne expérimentation de micro-méthanisation de déchets organiques urbains a ainsi été lancée au CFPH d’Écully dans le cadre de Decisive, un projet européen coordonné par l’Irstea.', 'Biowaste, food waste, and other natural biodegradable waste account for one-third of French household waste. Limited in 2016 to the largest economic players, the obligation to collect and recycle biowaste will be extended in 2025 to everyone, even the smallest players. With the desire to develop alternative energy sources, the issue of methanization in urban areas is gaining momentum, as composting alone cannot meet urban demand. But the subject remains complex: beyond the management of collection routes, bio-waste is 80% water, which makes transporting it over long distances impractical. This has led to the development of micro-methanization units, often containerized, which can be deployed locally to cover an area as close as possible to collection circuits. An experiment in micro-methanization of urban organic waste has been launched at the CFPH in Écully as part of Decisive, a European project coordinated by Irstea.', 'DDOI',
  'Ecully', 'Ecully', 45.7754498, 4.7785644,
  'images/IMG_3797.jpeg', '', 'https://learnandconnect.pollutec.com/la-micro-methanisation-liberer-le-potentiel-des-petites-exploitations/', '2026-03-03', 'published', 1, '2026-03-03 08:31:45', '2026-03-03 08:31:45'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772526705371', 'biogaz');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772526803429', 'NYC COOLROOF', 'NYC COOLROOF', '2009',
  'En 2004 des chercheurs du Lawrence Berkeley National Laboratory ont réfléchi à une solution simple, peu onéreuse et qui peut rapporter gros: blanchir les toits. L''équipe d''universitaires californiens a estimé l''économie que génère le remplacement des couleurs sombres des toitures de onze agglomérations américaines par des teintes claires sur les besoins en climatisation. A l''échelle du pays, cela aboutit à une économie de 750 millions de dollars chaque année\n\nDepuis 2009, les services municipaux new-yorkais exigent, pour accorder un permis de construire, que le facteur de réflectivité du toit, c''est-à-dire la fraction de l''énergie solaire réfléchie par la toiture, soit supérieur à 0,75 (à titre de comparaison, une membrane bitumineuse classique présente une réflectivité allant de 0,2 pour les couleurs sombres à 0,5 pour les plus claires). Dans ces bâtiments, la température est abaissée de 30% et la durée de vie des climatiseurs est augmentée.', 'In 2004, researchers at Lawrence Berkeley National Laboratory came up with a simple, inexpensive solution that could yield big returns: painting roofs white. The team of Californian academics estimated the savings that could be made on air conditioning costs by replacing the dark colors of roofs in eleven American cities with lighter shades. On a national scale, this would result in savings of $750 million each year. Since 2009, New York City municipal services have required that, in order to grant a building permit, the reflectivity factor of the roof, i.e., the fraction of solar energy reflected by the roof, must be greater than 0.75 (for comparison, a conventional bituminous membrane has a reflectivity ranging from 0.2 for dark colors to 0.5 for lighter colors). In these buildings, the temperature is lowered by 30% and the life of air conditioners is increased.', 'Pierre-Antoine Gombeaud',
  'Lawrence Berkeley National Laboratory', 'Lawrence Berkeley National Laboratory', 37.8769588, -122.2456303,
  'images/IMG_3798.jpeg', '', '', '2026-03-03', 'published', 1, '2026-03-03 08:33:23', '2026-03-03 08:33:23'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772526803429', 'h2o');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772526803429', 'rafraichir');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772526898504', 'PL@NTNET POUR IDENTIFIER LES PLANTES ', 'PL@NTNET TO IDENTIFY PLANTS ', '2009',
  'Lancé en 2009 par un consortium de chercheurs français, Pl@ntNet est un projet de sciences participatives visant à identifier les plantes à partir de photographies, en utilisant l’apprentissage automatique.\n\nDisponible depuis 2013 sous forme d’application mobile, Pl@ntNet permet aux utilisateurs de photographier une plante et d’obtenir une identification probable, tout en contribuant à une base de données collaborative.\n\nCette plateforme, qui a été téléchargée plus de 10 millions de fois dans plus de 180 pays, est utilisée par des amateurs et des professionnels pour l’identification des plantes, la recherche en biodiversité et l’éducation.\n\nEn 2020, les données de Pl@ntNet ont été intégrées au Global Biodiversity Information Facility (GBIF), renforçant son rôle dans la conservation de la biodiversité. ', 'Launched in 2009 by a consortium of French researchers, Pl@ntNet is a participatory science project that aims to identify plants from photographs using machine learning. Available since 2013 as a mobile app, Pl@ntNet allows users to photograph a plant and obtain a probable identification, while contributing to a collaborative database.\n\nThis platform, which has been downloaded more than 10 million times in over 180 countries, is used by amateurs and professionals for plant identification, biodiversity research, and education. In 2020, Pl@ntNet data was integrated into the Global Biodiversity Information Facility (GBIF), strengthening its role in biodiversity conservation. ', 'Simon Bouchaudy',
  'France', 'France', 46.603354, 1.8883335,
  'images/IMG_3799.jpeg', '', 'https://plantnet.org/comment-pourquoi/', '2026-03-03', 'published', 1, '2026-03-03 08:34:58', '2026-03-03 08:34:58'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772526898504', 'agriculture');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772526973246', 'L‘ ATELIER PAYSAN', 'THE FARMERS'' WORKSHOP', '2010',
  'L’Atelier Paysan est une coopérative française qui mène des activités de recherche et développement en co-conception d’outils agricoles, spécifiquement pour l’agriculture biologique et paysanne. L’organisation documente et diffuse en accès libre des plans de machines agricoles conçues avec et pour les agriculteurs. Ces outils sont pensés pour être construits directement par les utilisateurs dans le cadre de formations à l’autoconstruction. La démarche s’appuie sur des enquêtes de terrain, des prototypes testés collectivement, et une plateforme collaborative de documentation technique. Le catalogue comprend des équipements pour le travail du sol, le semis, la transformation ou encore le maraîchage. Les plans sont publiés sous licence libre.', 'L’Atelier Paysan is a French cooperative that conducts research and development activities in the co-design of agricultural tools, specifically for organic and small-scale farming. The organization documents and disseminates freely accessible plans for agricultural machinery designed with and for farmers. These tools are designed to be built directly by users as part of self-build training courses. The approach is based on field surveys, collectively tested prototypes, and a collaborative technical documentation platform. The catalog includes equipment for soil cultivation, sowing, processing, and market gardening. The plans are published under a free license.', 'Raphaël Luciani-Galais',
  'France', 'French', 46.603354, 1.8883335,
  'images/IMG_3800.jpeg', '', 'https://www.latelierpaysan.org/Outils-et-plans', '2026-03-03', 'published', 1, '2026-03-03 08:36:13', '2026-03-03 08:36:13'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772526973246', 'agriculture');

