INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772527144666', 'BICITRACTOR', 'BICYCLETRACTOR', '2010',
  'Ce bicitrator est l’outil idéal pour les exploitations maraîchères de petites et moyennes tailles. En effet, il n''existe pas de tracteur adapté aux exploitations maraîchères de petites et moyennes tailles désireuses de produire une agriculture durable et non-polluante. De plus, les petites exploitations agricoles doivent s''endetter pour acheter un tracteur conventionnel.\n\nC''est pourquoi le Bicitractor est l''outil le mieux adapté face à ces problèmes. Il s''agit d''un véhicule efficace, open source, non-polluant et peu coûteux à fabriquer soi-même.', 'This bicitractor is the ideal tool for small and medium-sized market gardens. There are no tractors suitable for small and medium-sized market gardens that want to produce sustainable, non-polluting agriculture. What''s more, small farms have to go into debt to buy a conventional tractor.\n\nThis is why the Bicitractor is the best tool for addressing these issues. It is an efficient, open-source, non-polluting vehicle that is inexpensive to build yourself.', 'Atelier 21',
  '', '', NULL, NULL,
  'images/IMG_3803.jpeg', '', 'https://www.latelierpaysan.org/Aggrozouk-bicitractor', '2026-03-03', 'published', 1, '2026-03-03 08:39:04', '2026-03-03 08:39:04'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772527144666', 'agriculture');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772527291085', 'LES SACS POTAGES', 'SOUP BAGS', '2012',
  'Conçus pour répondre aux situations de forte insécurité alimentaire en contexte urbain ou post-catastrophe, les sacs potagers sont des contenants textiles remplis de terre et de compost, permettant de cultiver des légumes en très faible surface. Utilisables sur un sol impropre ou inexistant, empilables et accessibles, ils permettent à des familles déplacées, réfugiées ou marginalisées de produire de quoi diversifier leur alimentation. Ces dispositifs sont particulièrement adaptés aux femmes, souvent premières responsables de l’alimentation domestique. Le modèle repose sur des matériaux simples : sacs de jute, déchets organiques, pierres pour le drainage, et semences locales. Testés et adaptés dans plusieurs pays (Burundi, Haïti, RDC…), les sacs potagers combinent faible coût, autonomie, résilience alimentaire et valorisation des déchets. Une micro-agriculture de survie, mais aussi de dignité.', 'Designed to address situations of severe food insecurity in urban or post-disaster contexts, vegetable bags are fabric containers filled with soil and compost, allowing vegetables to be grown in very small spaces. They can be used on unsuitable or non-existent soil, are stackable and accessible, and enable displaced, refugee, or marginalized families to produce enough food to diversify their diet. These devices are particularly suitable for women, who are often primarily responsible for feeding their families. The model is based on simple materials: jute bags, organic waste, stones for drainage, and local seeds. Tested and adapted in several countries (Burundi, Haiti, DRC, etc.), vegetable bags combine low cost, autonomy, food resilience, and waste recovery. They represent a form of micro-agriculture that promotes not only survival, but also dignity.', 'Raphael Luciani-Galais ',
  'Burundi', 'Burundi', -3.426449, 29.9324519,
  'images/IMG_3804.jpeg', '', 'https://defishumanitaires.com/wp-content/uploads/2018/01/SI-2016-Manuel-sacs-potagers.pdf', '2026-03-03', 'published', 1, '2026-03-03 08:41:31', '2026-03-03 08:41:31'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772527291085', 'agriculture');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772527414953', 'LAVERIE COMMUNAUTAIRE D’IZILF', 'IZILF COMMUNITY LAUNDROMAT', '2012',
  'Ce projet pilote est né de la prise de conscience environnementale et de la volonté de la population locale, en particulier les femmes, de s’impliquer davantage dans la vie économique du ksar d’Izilf.\n\nEn effet, la pollution des sols par les détergents des lessives au niveau des séguias (canaux d’irrigation) est un défi environnemental commun à toutes les oasis. La laverie communautaire est un modèle de projet de développement durable intégré à travers ses composantes : installation de 2 panneaux solaires permettant le chauffage de l’eau et du parc de 10 machines à laver d’une part, mise en place d’un système d’épuration des eaux grises à travers 5 bassins pour irriguer une ceinture verte de protection contre l’ensablement et l’avancée du désert d’autre part.', 'This pilot project was born out of environmental awareness and the desire of the local population, particularly women, to become more involved in the economic life of the ksar of Izilf.\n\nSoil pollution from laundry detergents in the seguias (irrigation canals) is an environmental challenge common to all oases. The community laundry is a model of integrated sustainable development through its components: installation of two solar panels to heat water and a fleet of ten washing machines on the one hand, and the implementation of a grey water purification system using five basins to irrigate a green belt that protects against sand encroachment and desertification.', 'Kadi Ayyad',
  'Maroc', 'Morocco', 28.3347722, -10.3713379,
  'images/IMG_3805.jpeg', '', 'http://www.oasistafilalet.ma/main.php?id=43&cont=430', '2026-03-03', 'published', 1, '2026-03-03 08:43:34', '2026-03-03 08:43:34'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772527414953', 'h2o');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772527675100', 'VERGERS URBAINS', 'URBAN ORCHARDS', '2013',
  'Fondée en 2013 à Paris, l’association Vergers Urbains œuvre à rendre la ville comestible en impliquant les habitants dans la végétalisation de l’espace public. Elle transforme trottoirs, friches, pieds d’immeubles ou toits en vergers et potagers partagés.\n\nNée dans le quartier de la Chapelle, l’association a depuis mené plus de 70 projets à travers la capitale, favorisant la biodiversité, le lien social et l’autonomie alimentaire. Elle propose également des formations, des chantiers participatifs et des animations pour sensibiliser à l’agriculture urbaine.\n\nLauréate de plusieurs appels à projets, Vergers Urbains est aujourd’hui un acteur clé du mouvement pour une ville plus verte, inclusive et résiliente.\n', 'Founded in Paris in 2013, the Vergers Urbains association works to make the city edible by involving residents in the greening of public spaces. It transforms sidewalks, vacant lots, building bases, and rooftops into shared orchards and vegetable gardens.\n\nBorn in the Chapelle neighborhood, the association has since carried out more than 70 projects across the capital, promoting biodiversity, social ties, and food autonomy. It also offers training, participatory projects, and activities to raise awareness about urban agriculture.\n\nWinner of several calls for projects, Vergers Urbains is now a key player in the movement for a greener, more inclusive, and more resilient city. ', 'Cedric Carles',
  'Paris', 'Paris', 48.8534951, 2.3483915,
  'images/IMG_3806.webp', '', 'https://vergersurbains.org/', '2026-03-03', 'published', 1, '2026-03-03 08:47:55', '2026-03-03 08:47:55'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772527675100', 'agriculture');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772527796455', 'FALLING FRUIT', 'FALLING FRUIT', '2013',
  'Falling Fruit est une carte collaborative mondiale recensant plus de 1,6 million de sources alimentaires gratuites : arbres fruitiers, plantes comestibles, champignons, puits d’eau, voire conteneurs à déchets alimentaires. Lancée en 2013 par deux passionnés de glanage, Caleb Phillips et Ethan Welty, cette plateforme open source vise à reconnecter les citadins à leur environnement comestible en valorisant les ressources souvent ignorées de l’espace urbain. \n\nAccessible en ligne ou via application mobile, Falling Fruit permet à chacun de localiser, documenter et partager des lieux de glanage dans plus de 70 pays. Les données proviennent à la fois de contributions citoyennes et de bases institutionnelles, comme les inventaires d’arbres municipaux. En France, des milliers de points sont déjà répertoriés, notamment à Paris. \n\nAu-delà de la cueillette gratuite, le projet s’inscrit dans une démarche anti-gaspillage, éducative et écologique, en favorisant une alimentation locale et résiliente. Falling Fruit est ainsi devenu un outil emblématique du glanage urbain moderne.', 'Falling Fruit is a collaborative global map listing more than 1.6 million free food sources: fruit trees, edible plants, mushrooms, water wells, and even food waste containers. Launched in 2013 by two gleaning enthusiasts, Caleb Phillips and Ethan Welty, this open-source platform aims to reconnect city dwellers with their edible environment by promoting the often overlooked resources of urban spaces. \n\nAccessible online or via a mobile app, Falling Fruit allows anyone to locate, document, and share foraging spots in more than 70 countries. The data comes from both citizen contributions and institutional databases, such as municipal tree inventories. In France, thousands of locations have already been listed, particularly in Paris. \n\nBeyond free foraging, the project is part of an anti-waste, educational, and ecological approach, promoting local and resilient food systems. Falling Fruit has thus become an iconic tool for modern urban foraging.', 'Cedric Carles',
  'France', 'France', 46.603354, 1.8883335,
  'images/IMG_3807.jpeg', '', 'https://fallingfruit.org/', '2026-03-03', 'published', 1, '2026-03-03 08:49:56', '2026-03-03 08:49:56'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772527796455', 'agriculture');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772527857016', 'UN VERGER DANS MON ÉCOLE', 'AN ORCHARD IN MY SCHOOL', '2014',
  'Entre 2014 et 2019, Paris a planté 2 300 arbres fruitiers, dont 1 700 dans les écoles, dans le cadre de l’opération « Un verger dans mon école ». Ce programme vise à reconnecter les enfants à la nature et à l’alimentation en leur permettant de cultiver et de récolter des fruits dans des vergers pédagogiques. Ces espaces, entretenus écologiquement, sont aussi des outils d’apprentissage sur la biodiversité, les saisons et le climat. \n\nAu total, 1170 arbres fruitiers ont été plantés dans 151 écoles parisiennes, offrant ainsi aux élèves l’opportunité de découvrir la culture des fruits en milieu urbain. \n\nAu-delà des écoles, des arbres fruitiers ont été plantés dans les rues, jardins et autres espaces publics, contribuant à la végétalisation de la ville et à la promotion de l’agriculture urbaine. \n\nCes initiatives s’inscrivent dans une stratégie plus large de la Ville de Paris pour favoriser une alimentation durable et renforcer la place de la nature en ville.', 'Between 2014 and 2019, Paris planted 2,300 fruit trees, including 1,700 in schools, as part of the "An orchard in my school" initiative. This program aims to reconnect children with nature and food by allowing them to grow and harvest fruit in educational orchards. These ecologically maintained spaces are also tools for learning about biodiversity, the seasons, and the climate. A total of 1,170 fruit trees have been planted in 151 Parisian schools, giving students the opportunity to discover fruit growing in an urban environment. \n\nBeyond schools, fruit trees have been planted in streets, gardens, and other public spaces, contributing to the greening of the city and the promotion of urban agriculture. These initiatives are part of a broader strategy by the City of Paris to promote sustainable food and strengthen the place of nature in the city.', 'Cedric Carles',
  'Paris', 'Paris', 48.8534951, 2.3483915,
  'images/IMG_3808.jpeg', '', '', '2026-03-03', 'published', 1, '2026-03-03 08:50:57', '2026-03-03 08:50:57'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772527857016', 'agriculture');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772527942376', 'LA TOUR WARKAWATER', 'LA TOUR WARKAWATER', '2015',
  'Le designer italien Arturo Vittori a conçu le WarkaWater pour faciliter l’accès à l’eau potable dans les régions arides. Cette tour capte l’humidité de l’air pour fournir jusqu’à cent litres d’eau par jour.\n\nCaractéristiques :\nHauteur : 9 mètres\nFonctionnement : Filet en nylon ou polypropylène qui condense la vapeur d’eau atmosphérique.\nRéservoir : Capacité de 100 litres d’eau potable par jour.\nStructure : Tressée avec des matériaux naturels locaux, ne pesant que 60 kg.\n\nCoût :\nUne tour coûte environ 550 dollars et fournit de l’eau gratuitement.\n\nImpact :\nMême avec un taux d’humidité de 20 %, cette solution peut aider face à la diminution des ressources en eau potable', 'Italian designer Arturo Vittori designed WarkaWater to facilitate access to drinking water in arid regions. This tower captures moisture from the air to provide up to 100 liters of water per day. Features: Height: 9 meters Operation: Nylon or polypropylene net that condenses atmospheric water vapor.\nReservoir: Capacity of 100 liters of drinking water per day. Structure: Woven from local natural materials, weighing only 60 kg. Cost: One tower costs around $550 and provides water free of charge. Impact: Even with a humidity level of 20%, this solution can help address the decline in drinking water resources.', 'Pierre Antoine P. Gombeaud',
  'Italie', 'Italy', 42.6384261, 12.674297,
  'images/IMG_3809.jpeg', '', '', '2026-03-03', 'published', 1, '2026-03-03 08:52:22', '2026-03-03 08:52:22'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772527942376', 'h2o');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772528117894', 'PRODUCTION D’EAU ATMOSPHÉRIQUE SKYSOURCE', 'SKYSOURCE ATMOSPHERIC WATER PRODUCTION', '2015',
  'Alimenté par des déchets végétaux, ce conteneur innovant transforme l’humidité de l’air en eau potable grâce à un procédé de condensation intégré. La biomasse issue des déchets végétaux est brûlée pour produire l’énergie nécessaire au fonctionnement du système d’extraction et d’aspiration d’air. Ce système, en aspirant l’air ambiant, le refroidit et provoque la condensation de la vapeur d’eau, laquelle est ensuite filtrée pour obtenir une eau potable de qualité. Ainsi, en une seule journée, ce dispositif est capable de générer jusqu’à 2 000 litres d’eau, offrant une solution prometteuse pour les environnements où l’eau est une ressource rare.\nLe principe repose sur des phénomènes physiques fondamentaux – la combustion de la biomasse et la condensation – appliqués de manière ingénieuse pour produire de l’eau potable. En valorisant des déchets végétaux, le système transforme une ressource souvent négligée en énergie utile, éliminant le besoin de sources d’énergie externes ou coûteuses. Ce dispositif peut être déployé dans des zones dépourvues de ressources en eau traditionnelles, offrant ainsi une solution low-tech et durable pour répondre aux besoins essentiels de populations isolées ou dans des situations d’urgence.', 'Powered by plant waste, this innovative container transforms moisture in the air into drinking water using an integrated condensation process. Biomass from plant waste is burned to produce the energy needed to operate the air extraction and suction system. This system cools the ambient air as it sucks it in, causing the water vapor to condense, which is then filtered to obtain high-quality drinking water. In a single day, this device can generate up to 2,000 liters of water, offering a promising solution for environments where water is a scarce resource.\nThe principle is based on fundamental physical phenomena—biomass combustion and condensation—ingeniously applied to produce drinking water. By utilizing plant waste, the system transforms an often-neglected resource into useful energy, eliminating the need for external or costly energy sources. This device can be deployed in areas lacking traditional water resources, offering a low-tech and sustainable solution to meet the essential needs of isolated populations or those in emergency situations.', 'Thomas Ortiz',
  '', '', NULL, NULL,
  'images/IMG_3810.jpeg', '', '', '2026-03-03', 'published', 1, '2026-03-03 08:55:17', '2026-03-03 08:55:17'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772528117894', 'h2o');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772528242000', 'LE BASSIN FILTRANT ET LES CHATEPLEURS', 'THE FILTERING BASIN AND THE CHATEPLEURS', '2016',
  'Dès le milieu du XIXème siècle, la Ville de Paris se dote d’un réseau d’eau non potable destiné à l’arrosage des espaces verts et au nettoyage de la voierie. Menacé un temps d’abandon car vétuste et sous-utilisé, ce réseau nécessite aujourd’hui d’imaginer de nouveaux contextes d’usage pour cette eau, extraite de la Seine et du canal de l’Ourcq. Le studio de design Idaé a réalisé le projet Topique-eau qui donne forme à trois usages de cette eau non potable.\n\nCe dispositif a été conçu pour utiliser l’eau non potable dans les jardins collectifs. Il filtre l’eau grâce à un procédé de phytorestoration (filtration par les plantes) développé par l’entreprise Phytorestore. Une fois filtrée, l’eau peut être acheminée jusqu’aux plantes grâce à des chantepleures. La chantepleure est l’ancêtre de l’arrosoir. Elle a la particularité de se remplir par le dessous, une manière d’esquisser une gestuelle propre à l’usage de cette eau de Seine. Cet objet a été redessiné pour l’occasion et produit en petite série par rotomoulage.', 'In the mid-19th century, the City of Paris built a network of non-potable water intended for watering green spaces and cleaning roads. Threatened with abandonment at one point due to its dilapidated state and underuse, this network now requires new uses to be found for this water, which is extracted from the Seine and the Ourcq Canal. The Idaé design studio has created the Topique-eau project, which gives shape to three uses for this non-potable water. This system was designed to use non-potable water in community gardens. It filters the water using a phytorestoration process (filtration by plants) developed by the company Phytorestore. Once filtered, the water can be transported to the plants using watering cans. The watering can is the ancestor of the watering pot. It has the distinctive feature of being filled from below, a way of sketching out a gesture specific to the use of this water from the Seine. This object has been redesigned for the occasion and produced in small series by rotational molding.', 'Simon Bouchaudy',
  'Paris', 'Paris', NULL, NULL,
  'images/IMG_3811.jpeg', '', 'https://pablobras.fr/09_Kit-d-arrosage', '2026-03-03', 'published', 1, '2026-03-03 08:57:22', '2026-03-03 08:57:22'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772528242000', 'agriculture');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772528242000', 'h2o');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772528316329', 'LA DÉMARCHE PARISCULTEURS', 'THE PARISCULTEURS APPROACH', '2016',
  'Lancé en 2016, le programme Parisculteurs transforme les toits, murs et friches de la capitale en espaces de production agricole. Chaque saison, des appels à projets permettent à des collectifs, associations ou entreprises d’investir des sites mis à disposition par la Ville de Paris. Ces projets favorisent une alimentation locale, créent des emplois, renforcent la biodiversité et reconnectent les citadins à la nature.\n\nÀ ce jour, plus de 70 sites ont été attribués, incluant des fermes sur les toits, des jardins partagés, des cultures hydroponiques ou des microbrasseries. Des lieux emblématiques comme l’Opéra Bastille, le réservoir de Charonne ou le centre commercial Beaugrenelle accueillent désormais des cultures comestibles. Parisculteurs s’inscrit dans une stratégie plus large de végétalisation et de transition écologique, visant à faire de Paris une ville plus résiliente et nourricière.', 'Launched in 2016, the Parisculteurs program transforms the capital''s rooftops, walls, and vacant lots into agricultural production spaces. Each season, calls for projects allow collectives, associations, and companies to invest in sites made available by the City of Paris. These projects promote local food, create jobs, enhance biodiversity, and reconnect city dwellers with nature.\n\nTo date, more than 70 sites have been allocated, including rooftop farms, shared gardens, hydroponic crops, and microbreweries. Iconic locations such as the Opéra Bastille, the Charonne reservoir, and the Beaugrenelle shopping center now host edible crops. Parisculteurs is part of a broader strategy of greening and ecological transition, aimed at making Paris a more resilient and nourishing city.', 'Cedric Carles',
  'Paris', 'Paris', 48.8534951, 2.3483915,
  'images/IMG_3812.jpeg', '', 'https://www.parisculteurs.paris/', '2026-03-03', 'published', 1, '2026-03-03 08:58:36', '2026-03-03 08:58:36'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772528316329', 'agriculture');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772528474851', 'LANCEMENT DE REGENBOX PAR L’ATELIER 21', 'LAUNCH OF REGENBOX BY ATELIER 21', '2016',
  'RegenBox est le premier régénérateur open source, capable de régénérer les alcalines dites à usages uniques ou encore “non rechargeables”. La technologie est connue et a été exhumée par un paléo-chercheur qui a prototypé cet appareil en s''inspirant du brevet de Karl Kordesch datant de 1980, brevet passé dans le domaine public. La première phase du projet consiste à créer une communauté de bêta-testeurs afin de comparer les performances des différentes piles disponibles sur le marché. Dans le même temps, le but est de démontrer la régénérabilité et d''identifier les piles possédant la meilleure capacité de régénération, et de pouvoir en faire profiter la communauté. En 2025, la Regenbox V2 grand publique et industrialisée est lancée ! ', 'RegenBox is the first open-source regenerator capable of regenerating single-use or "non-rechargeable" alkaline batteries. The technology is well known and was unearthed by a paleo-researcher who prototyped this device based on Karl Kordesch''s 1980 patent, which is now in the public domain. The first phase of the project consists of creating a community of beta testers to compare the performance of different batteries available on the market. At the same time, the goal is to demonstrate regenerability and identify the batteries with the best regeneration capacity, and to share this information with the community. In 2025, the Regenbox V2 will be launched for the general public and industrial use! ', 'Cedric Carles',
  'France', 'France', 46.603354, 1.8883335,
  'images/IMG_3813.jpeg', '', 'Regenbox.org', '2026-03-03', 'published', 1, '2026-03-03 09:01:14', '2026-03-03 09:01:14'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772528474851', 'electricite');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772528474851', 'conservation-de-lenergie');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772529193401', 'LE BEEHIVE - ANT STUDIO', 'LE BEEHIVE - ANT STUDIO', '2017',
  'L’entreprise de design Ant Studio, située à New Delhi, a eu l’idée de créer « The Beehive » (en français, la ruche) une structure en forme d’alvéoles capable de rafraîchir l’air ambiant sans nécessiter d’énergie. Le système est à base d’argile et d’eau.\n\nCette « ruche » est composée de simples tubes en terre cuite, un matériau naturel. Ceux-ci sont installés sur une structure métallique circulaire qui est ensuite déposée dans un bassin qui permet de recueillir l’eau, sur le même principe qu’une fontaine en circuit fermé.\n\nL’eau versée manuellement au sommet de la structure ruisselle sur les tubes d’argile et les imbibe de son humidité. L’air qui pénètre dans les tubes est alors rafraîchi, tout simplement.', 'The design company Ant Studio, based in New Delhi, came up with the idea of creating "The Beehive," a honeycomb-shaped structure capable of cooling the ambient air without requiring energy. The system is based on clay and water.\n\nThis "beehive" is made up of simple terracotta tubes, a natural material. These are installed on a circular metal structure which is then placed in a basin that collects water, using the same principle as a closed-circuit fountain.\n\nWater poured manually onto the top of the structure trickles down the clay tubes and soaks them with moisture. The air entering the tubes is then cooled, quite simply.', 'Marcel Robert',
  'New Delhi', 'New Delhi', 28.6138954, 77.2090057,
  'images/IMG_3814.jpeg', '', '', '2026-03-03', 'published', 1, '2026-03-03 09:13:13', '2026-03-03 09:13:13'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772529193401', 'h2o');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772529193401', 'rafraichir');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772529299253', 'AEROLIANSPARIS : DES PRAIRIES EN ZONE URBAINE', 'AEROLIANSPARIS: MEADOWS IN URBAN AREAS', '2018',
  'Grand Paris Aménagement a participé à l’aménagement de la pointe sud d’AeroliansParis (ZAC Sud Charles-de-Gaulle) à Tremblay-en-France (93). Ce site de 198 hectares ambitionne d’accueillir 850 000 m² d’entreprises internationales ainsi qu’une extension majeure du parc des expositions Paris Nord Villepinte (PEX). L’objectif était de recréer un environnement écologique pluriel attirant une grande variété d’espèces animales et végétales.\n\nGPA a ainsi implanté trois milieux riches en biodiversité : prairie humide, prairie sèche et milieu boisé. L’ancien usage agricole en monoculture cède place à une biodiversité plus dense.\n\nLes aménagements visent aussi à limiter l’imperméabilisation des sols, afin de maîtriser à la source les eaux pluviales et réduire pollution et risques d’inondation.\n\nAeroliansParis se veut un projet exemplaire, avec une gestion innovante des eaux pluviales et de vastes espaces verts pensés pour oxygéner l’urbanisme dense de la ZAC.', 'Grand Paris Aménagement participated in the development of the southern tip of AeroliansParis (ZAC Sud Charles-de-Gaulle) in Tremblay-en-France (93). This 198-hectare site aims to accommodate 850,000 m² of international businesses as well as a major extension of the Paris Nord Villepinte exhibition center (PEX). The goal was to recreate a diverse ecological environment that would attract a wide variety of animal and plant species. GPA therefore created three environments rich in biodiversity: wet meadow, dry meadow, and wooded area. The former monoculture agricultural use has given way to a denser biodiversity.\n\nThe developments also aim to limit soil sealing in order to control rainwater at source and reduce pollution and flood risks. AeroliansParis is intended to be an exemplary project, with innovative rainwater management and vast green spaces designed to oxygenate the dense urban planning of the ZAC.', 'GPA',
  'Tremblay-en-France', 'Tremblay-en-France', 48.9802035, 2.5589558,
  'images/IMG_3815.jpeg', '', 'https://www.aeroliansparis-gestion.fr/', '2026-03-03', 'published', 1, '2026-03-03 09:14:59', '2026-03-03 09:14:59'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772529299253', 'agriculture');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772529526787', 'HELIO TRANSFORMER L’EAU DE MER EN EAU POTABLE', 'HELIO TRANSFORMING SEAWATER INTO DRINKING WATER', '2018',
  'Les systèmes HELIO ont été conçus pour reproduire le cycle naturel de l’eau. Comment ? Grâce au phénomène de distillation solaire !\n\nCe principe permet de traiter tout liquide contenant la molécule de H2O : eau de mer, eau de rivière, eau de pluie, lac.\n\nL''eau à traiter est acheminée par une pompe et un panneau solaire jusqu’au plateau situé au centre de la sphère.\n\nPar effet de serre, elle s’évapore et se condense au contact des parois pour former de micro gouttelettes d’eau pure. Cette eau va ensuite ruisseler le long des parois pour être récupérée en partie basse de la sphère.\n\nLes résidus solides (sel, etc.) sont évacués par une purge du plateau.\n\nL’eau produite par le système HELIO est une eau pure qui pourra être consommée directement en sortie.Un kit de reminéralisation optionnel composé d’éléments naturels (calcium, magnésium, etc.), vous permettra de produire votre propre eau minérale !', 'HELIO systems are designed to replicate the natural water cycle. How? Through solar distillation! This principle can be used to treat any liquid containing H2O molecules: seawater, river water, rainwater, lake water. The water to be treated is pumped through a solar panel to the plate located in the center of the sphere.\n\nThrough the greenhouse effect, it evaporates and condenses on contact with the walls to form micro-droplets of pure water. This water then trickles down the walls to be collected at the bottom of the sphere. Solid residues (salt, etc.) are removed by draining the tray.\n\nThe water produced by the HELIO system is pure water that can be consumed directly at the outlet. An optional remineralization kit composed of natural elements (calcium, magnesium, etc.) allows you to produce your own mineral water!', 'Simon Bouchaudy',
  '', '', NULL, NULL,
  'images/IMG_3816.jpeg', '', '', '2026-03-03', 'published', 1, '2026-03-03 09:18:46', '2026-03-03 09:18:46'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772529526787', 'sante');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772529526787', 'h2o');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772529588182', 'MARCELLE, L’URINOIR FÉMININ POUR L’ENGRAIS', 'MARCELLE, THE FEMALE URINAL FOR FERTILIZER', '2018',
  'Conçu par la designeuse Louise Raguet, Marcelle est un urinoir adapté à l''anatomie des femmes pour faire pipi sans toucher la cuvettes des toilettes et sans éclaboussures. Il permet l''économie de 6 litres d''eau par utilisation et réduit considérablement les files d''attente aux toilettes pour femmes.\n\nL’urinoir est accompagné de signalétique pour sa bonne utilisation. Une poubelle assortie est dédiée au papier toilette. Marcelle est 100% fabriqué en France, à Troyes. En acier inox peint, c’est un objet durable et facile d''entretien.\n\nL’urinoir féminin est destiné aux toilettes des lieux publics : salles de concert, centre commercial, etc mais aussi aux festivals. Il a été installé à Paris (Grands Voisins, 14ème), à Bruxelles (Tri Postal), à Trelins (Foreztival), à Puget-sur-Argens (Mas des Écaravatiers)...\n\nL’urine récoltée et ensuite valorisée sous forme d’engrais. L''utilisation de l''urine en agriculture permet de limiter la pollution des cours d''eau et de réduire la consommation d''engrais chimiques dans les champs.', 'Designed by Louise Raguet, Marcelle is a urinal adapted to the female anatomy, allowing women to urinate without touching the toilet bowl and without splashing. It saves 6 liters of water per use and significantly reduces queues at women''s toilets.\n\nThe urinal comes with signage explaining how to use it properly. A matching trash can is provided for toilet paper. Marcelle is 100% made in France, in Troyes. Made of painted stainless steel, it is durable and easy to maintain.\n\nThe female urinal is intended for use in public toilets: concert halls, shopping centers, etc., but also at festivals. It has been installed in Paris (Grands Voisins, 14th arrondissement), Brussels (Tri Postal), Trelins (Foreztival), Puget-sur-Argens (Mas des Écaravatiers), and elsewhere.\n\nThe urine is collected and then recycled as fertilizer. The use of urine in agriculture helps to limit water pollution and reduce the consumption of chemical fertilizers in fields.', 'Simon Bouchaudy',
  'Paris', 'Paris', 48.8534951, 2.3483915,
  'images/IMG_3817.jpeg', '', 'https://urinoirmarcelle.fr/', '2026-03-03', 'published', 1, '2026-03-03 09:19:48', '2026-03-03 09:19:48'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772529588182', 'agriculture');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772529588182', 'h2o');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772529680305', 'LE SEMOIR « YOOKOUTEF »', 'THE "YOOKOUTEF" SEED DRILL', '2019',
  'L’épandage est un frein à l’adoption de l’inoculation au Sénégal. Cette opération, souvent laborieuse, manquait jusqu’alors d’un outil adapté pour garantir une répartition homogène et efficace du biofertilisant au moment du semis. Pour y remédier, chercheurs, artisans et producteurs ont co-développé le « Yookoutef », un semoir innovant conçu dans une démarche de recherche participative. Cette machine, intégrant un système de co-localisation des semences et de l’inoculum, permet de déposer simultanément les graines et les micro-organismes symbiotiques au bon endroit dans le sol. Brevetée auprès de l’Organisation Africaine de la Propriété Intellectuelle (OAPI), elle allège le travail des paysans, réduit le temps de semis et augmente l’efficacité agronomique du traitement. Fabriquée localement par l’Association pour la Promotion des Artisans et Ouvriers (APRAO), elle répond aux contraintes techniques et économiques du milieu rural. Déployée en phase expérimentale sur plusieurs exploitations, elle a déjà suscité l’intérêt de nombreuses coopératives agricoles, qui y voient un levier de modernisation accessible et adapté à leurs pratiques.', 'Spreading is a barrier to the adoption of inoculation in Senegal. This often laborious operation has until now lacked a suitable tool to ensure the even and effective distribution of biofertilizer at the time of sowing. To remedy this, researchers, artisans, and producers have co-developed the "Yookoutef," an innovative seeder designed through a participatory research approach. This machine, which integrates a system for co-locating seeds and inoculum, allows seeds and symbiotic microorganisms to be deposited simultaneously in the right place in the soil. Patented by the African Intellectual Property Organization (OAPI), it lightens the workload for farmers, reduces sowing time, and increases the agronomic efficiency of the treatment. Manufactured locally by the Association for the Promotion of Artisans and Workers (APRAO), it meets the technical and economic constraints of rural areas. Deployed in an experimental phase on several farms, it has already attracted the interest of numerous agricultural cooperatives, which see it as an accessible lever for modernization that is adapted to their practices.', 'Raphaël Luciani-Galais',
  'Sénégal', 'Senegal', 14.4750607, -14.4529612,
  'images/IMG_3818.jpeg', '', 'https://theconversation.com/la-recherche-participative-au-senegal-une-bonne-recette-pour-booster-lagriculture-124828', '2026-03-03', 'published', 1, '2026-03-03 09:21:20', '2026-03-03 09:21:20'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772529680305', 'agriculture');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772529735654', 'CULTURE PAR HYDROPONIE ET DÉSALINISATION', 'HYDROPONIC CULTIVATION AND DESALINATION', '2019',
  'Dans le désert d’Atacama, l’un des milieux les plus arides de la planète, ce projet novateur associe la désalinisation de l’eau de mer à la technique de l’hydroponie. La désalinisation permet de transformer l’eau de mer en eau douce apte à l’irrigation, tandis que l’hydroponie offre un système de culture sans sol, dans lequel les plantes reçoivent directement les nutriments nécessaires via une solution aqueuse. Grâce à cette synergie, les agriculteurs parviennent à produire plusieurs tonnes de légumes chaque mois, malgré des conditions climatiques extrêmement contraignantes.\nLa transformation de l’eau de mer, une ressource quasi-illimitée dans ce contexte, en eau douce permet une utilisation judicieuse de l’eau dans un environnement où celle-ci est rare.\n\nLe système hydroponique, tout en étant un procédé moderne, se caractérise par sa simplicité d’installation et sa capacité à être adapté à divers environnements, y compris les zones désertiques.\nEn permettant une production alimentaire dans un milieu aride, ce projet réduit la pression sur les terres arables et offre une solution résiliente face aux enjeux climatiques actuels, dans une logique de gestion efficiente des ressources.', 'In the Atacama Desert, one of the most arid environments on the planet, this innovative project combines seawater desalination with hydroponics. Desalination transforms seawater into fresh water suitable for irrigation, while hydroponics provides a soil-free growing system in which plants receive the nutrients they need directly via an aqueous solution. Thanks to this synergy, farmers are able to produce several tons of vegetables each month, despite extremely challenging climatic conditions.\nThe transformation of seawater, a virtually unlimited resource in this context, into fresh water allows for the judicious use of water in an environment where it is scarce.\n\nThe hydroponic system, while a modern process, is characterized by its simplicity of installation and its ability to be adapted to various environments, including desert areas. By enabling food production in an arid environment, this project reduces pressure on arable land and offers a resilient solution to current climate challenges, in line with efficient resource management.', 'Lola Baron',
  '', '', NULL, NULL,
  'images/IMG_3819.jpeg', '', 'https://www.sciencesetavenir.fr/nature-environnement/chili-faire-pousser-des-legumes-dans-le-desert-le-plus-aride-du-monde_132337', '2026-03-03', 'published', 1, '2026-03-03 09:22:15', '2026-03-03 09:22:15'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772529735654', 'agriculture');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772529735654', 'h2o');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772529808121', 'RÉSERVOIR DE FAÇADE REËSTOK', 'REËSTOK FACADE TANK', '2019',
  'Le réservoir de façade Reënstok, conçu par le Studio Faltazi, est un dispositif innovant de collecte et de stockage des eaux pluviales, installé pour la première fois en juillet 2019 au 2 rue Louis Blanc, Paris 10ᵉ. \n\nRemplaçant les descentes d''eau pluviale traditionnelles, ce système se compose de modules en inox brossé superposables, permettant de collecter l''eau de pluie directement sur les façades des immeubles. L''eau ainsi récupérée est utilisée pour l''arrosage des espaces verts adjacents, tels que les jardins partagés, contribuant à une gestion durable des ressources en eau en milieu urbain. \n\nCes réservoirs jouent un rôle de régulateur en absorbant les surplus d''eau lors des orages et en différant leur utilisation pendant les périodes sèches, soutenant ainsi le Plan Parispluie. Après cette première installation, un second réservoir a été mis en place en 2020 rue Delesseux, dans le 19ᵉ arrondissement de Paris.', 'The Reënstok façade reservoir, designed by Studio Faltazi, is an innovative rainwater collection and storage device, installed for the first time in July 2019 at 2 rue Louis Blanc, Paris 10ᵉ. \n\nReplacing traditional rainwater downspouts, this system consists of stackable brushed stainless steel modules that collect rainwater directly from building facades. The water collected is used to water adjacent green spaces, such as shared gardens, contributing to sustainable water resource management in urban areas. \n\nThese reservoirs act as regulators by absorbing excess water during storms and deferring its use during dry periods, thus supporting the Parispluie Plan. Following this initial installation, a second reservoir was set up in 2020 on Rue Delesseux, in the 19th arrondissement of Paris.', 'Cedric Carles',
  'Paris', 'Paris', 48.8534951, 2.3483915,
  'images/IMG_3820.jpeg', '', '', '2026-03-03', 'published', 1, '2026-03-03 09:23:28', '2026-03-03 09:23:28'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772529808121', 'agriculture');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772529808121', 'h2o');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772529913558', 'PRODUCTION LOCALE DE BIOFERTILISANTS', 'LOCAL PRODUCTION OF BIOFERTILIZERS', '2019',
  'Face aux sols pauvres du Sénégal, une alliance entre chercheurs et agriculteurs a permis de lancer la production locale de biofertilisants à base de champignons mycorhiziens. Ces micro-organismes vivent en symbiose avec les plantes et boostent leur croissance en améliorant l’accès aux nutriments. Grâce à un dispositif de culture sur racines de maïs utilisant des coques d’arachide, les producteurs peuvent désormais multiplier eux-mêmes les inoculums. Une innovation accessible, durable, et parfaitement adaptée à l’agriculture familiale vivrière. Cette approche, testée à Darou Mousty, pose les bases d’une autonomie agricole fondée sur les ressources locales et la science partagée.', 'Faced with poor soil in Senegal, an alliance between researchers and farmers has led to the launch of local production of biofertilizers based on mycorrhizal fungi. These microorganisms live in symbiosis with plants and boost their growth by improving access to nutrients. Thanks to a corn root cultivation system using peanut shells, producers can now multiply inoculants themselves. This innovation is accessible, sustainable, and perfectly suited to family subsistence farming. Tested in Darou Mousty, this approach lays the foundations for agricultural autonomy based on local resources and shared science.', 'Raphaël Luciani-Galais',
  'Sénégal', 'Senegal', 14.4750607, -14.4529612,
  'images/IMG_3821.jpeg', '', 'https://theconversation.com/la-recherche-participative-au-senegal-une-bonne-recette-pour-booster-lagriculture-124828', '2026-03-03', 'published', 1, '2026-03-03 09:25:13', '2026-03-03 09:25:13'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772529913558', 'agriculture');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772529913558', 'h2o');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772530010947', 'HORS-CHAMP', 'OUT OF FRAME', '2019',
  'Hors-champ est un projet de diplôme en création industrielle réalisé par Paul Appert à l’ENSCI – Les Ateliers. Ce projet vise à accompagner les maraîchers souhaitant adopter des pratiques agricoles écologiques et diversifiées. Il propose une solution intégrée comprenant une application numérique personnalisée pour la formation, la planification des cultures et la gestion des parcelles, ainsi qu’un microtracteur électrique open source, économique et modulable, adapté aux contraintes spécifiques du maraîchage. L’objectif est de fournir aux agriculteurs des outils accessibles et adaptés pour faciliter la transition vers des modèles de production plus durables. ', 'Hors-champ is a degree project in industrial design carried out by Paul Appert at ENSCI – Les Ateliers. This project aims to support market gardeners who wish to adopt ecological and diversified agricultural practices. It offers an integrated solution comprising a customized digital application for training, crop planning, and plot management, as well as an open-source, economical, and modular electric microtractor adapted to the specific constraints of market gardening. The goal is to provide farmers with accessible and adapted tools to facilitate the transition to more sustainable production models. ', 'Simon Bouchaudy',
  'France', 'France', NULL, NULL,
  'images/IMG_3822.jpeg', '', 'https://www.ensci.com/galerie-des-ateliers/un-projet?tx_news_pi1%5Baction%5D=detail&tx_news_pi1%5Bcontroller%5D=News&tx_news_pi1%5Bnews%5D=28792&cHash=7a7e7d6be11fcd5e41911d40e3147620', '2026-03-03', 'published', 1, '2026-03-03 09:26:50', '2026-03-03 09:26:50'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772530010947', 'agriculture');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772530080424', 'AGRO-PHOTOVOLTAÏQUE POUR LE MARAÎCHAGE', 'AGRO-PHOTOVOLTAICS FOR VEGETABLE GROWING', '2019',
  'Le projet APV-MaGa met en œuvre une technologie doublement bénéfique : des panneaux solaires surélevés qui produisent de l’électricité tout en laissant passer suffisamment de lumière pour la culture de légumes en dessous. Testé dans des zones rurales du Ghana, ce système optimise l’usage de l’espace, en combinant production alimentaire et énergie renouvelable sur la même surface. L’ombre partielle améliore aussi la rétention d’humidité des sols, un atout crucial face au stress hydrique. Le projet s’appuie sur des partenariats locaux solides pour former des techniciens, soutenir les coopératives maraîchères et adapter la technologie aux besoins réels du terrain.', 'The APV-MaGa project implements a technology that offers two benefits: raised solar panels that generate electricity while allowing enough light to pass through for vegetables to grow underneath. Tested in rural areas of Ghana, this system optimizes space usage by combining food production and renewable energy on the same surface area. Partial shade also improves soil moisture retention, a crucial advantage in the face of water stress. The project relies on strong local partnerships to train technicians, support vegetable cooperatives, and adapt the technology to real needs on the ground.', 'Raphaël Luciani-Galais',
  'Ghana', 'Ghana', 8.0300284, -1.0800271,
  'images/IMG_3823.jpeg', '', 'https://www.ise.fraunhofer.de/en/research-projects/apv-maga.html', '2026-03-03', 'published', 1, '2026-03-03 09:28:00', '2026-03-03 09:28:00'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772530080424', 'agriculture');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772530080424', 'h2o');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772530080424', 'solaire');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772531924119', 'La gestion des eaux pluviales et le logiciel PARAPLUIE', 'Rainwater management and the PARAPLUIE software', '2019',
  'La métropole de Lyon a mis en place un logiciel pour aider les professionnels et les particuliers dans la mise en place de dispositifs de gestion des eaux pluviales. En effet, lors de fortes pluies, les réseaux d’assainissement peuvent être saturés. Le trop-plein d’eau qui n’a pas pû être traité est relâché dans les rivières ce qui occasionne de la pollution.  Le logiciel PARAPLUIE permet de choisir la solution la plus adaptée et de faciliter sa réalisation via des avant-projets ou encore des esquisses d''architecture. Une meilleure gestion des eaux pluviales est un enjeu important auquel s’attaque la métropole lyonnaise. Son objectif est de réaliser une ville plus perméable avec des travaux de désimperméabilisation, l’installation de revêtements poreux ou encore la réalisation de jardins d’eau. \n', 'The city of Lyon has developed software to help professionals and individuals implement rainwater management systems. During heavy rainfall, sewer systems can become saturated. The excess water that cannot be treated is released into rivers, causing pollution. The PARAPLUIE software allows users to choose the most suitable solution and facilitates its implementation through preliminary designs or architectural sketches. Better stormwater management is an important issue that the city of Lyon is tackling. Its goal is to create a more permeable city through de-impermeabilization works, the installation of porous surfaces, and the creation of water gardens. ', 'Atelier étudiants Paris 1',
  'Métropole de Lyon', 'Metropolitan area of Lyon', 45.7481616, 4.8556859,
  'images/logicielparapluielyon.png', 'Logiciel Parapluie, Métropole de Lyon, https://parapluie-hydro.com/grandlyon/', 'https://parapluie-hydro.com/grandlyon/', '2026-03-03', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772531924119', 'h2o');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772532016489', 'Lancement du projet du Grand Chemin', 'Launch of the Grand Chemin project', '2024',
  'Le Grand Chemin est un projet ambitieux lancé par la communauté de communes Est Ensemble, qui rassemble neuf villes de Seine-Saint-Denis. D’ici 2030, l’objectif est d''aménager une boucle de 55 km pour faciliter l’accès des mobilités douces (piétons, vélos etc.), renforcer la présence végétale et favoriser de nouveaux usages culturels, récréatifs ou sportifs. Le Grand Chemin permet également aux villes de mieux s’adapter aux enjeux du changement climatique. En effet, la végétalisation permet de créer un effet d’îlot de fraîcheur et d’augmenter le confort des habitants. La désimperméabilisation des surfaces permet également de favoriser l’infiltration de l’eau et de réduire les phénomènes de ruissellement qui peuvent causer la surcharge des réseaux de traitement des eaux. Les premiers travaux ont commencé en 2024 aux Lilas et à Montreuil. \n\n', 'Le Grand Chemin is an ambitious project launched by the Est Ensemble community of municipalities, which brings together nine towns in Seine-Saint-Denis. By 2030, the goal is to develop a 55 km loop to facilitate access for soft mobility (pedestrians, bicycles, etc.), increase green spaces, and promote new cultural, recreational, and sporting activities. Le Grand Chemin also enables towns to better adapt to the challenges of climate change. Greening creates a cooling effect and increases comfort for residents. The de-impermeabilization of surfaces also promotes water infiltration and reduces runoff, which can overload water treatment networks. The first works began in 2024 in Les Lilas and Montreuil. ', 'Atelier étudiants Paris 1',
  'Seine-Saint-Denis', 'Seine-Saint-Denis', 48.9098125, 2.4528635,
  'images/image_cartel_grand_chemin.jpg', 'Agence Ter - Vue future de l’avenue du président Robert Schuman, aux Lilas.', 'https://www.est-ensemble.fr/grand-chemin', '2026-03-03', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772532016489', 'rafraichir');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772532016489', 'h2o');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772532138229', 'Récupération d’eau pluviale dans le square des Acrobates', 'Rainwater harvesting in Acrobates Square', '2007',
  'Le square des Acrobates, espace vert de la ville de Saint-Denis, fonctionne également comme un bassin de rétention des eaux de pluie. Une dépression enherbée, située à l’est du parc, est inondée après les orages importants. Cela permet que les eaux pluviales n’encombrent pas les réseaux d’assainissement du quartier. Quelques heures après l’orage, grâce à sa topographie en pente douce, l’eau se vide. Le square retrouve alors son usage récréatif habituel. ', 'The Square des Acrobates, a green space in the city of Saint-Denis, also functions as a rainwater retention basin. A grassy depression located to the east of the park is flooded after heavy storms. This prevents rainwater from clogging the neighborhood''s sewer system. A few hours after the storm, thanks to its gently sloping topography, the water drains away. The square then returns to its usual recreational use. ', 'Anastasia Guéguen',
  'Saint-Denis', 'Saint-Denis', 48.9383732, 2.3627508,
  'images/Saint-Denis.Square_des_Acrobates.jpg', 'Square des acrobates, 19/10/18, Rc1959, Wikimedia Commons. https://commons.wikimedia.org/wiki/File:Saint-Denis.Square_des_Acrobates.jpg', 'https://www.lemoniteur.fr/article/le-square-des-acrobates-un-ilot-vert-dans-une-ville-en-mouvement.1135379', '2026-03-03', 'published', 1, '2026-03-03 10:13:00', '2026-03-03 10:13:00'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772532138229', 'h2o');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772532229005', 'L’histoire de l’eau en Seine-Saint-Denis sur le Géoportail93', 'The history of water in Seine-Saint-Denis on Géoportail93', '2025',
  'Le Géoportail 93 est une interface cartographique publiée par le département de Seine-Saint-Denis. Il permet de consulter des informations géographiques relatives au département, de les croiser ou encore, pour les informations libres d’accès, de les télécharger afin de réaliser des cartes. En 2025, le département publie un dossier sur son Géoportail intitulé “L''eau en Seine-Saint-Denis : comment composer avec le passé ?”. Cette page décrit l’histoire de l’eau en Seine-Saint-Denis depuis le XVIIIe siècle. Une carte interactive permet de localiser différents éléments historiques liés à l’eau (sources, fontaines, gare d''eau, etc.). Chaque point sur la carte est accompagné d’une notice explicative et d’images. Le site permet de comprendre le passage d’un territoire avec une présence de l’eau fortement intégrée à un espace où l’eau est devenue presque invisible du fait de l’urbanisation et de l’industrialisation. Une carte diachronique permet de se rendre compte de l’amenuisement du réseau hydrographique entre la période pré-industrielle et aujourd’hui. Cet espace permet de sensibiliser les habitants aux enjeux qui entourent l’eau dans un contexte de changement climatique et de faire changer la vision de l’eau dans la ville, conformément aux ambitions du département décrites dans leur manifeste “La Seine-Saint-Denis”, territoire d’eau.', 'Géoportail 93 is a mapping interface published by the Seine-Saint-Denis department. It allows users to view geographical information about the department, cross-reference data, and download freely accessible information to create maps. In 2025, the department published a report on its Géoportail entitled "Water in Seine-Saint-Denis: how to deal with the past?". This page describes the history of water in Seine-Saint-Denis since the 18th century. An interactive map allows users to locate various historical elements related to water (springs, fountains, water stations, etc.). Each point on the map is accompanied by an explanatory note and images. The site helps users understand the transition from a territory with a strong water presence to an area where water has become almost invisible due to urbanization and industrialization. A diachronic map shows the decline of the hydrographic network between the pre-industrial period and today. This space raises residents'' awareness of the challenges surrounding water in the context of climate change and changes the way water is viewed in the city, in line with the department''s ambitions as described in their manifesto "La Seine-Saint-Denis," territory of water.', 'Bureau Eau dans la Ville 93',
  'Seine-Saint-Denis', 'Seine-Saint-Denis', 48.9098125, 2.4528635,
  'images/Carte_de_Cassini.Ile-Saint-Denis.Maison_de_Seine.Fort_de_la_Briche.jpg', 'Carte de Cassini. https://commons.wikimedia.org/wiki/File:Carte_de_Cassini.Ile-Saint-Denis.Maison_de_Seine.Fort_de_la_Briche.jpg', 'https://geo.seinesaintdenis.fr/portal/apps/storymaps/stories/60d2d9d58e2d4742836f3f6af214400b', '2026-03-03', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772532229005', 'h2o');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772532334174', 'Création de l''exposition “les futurs de l’eau en Seine-Saint-Denis : comment composer avec le passé ?”', 'Creation of the exhibition “The Future of Water in Seine-Saint-Denis: How to Deal with the Past?”', '2024',
  'En 2024, suite à une commande de la Direction de l’Eau et de l’Assainissement de Seine-Saint-Denis, six étudiants du Master 2 Urbanisme et aménagement du territoire de l’université Paris 1 Panthéon-Sorbonne ont réalisé une étude sur le patrimoine aquatique du département. Cette dernière a donné lieu à une exposition qui retrace l’histoire des usages de l’eau depuis le XVIIIe siècle. Elle souligne les très nombreuses utilisations, particulièrement marquées au XIXe siècle, de l’eau en Seine-Saint-Denis (usages utilitaires ou encore de loisir). Le XXe siècle marque la disparition progressive de la place de l’eau dans la ville avec l’urbanisation. Composée de 12 panneaux, cette exposition propose également une projection vers 2050. Celle-ci met en lumière des idées de projets à mener pour améliorer la visibilité de l’eau pour les habitants, pour préserver la biodiversité et pour réduire les îlots de chaleur dans un contexte de changement climatique. Par exemple, les étudiants présentaient leur plan de restauration des lavoirs ou encore de création de mares. Ces idées sont inspirées du manifeste “La Seine-Saint-Denis, territoire d’eau” publié en 2024 par le département et qui fixe l’objectif d’affirmation de la place de l’eau en ville.\n', 'In 2024, following a commission from the Seine-Saint-Denis Water and Sanitation Department, six students from the Master 2 Urban Planning and Land Use program at Paris 1 Panthéon-Sorbonne University conducted a study on the department''s aquatic heritage. This study gave rise to an exhibition tracing the history of water use since the 18th century. It highlights the many uses of water in Seine-Saint-Denis, particularly in the 19th century, for both practical and recreational purposes. The 20th century saw the gradual disappearance of water from the city with urbanization. Comprising 12 panels, this exhibition also offers a projection towards 2050. It highlights ideas for projects to improve the visibility of water for residents, preserve biodiversity, and reduce heat islands in the context of climate change. For example, the students presented their plan to restore wash houses and create ponds. These ideas are inspired by the manifesto "La Seine-Saint-Denis, territoire d''eau" (Seine-Saint-Denis, land of water) published in 2024 by the department, which sets the objective of affirming the place of water in the city. ', 'Bureau Eau dans la Ville 93',
  'Seine-Saint-Denis', 'Seine-Saint-Denis', 48.9098125, 2.4528635,
  'images/paneau1expolesfutursdeleau.png', 'Panneau 1 de l''exposition “les futurs de l’eau en Seine-Saint-Denis : comment composer avec le passé ?”. Paris 1 Panthéon-Sorbonne et Département Seine-Saint-Denis. https://reseau.doc.seinesaintdenis.fr/index.php?lvl=notice_display&id=105528', 'https://reseau.doc.seinesaintdenis.fr/index.php?lvl=notice_display&id=105528', '2026-03-02', 'published', 1, '2026-03-02 14:04:28', '2026-03-02 14:04:28'
);
