INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772532502316', 'Manifeste “La Seine-Saint-Denis, territoire d’eau”', 'Manifesto “Seine-Saint-Denis, territory of water”', '2024',
  'L’eau a servi de support de développement du département Seine-Saint-Denis, mais sa place dans le paysage est aujourd’hui discrète. Avant l’urbanisation des XIXe et XXe siècles, le réseau hydrographique était dense et les nombreuses nappes rendaient les terres fertiles. Puis, l’urbanisation a causé une quasi-disparition de l’eau en ville (via le remblaiement ou le recouvrement de petites rivières urbaines par exemple). Elle n''apparaît plus aujourd’hui au cœur des préoccupations des habitants en ce qui concerne l’accès à la nature en ville. Elle peut même, parfois, être perçue négativement. Dans un contexte de changement climatique, l''eau peut être intégrée pour rafraîchir la ville, soumise à des problématiques d’îlot de chaleur urbain. Le Manifeste affirme les ambitions du département de refaire une place à l’eau dans la ville et fonde une nouvelle politique entièrement dédiée au territoire d’eau. Pour ce faire, des projets de préservation des zones humides, de création de mares et jardins d’eau ou encore des initiatives culturelles et artistiques autour de l’eau sont soutenus par le département. ', 'Water has been instrumental in the development of the Seine-Saint-Denis department, but its place in the landscape is now discreet. Before urbanization in the 19th and 20th centuries, the hydrographic network was dense and the numerous aquifers made the land fertile. Then, urbanization caused water to virtually disappear from the city (through the filling or covering of small urban rivers, for example). Today, it is no longer a major concern for residents in terms of access to nature in the city. It can even, at times, be perceived negatively. In the context of climate change, water can be integrated to cool the city, which is subject to urban heat island issues. The Manifesto affirms the department''s ambitions to restore water''s place in the city and establishes a new policy entirely dedicated to water. To this end, the department supports projects to preserve wetlands, create ponds and water gardens, and cultural and artistic initiatives related to water. ', 'Bureau Eau dans la Ville 93',
  'Seine-Saint-Denis', 'Seine-Saint-Denis', 48.9098125, 2.4528635,
  'images/image_manifeste_ssd.png', 'Manifeste "La Seine-Saint-Denis territoire d''eau", département Seine-Saint-Denis, https://reseau.doc.seinesaintdenis.fr/index.php?lvl=notice_display&id=105248', 'https://reseau.doc.seinesaintdenis.fr/index.php?lvl=notice_display&id=105248', '2026-03-02', 'published', 1, '2026-03-02 14:38:08', '2026-03-02 14:38:08'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772532502316', 'h2o');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772532502316', 'politique-publique');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772532502316', 'gouvernance-de-leau');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772532742222', 'Etude sur les sources en Seine-Saint-Denis', 'Study on water sources in Seine-Saint-Denis', '2025',
  'Il existe de nombreuses sources sur le territoire de Seine-Saint-Denis. Elles étaient autrefois très utilisées, mais, avec le développement d’autres méthodes d’alimentation en eau, les habitants s’en sont détournés. Aujourd’hui, certaines de ces sources ont été recouvertes avec l’urbanisation. Une étude pour localiser ces anciennes sources a été réalisée par le CEREMA (centre d’études et d’expertises sur les risques, l’environnement, la mobilité et l’aménagement), sur demande du département Seine-Saint-Denis. L’étude a permis d’affiner la connaissance sur les sources. L’eau des sources qui subsistent est souvent rejetée dans les systèmes d’assainissement. Sur le plateau de Romainville, leur débit peut atteindre 50 à 100 m3 par jour. Cette étude pose la question de l’utilisation de ces eaux, qui ne sont pas potables, pour le nettoyage des rues, l’arrosage des plantes ou encore la réalisation de jeux d’eau. ', 'There are numerous springs in the Seine-Saint-Denis area. They were once widely used, but with the development of other methods of water supply, residents have turned away from them. Today, some of these springs have been covered over by urbanization. A study to locate these ancient springs was carried out by CEREMA (Center for Studies and Expertise on Risks, the Environment, Mobility, and Development) at the request of the Seine-Saint-Denis department. The study provided more detailed information about the springs. The water from the remaining springs is often discharged into the sewerage system. On the Romainville plateau, their flow can reach 50 to 100 m3 per day. This study raises the question of how to use this water, which is not drinkable, for cleaning streets, watering plants or creating water features. ', 'Bureau Eau dans la Ville 93',
  'Seine-Saint-Denis', 'Seine-Saint-Denis', 48.9098125, 2.4528635,
  'images/Clichy-sous-Bois.Notre-Dame-des-Anges.Fontaine_miraculeuse.Vue_densemble.jpg', 'Fontaine miraculeuse de Notre-Dame-des-Anges à Clichy-sous-Bois, vers 1900-1910', 'https://comprendre-pour-agir.transistor.fm/episodes/3-la-seine-saint-denis-territoire-deau', '2026-03-03', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772532742222', 'h2o');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772532742222', 'imaginaire');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772538547187', 'Mise en service des lacs réservoirs du bassin versant de la Seine', 'Commissioning of reservoir lakes in the Seine watershed', '1949-1990',
  'Au cours du XXe siècle, quatre grands lacs-réservoirs ont été construits autour de la région parisienne. Ce sont les lacs de Pannecière (1949), d’Orient (1966), du Der (1974) et Amance-Temple (1990). Leur objectif est double : ils permettent de stocker le trop-plein d’eau durant les périodes les plus pluvieuses (printemps/hiver) et de réinjecter de l’eau dans les rivières durant les périodes plus sèches (été/automne). Cela permet de réduire les inondations (puisque le trop-plein d’eau est stocké) et de soutenir les activités qui dépendent de l’eau de la rivière (activité industrielles, centrales nucléaires, etc.). Aujourd’hui, ces lacs-réservoirs sont gérés par l’Établissement public territorial de bassin (EPTB) Seine-Grands lacs. \n', 'During the 20th century, four large reservoir lakes were built around the Paris region. These are the lakes of Pannecière (1949), Orient (1966), Der (1974), and Amance-Temple (1990). They serve a dual purpose: they store excess water during the rainiest periods (spring/winter) and feed water back into the rivers during drier periods (summer/fall). This reduces flooding (since excess water is stored) and supports activities that depend on river water (industrial activity, nuclear power plants, etc.). Today, these reservoir lakes are managed by the Seine-Grands Lacs Public Basin Authority (EPTB). ', 'Anastasia Guéguen',
  'France', 'France', 46.603354, 1.8883335,
  'images/Lac_Pannecire_et_barrage.jpeg', 'Lac de Pannecière, 08/08, Benchaum, Wikimedia Commons. https://commons.wikimedia.org/wiki/File:Lac_Panneci%C3%A8re_et_barrage.JPG', 'https://www.seinegrandslacs.fr/quatre-lacs-reservoirs-au-coeur-dun-bassin', '2026-03-03', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772538547187', 'h2o');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772637748144', 'ALIMENTATION URBAINE ALTERNATIVE', 'ALTERNATIVE URBAN FOOD SUPPLY', '2020',
  'Depuis 2020, le programme européen CENTRINNO explore la réhabilitation des friches industrielles pour favoriser des systèmes alimentaires urbains durables. À Paris, l’accent est mis sur des alternatives à l’agriculture mondialisée, reconnectant les citadins à leur alimentation.\n\nDeux sites pilotes illustrent cette démarche : le FabCity Hub Paris, dédié à la production locale et à la formation, et le Jardin des Traverses, ancien tronçon ferroviaire transformé en jardin comestible. Ces lieux servent de laboratoires pour expérimenter des modèles alimentaires circulaires.\n\nLe projet mobilise un réseau d’acteurs variés (associations, chercheurs, designers, citoyens) pour développer des solutions adaptées au contexte parisien. Cartographie des compétences alimentaires et formations professionnelles renforcent cette dynamique.\n\nEn s’inspirant des pratiques maraîchères historiques, CENTRINNO vise à construire un système alimentaire résilient, ancré dans le territoire et accessible à tous.', 'Since 2020, the European CENTRINNO program has been exploring the rehabilitation of brownfield sites to promote sustainable urban food systems. In Paris, the focus is on alternatives to globalized agriculture, reconnecting city dwellers with their food.\n\nTwo pilot sites illustrate this approach: FabCity Hub Paris, dedicated to local production and training, and Jardin des Traverses, a former railway line transformed into an edible garden. These sites serve as laboratories for experimenting with circular food models.\n\nThe project mobilizes a network of diverse actors (associations, researchers, designers, citizens) to develop solutions adapted to the Parisian context. Mapping of food skills and professional training reinforce this dynamic. Inspired by historical market gardening practices, CENTRINNO aims to build a resilient food system that is rooted in the territory and accessible to all.', 'Raphaël Luciani-Galais',
  'Paris', 'Paris', 48.8534951, 2.3483915,
  'images/Capturedcran2026-03-04161554.png', '', 'https://centrinno.eu/blog/how-to-gather-a-consistent-alternative-food-system-in-paris/', '2026-03-04', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772637748144', 'agriculture');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772639697187', 'ALIMENTATION URBAINE ALTERNATIVE', 'ALTERNATIVE URBAN FOOD SUPPLY', '2020',
  'Depuis 2020, le programme européen CENTRINNO explore la réhabilitation des friches industrielles pour favoriser des systèmes alimentaires urbains durables. À Paris, l’accent est mis sur des alternatives à l’agriculture mondialisée, reconnectant les citadins à leur alimentation.\n\nDeux sites pilotes illustrent cette démarche : le FabCity Hub Paris, dédié à la production locale et à la formation, et le Jardin des Traverses, ancien tronçon ferroviaire transformé en jardin comestible. Ces lieux servent de laboratoires pour expérimenter des modèles alimentaires circulaires.\n\nLe projet mobilise un réseau d’acteurs variés (associations, chercheurs, designers, citoyens) pour développer des solutions adaptées au contexte parisien. Cartographie des compétences alimentaires et formations professionnelles renforcent cette dynamique.\n\nEn s’inspirant des pratiques maraîchères historiques, CENTRINNO vise à construire un système alimentaire résilient, ancré dans le territoire et accessible à tous.', 'Since 2020, the European CENTRINNO program has been exploring the rehabilitation of brownfield sites to promote sustainable urban food systems. In Paris, the focus is on alternatives to globalized agriculture, reconnecting city dwellers with their food.\n\nTwo pilot sites illustrate this approach: FabCity Hub Paris, dedicated to local production and training, and Jardin des Traverses, a former railway line transformed into an edible garden. These sites serve as laboratories for experimenting with circular food models.\n\nThe project mobilizes a network of diverse actors (associations, researchers, designers, citizens) to develop solutions adapted to the Parisian context. Mapping of food skills and professional training reinforce this dynamic. Inspired by historical market gardening practices, CENTRINNO aims to build a resilient food system that is rooted in the territory and accessible to all.', 'Raphaël Luciani-Galais',
  'Paris', 'Paris', 48.8534951, 2.3483915,
  'images/Capturedcran2026-03-04161554.png', '', 'https://centrinno.eu/blog/how-to-gather-a-consistent-alternative-food-system-in-paris/', '2026-03-04', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772639697187', 'agriculture');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772639706260', 'VÉGÉTALISER LES PLACES DE STATIONNEMENT', 'GREENING PARKING SPACES', '2020',
  'La réduction du nombre de véhicules en ville va permettre de libérer de l’emprise foncière dans les cours des immeubles Haussmanniens. \n\nQue faire des cours d’immeubles ou des places en ville ? Pour les cours, l’une des pistes serait de les végétaliser pour lutter contre les îlots de chaleurs urbains. Et de réduire les besoins en climatisation des immeubles avec ces îlots des fraicheur.\n\nPistes : \nForêts “Miyawaki” du nom du botaniste japonais, expert en biologie végétale et professeur à l’université nationale de Yokohama. Il a élaboré et mis en pratique la méthode de reforestation “senzai shizen shokysei”, soit la “végétation potentielle naturelle”.', 'Reducing the number of vehicles in the city will free up land in the courtyards of Haussmann-style buildings. What should be done with building courtyards and city squares? One option for courtyards would be to plant vegetation to combat urban heat islands. These cool spots would also reduce the need for air conditioning in buildings.\n\nIdeas: "Miyawaki" forests, named after the Japanese botanist, plant biology expert, and professor at Yokohama National University. He developed and implemented the "senzai shizen shokysei" reforestation method, or "natural potential vegetation."', 'Raphaël Luciani-Galais',
  '', '', NULL, NULL,
  'images/Capturedcran2026-03-04162056.png', '', '', '2026-03-04', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772639706260', 'agriculture');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772639754647', 'FILTRATION DES BASSINS', 'POND FILTRATION', '2021',
  'Le Festival international des Jardins de Chaumont-sur-Loire présente chaque année une sélection de créations paysagères. L’édition 2021 accueille la création d''un jardin aquatique, conçu par un architecte paysagiste jean Philippe Poirée-Ville, dans une mare peu entretenue.  \n\nIl a créé un système simple constitué de bouées flottantes et dépolluantes posées sur l''eau. Celui-ci est composé de chambres à air recouvertes de feutre puis de graines de joncs, carex et iris... Le Ph de l’eau est similaire à celle du Mont-Blanc. Leurs racines purifient l''eau du bassin au bout de deux mois, un écosystème se réorganise sans nécessité un grand entretien.', 'Every year, the Chaumont-sur-Loire International Garden Festival presents a selection of landscape designs. The 2021 edition features a water garden designed by landscape architect Jean Philippe Poirée-Ville in a poorly maintained pond. He created a simple system consisting of floating, pollution-reducing buoys placed on the water. This system consists of inner tubes covered with felt and then seeds of rushes, sedges, and irises. The pH of the water is similar to that of Mont Blanc. Their roots purify the water in the pond after two months, and an ecosystem is reorganized without the need for extensive maintenance.', 'Sylvie Souet',
  'Chaumont-sur-Loire', 'Chaumont-sur-Loire', 47.4781489, 1.1903903,
  'images/Capturedcran2026-03-04163128.png', '', 'https://www.ise.fraunhofer.de/en/research-projects/apv-maga.html', '2026-03-04', 'published', 1, '2026-03-04 15:31:45', '2026-03-04 15:31:45'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772639754647', 'h2o');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772639812344', 'CHANTIER BIOCLIMATIQUE EN TERRE CRUE À DAKAR', 'BIOCLIMATIC RAW EARTH CONSTRUCTION SITE IN DAKAR', '2020',
  'Le chantier de l’Université Cheikh Anta Diop de Dakar (UCAD) est un projet emblématique au Sénégal et une référence en matière de construction lowtech à faible empreinte carbone, notamment par sa conception bioclimatique et le choix de la brique en terre cuite comme matériau principal. Ce projet doit donner le jour à 27 nouveaux bâtiments sur une surface de 26 000 m2, destinés au logement de plusieurs milliers d''étudiant(e)s. La qualité des espaces intérieurs et le confort thermique ont guidé la conception, réalisée par HARDEL LE BIHAN ARCHITECTES : choix raisonné des matériaux, ventilation naturelle, équilibre entre protection solaire et apport suffisant de lumière naturelle, canalisation du vent, etc. La morphologie des bâtiments révèle cette approche bioclimatique et respecte l’urbanisation actuelle (hauteur limitée).', 'The Cheikh Anta Diop University of Dakar (UCAD) construction project is a flagship project in Senegal and a benchmark in low-tech, low-carbon construction, particularly due to its bioclimatic design and the choice of terracotta bricks as the main building material. This project will result in 27 new buildings covering an area of 26,000 m², intended to house several thousand students. The quality of the interior spaces and thermal comfort guided the design, carried out by HARDEL LE BIHAN ARCHITECTES: careful choice of materials, natural ventilation, balance between sun protection and sufficient natural light, wind channeling, etc. The morphology of the buildings reflects this bioclimatic approach and respects the current urbanization (limited height).', 'Cédric Carles',
  'Dakar', 'Dakar', 14.693425, -17.447938,
  'images/Capturedcran2026-03-04162741.png', '', '', '2026-03-04', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772639812344', 'rafraichir');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772639812344', 'isolation-thermique');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772639887839', 'LE PAVILLON DES RÊVES', 'THE PAVILION OF DREAMS', '2021',
  'Les pavillons résidentiels sont inscrits dans des milieux où les forces naturelles existent. Alors pourquoi ne pas les capter et ainsi faire par exemple d’une gouttière une source d’énergie ? Pablo Bras conçoit différentes installations pour créer des micros-sources d’énergie dans l’habitat individuel et rêver un pavillon plus vertueux\n\nDans son projet de recherche sur l’optimisation énergétique à l’échelle domestique, il propose des gargouilles hydrogénératrices dans des bas de gouttière pour utiliser le flux descendant. \n\nIl dessine également un barrage installé sur le toit des pavillons qui permet de jouer sur la temporalité de la production de cette hydroélectricité en stockant sous forme de potentiel physique (eau).\n\nTous ces dispositifs sont fabriqués localement par des artisans et offrent de nouveaux potentiels dans la production d’énergie ultra localisée.\n\nIssu du projet Le Pavillon des Rêves réalisé dans le cadre de la bourse Agora pour la recherche en design 2019-2021.', 'Residential houses are built in environments where natural forces exist. So why not harness them and turn a gutter, for example, into a source of energy? Pablo Bras designs various installations to create micro-energy sources in individual homes and dreams of a more virtuous house.\n\nIn his research project on energy optimization at the domestic level, he proposes hydro-generating gargoyles at the bottom of gutters to use the downward flow. He also designs a dam installed on the roof of houses that allows the timing of hydroelectricity production to be adjusted by storing it in the form of physical potential (water).\n\nAll these devices are manufactured locally by craftsmen and offer new potential for ultra-localized energy production. From the Le Pavillon des Rêves project carried out as part of the Agora grant for design research 2019-2021.', 'Sylvie Souet',
  '', '', NULL, NULL,
  'images/Capturedcran2026-03-04163517.png', '', '', '2026-03-04', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772639887839', 'h2o');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772639898539', 'ARCHITECTURE NUDGE', 'NUDGE ARCHITECTURE', '2021',
  'Issue du croisement entre les sciences comportementales, le design et l’architecture, le nudge est une nouvelle manière de concevoir les bâtiments pour qu’ils intègrent des éléments influençant positivement les comportements des usagers. On peut citer comme exemple : \n\nDes escaliers plus larges, centraux et décorés d’oeuvre d’art. La réduction de la vitesse des ascenseurs. L’idée est d’inciter les habitants à faire du sport, ce qui contribue à l’amélioration de leurs santés. \n\nAfficher le nombre de calories dépensées lorsque l’on monte un escalier. \n\nLa pensée nudge et ses solutions low-tech sont inspirants pour coller au plus prêt des besoins des usagers du bâtiment, tenir compte de leurs aspirations les engagera dans une démarche vertueuse de respect des bâtiments. Cela réduira les frais d’entretien du bâti. ', 'A cross between behavioral science, design, and architecture, nudging is a new way of designing buildings to incorporate elements that positively influence user behavior. Examples include wider, centrally located staircases decorated with artwork and slower elevators. The idea is to encourage residents to exercise, which contributes to improving their health. Displaying the number of calories burned when climbing stairs. \n\nNudge thinking and its low-tech solutions are inspiring in that they closely match the needs of building users. Taking their aspirations into account will engage them in a virtuous approach to respecting buildings. This will reduce building maintenance costs. ', 'Adrien Chaussinand',
  '', '', NULL, NULL,
  'images/Capturedcran2026-03-04163653.png', '', '', '2026-03-04', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772639898539', 'mecanique');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772639913136', 'KIT D’ARROSAGE', 'WATERING KIT', '2021',
  'Ce kit conçu par le designer Pablo Bras permet à tout le monde d’arroser des zones à végétaliser à partir des bouches de lavage qu’il y a partout dans la ville.\n\nLe kit est constitué de deux parties : \n-une réduction à relier sur les bouches de lavage de la ville de Paris et qui débouche sur une sortie de plomberie standard\n-une clé de manœuvre permettant d’ouvrir l’eau\n\nLes deux pièces sont reliées par un joint torique serti par un manchon d’aluminium standard. Ce kit a été conçu à partir des savoir-faire et des machines observées dans les ateliers du service des eaux de la ville.\n\nPensé comme un objet compact, le kit permet de regrouper un tuyau d’arrosage qui relie l’arrivée d’eau à un arrosoir ou permet d’arroser directement une zone à végétaliser.\n\nOn y associe préférablement un raccord rapide de tuyau, mais il débouche sur un filetage standard qui permet d’ouvrir les usages.', 'This kit, designed by Pablo Bras, allows anyone to water areas to be planted using the fire hydrants that are located throughout the city. The kit consists of two parts: -a reducer that connects to Paris fire hydrants and connects to a standard plumbing outlet -a wrench for turning on the water\n\nThe two parts are connected by an O-ring secured by a standard aluminum sleeve. This kit was designed based on the expertise and machinery observed in the city''s water department workshops.\n\nDesigned as a compact object, the kit allows you to connect a garden hose that connects the water supply to a watering can or allows you to water a planting area directly. It is best to use a quick-connect hose connector, but it connects to a standard thread, which allows for a variety of uses.', 'Simon Bouchaudy',
  '', '', NULL, NULL,
  'images/Capturedcran2026-03-04164522.png', '', 'https://pablobras.fr/09_Kit-d-arrosage', '2026-03-04', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772639913136', 'h2o');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772639913136', 'agriculture');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772639944407', 'JARDIN AMBULANT - ISD ORSA', 'MOBILE GARDEN - ISD ORSA', '2021',
  'En décembre 2021, Villeneuve-Saint-Georges (Val-de-Marne) a inauguré deux jardins urbains novateurs, symboles d’une reconquête écologique et sociale de l’espace public. Situés dans les quartiers du Plateau et de la Pologne, ces espaces ont été aménagés sur d’anciens terrains en friche, transformés en lieux de production maraîchère et de convivialité. Ces projets s’inscrivent dans une démarche participative, impliquant les habitants dans la conception et la gestion des jardins, favorisant ainsi le lien social et l’appropriation des espaces verts. Au-delà de leur fonction alimentaire, ces jardins contribuent à la biodiversité urbaine, à la gestion des eaux pluviales et à la sensibilisation aux enjeux environnementaux.', 'In December 2021, Villeneuve-Saint-Georges (Val-de-Marne) inaugurated two innovative urban gardens, symbols of an ecological and social reclaiming of public space. Located in the Plateau and Pologne neighborhoods, these spaces were developed on former brownfield sites, transformed into places for vegetable production and socializing. These projects are part of a participatory approach, involving residents in the design and management of the gardens, thereby promoting social ties and ownership of green spaces. Beyond their food-producing function, these gardens contribute to urban biodiversity, stormwater management, and awareness of environmental issues.', 'GPA',
  'Villeneuve-Saint-Georges', 'Villeneuve-Saint-Georges', 48.7305272, 2.44782,
  'images/Capturedcran2026-03-04164836.png', '', '', '2026-03-04', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772639944407', 'agriculture');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772639982104', 'OMBRIÈRES, ARCHITECTURE BIOCLIMATIQUE', 'SHADE STRUCTURES, BIOCLIMATIC ARCHITECTURE', '2022',
  'Un habitat bioclimatique est un bâtiment dans lequel le chauffage et le rafraîchissement sont réalisés en tirant le meilleur parti du rayonnement solaire et de la circulation naturelle de l’air. Ce type de conception, issu d’un savoir-faire ancien remis au goût du jour, repose sur une articulation fine entre architecture, climat local, et comportement thermique des matériaux. L’habitat bioclimatique privilégie une orientation optimale du bâtiment, des ouvertures pensées pour capter ou limiter les apports solaires selon les saisons, ainsi qu’une isolation renforcée pour minimiser les besoins en énergie. L’inertie thermique, la ventilation naturelle traversante, et l’usage de matériaux locaux à faible impact environnemental complètent cette stratégie. Ce mode de construction, éprouvé notamment dans les régions méditerranéennes, sahéliennes ou alpines, permet de réduire considérablement les consommations d’énergie tout en améliorant le confort intérieur. Il s’inscrit ainsi comme une réponse pertinente aux enjeux contemporains de sobriété énergétique et d’adaptation climatique.', 'A bioclimatic home is a building in which heating and cooling are achieved by making the most of solar radiation and natural air circulation. This type of design, based on ancient know-how that has been brought up to date, relies on a delicate balance between architecture, local climate, and the thermal behavior of materials. Bioclimatic housing prioritizes optimal building orientation, openings designed to capture or limit solar gain depending on the season, and enhanced insulation to minimize energy requirements. Thermal inertia, natural cross ventilation, and the use of local materials with low environmental impact complete this strategy. This construction method, which has been tried and tested in Mediterranean, Sahelian, and Alpine regions, significantly reduces energy consumption while improving indoor comfort. It is therefore a relevant response to the contemporary challenges of energy efficiency and climate adaptation.', 'DDOI',
  '', '', NULL, NULL,
  'images/Capturedcran2026-03-04165321.png', '', 'https://atba.ch/wp-content/uploads/2018/12/Conference-bioclimatique-2007-Ecoquartier.pdf', '2026-03-04', 'published', 1, '2026-03-04 15:54:17', '2026-03-04 15:54:17'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772639982104', 'solaire');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772639982104', 'h2o');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772639982104', 'agriculture');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772640075826', 'LE PRÉSAGE, LE RESTAURANT SOLAIRE', 'LE PRÉSAGE, THE SOLAR RESTAURANT', '2020',
  'À Marseille, Le Présage est devenu en 2020 le premier restaurant solaire d’Europe. Imaginé par Pierre-André Aubert, ancien ingénieur aéronautique, il utilise une parabole solaire pour cuire ses plats, s’inspirant des travaux de Wolfgang Scheffler. Cette technologie a permis de réduire de moitié la consommation d’énergie en huit mois.\n\nAu-delà de la cuisson solaire, Le Présage adopte une approche durable : produits locaux et de saison, lutte contre le gaspillage, projets de méthanisation et de forêt comestible. Véritable laboratoire culinaire, il montre comment l’innovation peut réinventer la gastronomie en alliant tradition, écologie et excellence.', 'In Marseille, Le Présage became Europe''s first solar-powered restaurant in 2020. Designed by Pierre-André Aubert, a former aeronautical engineer, it uses a solar dish to cook its dishes, inspired by the work of Wolfgang Scheffler. This technology has halved energy consumption in eight months.\n\nBeyond solar cooking, Le Présage takes a sustainable approach: local and seasonal products, waste reduction, methanization projects, and edible forests. A true culinary laboratory, it shows how innovation can reinvent gastronomy by combining tradition, ecology, and excellence.', '',
  'Marseille', 'Marseille', 43.2961743, 5.3699525,
  'images/Capturedcran2026-03-04170042.png', '', 'https://lepresage.fr/wp/', '2026-03-04', 'published', 1, '2026-03-04 15:29:25', '2026-03-04 15:29:25'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772640075826', 'agriculture');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772640075826', 'solaire');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772722621286', 'convention citoyenne sur la reconnaissance juridique de la Seine', 'Citizens'' convention on the legal recognition of the Seine', '2025',
  'Entre avril et mai 2025, la ville de Paris a organisé une convention citoyenne pour décider si une proposition de loi devait être déposée pour doter la Seine d’une personnalité juridique. L’objectif est, pour les grandes villes riveraines comme Paris et Rouen, double. Cette reconnaissance pourrait permettre de mieux protéger le fleuve face à des entreprises qui le polluent et de mieux intégrer les collectivités territoriales et les habitants vivant à proximité du fleuve dans les réflexions. C’est l’Etat qui, aujourd’hui, est responsable de la protection de la Seine, laissant assez peu de poids aux collectivités territoriales. La convention de Paris a finalement statué pour la déposition d’une proposition de loi, déposée en 2026. ', 'Between April and May 2025, the city of Paris organized a citizens'' convention to decide whether a bill should be introduced to give the Seine legal personality. The objective is twofold for large riverside cities such as Paris and Rouen. This recognition could make it possible to better protect the river from companies that pollute it and to better integrate local authorities and residents living near the river into the discussions. Today, the state is responsible for protecting the Seine, leaving local authorities with little influence. The Paris convention finally ruled in favor of submitting a bill, which was tabled in 2026. ', 'Anastasia Guéguen',
  'Paris', 'Paris', 48.8534951, 2.3483915,
  'images/Panorama_of_the_Seine_from_the_le_Saint-Louis_2.jpg', 'La Seine depuis l''île Saint-Louis, Paris, 17/07/22, DiscoA340, Wikimedia Commons. https://commons.wikimedia.org/wiki/File:Panorama_of_the_Seine_from_the_%C3%8Ele_Saint-Louis_2.jpg', 'https://www.leclubdesjuristes.com/opinion/loctroi-de-la-personnalite-juridique-a-la-seine-utile-ou-pas-11200/', '2026-03-05', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772722621286', 'h2o');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772722621286', 'gouvernance-de-leau');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772722621286', 'politique-publique');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772722831526', 'Minealithe', 'Minealithe', '2023',
  'Minealithe est une entreprise qui, après des années de recherche, a mis au point un procédé pour réaliser des pierres moulées à froid et à pression ambiante. En mélangeant du sable, de l’eau et un liant développé par l’entreprise, un matériel pouvant être utilisé pour la construction ou la décoration d’intérieur et qui a des caractéristiques proches du ciment peut être créé. La matière ainsi formée a une empreinte carbone faible, l’absence de cuisson permettant des économies d’énergie. L’eau utilisée n’a pas besoin d’être douce, de l’eau de mer convient parfaitement. Ce matériel est également 100% recyclable. ', 'Minealithe is a company that, after years of research, has developed a process for producing cold-molded stones at ambient pressure. By mixing sand, water, and a binder developed by the company, a material can be created that can be used for construction or interior decoration and has characteristics similar to cement. The material thus formed has a low carbon footprint, as the absence of firing saves energy. The water used does not need to be soft; seawater is perfectly suitable. This material is also 100% recyclable. ', 'François Waendendries',
  'France', 'France', 46.603354, 1.8883335,
  'images/copie-0-Minehalite-7.jpg', 'Pierre sculptées par Minealithe, Marie-Line Waroude, https://www.lagazettefrance.fr/article/minealithe-fabrique-des-pierres-par-voie-liquide.', 'https://www.lagazettefrance.fr/article/minealithe-fabrique-des-pierres-par-voie-liquide', '2026-03-05', 'published', 1, '2026-03-05 15:00:31', '2026-03-05 15:00:31'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772722831526', 'construction');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772722878460', 'Lancement du PIREN-Seine', 'Launch of PIREN-Seine', '1989',
  'Le Programme Interdisciplinaire de Recherche sur l’Environnement (PIREN) pour le bassin versant de la Seine a été lancé en 1989. Il s’agit d’un programme scientifique interdisciplinaire qui vise à mieux comprendre le fonctionnement du réseau hydrologique de la Seine, de son bassin versant et de la société humaine qui y habite. Il rassemble des chercheurs dans toute la France qui étudient plusieurs axes de recherche tels que l’évolution de la qualité des eaux ou les effets de l’agriculture sur l’eau et les milieux aquatiques. Aujourd’hui, et depuis les années 2010, le PIREN-Seine consacre une partie de ses ressources à envisager des adaptations du bassin aux effets du changement climatique. ', 'The Interdisciplinary Environmental Research Program (PIREN) for the Seine River Basin was launched in 1989. It is an interdisciplinary scientific program that aims to better understand the functioning of the Seine''s hydrological network, its watershed, and the human society that inhabits it. It brings together researchers from all over France who are studying several areas of research, such as changes in water quality and the effects of agriculture on water and aquatic environments. Today, and since the 2010s, PIREN-Seine has been devoting part of its resources to considering ways in which the basin can adapt to the effects of climate change. ', 'Bureau Eau dans la Ville 93',
  'France', 'France', 46.603354, 1.8883335,
  'images/WhatsAppImage2026-03-04at15.05.38.jpg', 'Mesures GPS sur le ruisseau des Avenelles dans la cadre d''un programme PIREN-Seine, 2025. ', 'https://www.piren-seine.fr/sites/default/files/piren_documents/fiches_4_pages/fiche_piren_seine_maj_2025_2305.pdf', '2026-03-05', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772722878460', 'h2o');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772723299485', 'Water calling, Isabelle Daëron', 'Water calling, Isabelle Daëron (Proposition)', '2023',
  'En 2023, la designer Isabelle Daëron publie Water calling, un livre sur les eaux souterraines à Kyoto menée en collaboration avec c Yoshiko Nagai, commissaire d’exposition. Les eaux souterraines sous la ville représentent un volume très important. Isabelle Daëron interroge le rapport entre cette eau et les êtres humains et son exploitation dans le milieu urbain. Le livre est composé de 20 illustrations, chacune associée à une onomatopée japonaise faisant référence à l’eau. \n', 'In 2023, designer Isabelle Daëron published Water Calling, a book about groundwater in Kyoto, in collaboration with exhibition curator Yoshiko Nagai. The city has a very large volume of groundwater beneath it. Isabelle Daëron explores the relationship between this water and human beings, and its use in urban environments. The book consists of 20 illustrations, each associated with a Japanese onomatopoeia referring to water. ', 'Cédric Carles',
  '', '', NULL, NULL,
  'images/water_calling_daeron.png', 'Water calling, https://www.leclubdesjuristes.com/opinion/loctroi-de-la-personnalite-juridique-a-la-seine-utile-ou-pas-11200/', 'https://cahiercentral.com/products/water-calling-isabelle-daeron', '2026-03-05', 'published', 1, '2026-03-05 15:07:17', '2026-03-05 15:07:17'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772723299485', 'h2o');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772723299485', 'imaginaire');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1772790229542', 'Maison de la famille Bel', 'Bel Family Home', '2006-2008',
  'Entre 2006 et 2008, Emmanuel et Christine se sont lancés dans la construction d’une maison écologique à Meulan, dans les Yvelines. La maison a été construite en suivant les principes du bioclimatisme. On retrouve peu d’ouvertures au nord, mais de grandes fenêtres au sud, avec une serre qui permet de capturer l’énergie solaire et de redistribuer la chaleur au reste de la maison. La maison est construite avec une ossature en bois et isolée avec des matériaux écologiques (chanvre notamment). En ce qui concerne la consommation en eau, c’est l’eau de pluie qui alimente la salle de bain et la cuisine. L’eau qui ruisselle sur le toit est stockée dans une cuve de 6000 litres puis passe par plusieurs filtres pour la rendre potable. Enfin, cette eau est traitée par un système de phyto-épuration, c’est-à-dire que ce sont les plantes qui filtrent les eaux usées. \n', 'Between 2006 and 2008, Emmanuel and Christine embarked on the construction of an eco-friendly house in Meulan, in the Yvelines department. The house was built according to bioclimatic principles. There are few openings on the north side, but large windows on the south side, with a greenhouse that captures solar energy and redistributes heat to the rest of the house. The house is built with a wooden frame and insulated with eco-friendly materials (including hemp). In terms of water consumption, rainwater is used to supply the bathroom and kitchen. The water that runs off the roof is stored in a 6,000-liter tank and then passes through several filters to make it drinkable. Finally, this water is treated by a phytopurification system, which means that plants filter the wastewater. ', 'Anastasia Guéguen',
  'Meulan', 'I''m sorry', 49.0049712, 1.9100835,
  'images/maison_famille_bel.png', 'Maison de la famille Bel, Elisabeth Gardet, Le Parisien, https://www.leparisien.fr/yvelines-78/meulan-depuis-dix-ans-ils-vivent-dans-une-maison-ecolo-faite-maison-10-07-2018-7814631.php', 'https://boutique.lamaisonecologique.com/produit/collector-eau-2024', '2026-03-06', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772790229542', 'h2o');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772790229542', 'isolation-thermique');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772790229542', 'conservation-de-lenergie');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1772790229542', 'construction');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1773130713309', 'La ga(r)zette de la Mission Val de Loire', 'The Mission Val de Loire newsletter', '2023',
  'La Mission Val de Loire est l’organisme chargé de la valorisation du fleuve Loire, inscrit au patrimoine mondial de l’UNESCO. Elle publie la ga(r)zette, un journal qui se déplie comme une carte et qui comprend des articles, interviews, éditos et un poster réalisé par un illustrateur ou une illustratrice. Le troisième numéro, intitulé “Loire sentinelle. Remonter aux sources”, invite le lecteur à s’interroger sur les sources, les îles, l’estuaire au encore les polluants. Ces journaux ont vocation à sensibiliser les lecteurs sur le patrimoine naturel formé par la Loire, son devenir ou encore sa protection. \n', 'Mission Val de Loire is the organization responsible for promoting the Loire River, a UNESCO World Heritage Site. It publishes La Ga(r)zette, a newspaper that unfolds like a map and includes articles, interviews, editorials, and a poster created by an illustrator. The third issue, entitled "Loire sentinelle. Remonter aux sources" (Loire sentinel. Back to the sources), invites readers to reflect on the river''s sources, islands, estuary and pollutants. These newspapers aim to raise readers'' awareness of the natural heritage formed by the Loire, its future and its protection. ', 'Anastasia Guéguen',
  'Val de Loire', 'Loire Valley', 47.4492772, -0.349549,
  'images/lagarzette.jpg', 'N°03 de la ga(r)zette, Mission Val de Loire, https://valdeloire.org/lagarzette', 'https://valdeloire.org/lagarzette', '2026-03-10', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1773130713309', 'imaginaire');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1773130713309', 'h2o');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1773130723504', 'CAMPAGNE DE PUB SUR LES PIEDS', 'ADVERTISING CAMPAIGN ON FEET', '2022',
  'En mai 2021, Bruxelles Mobilité lance pour la première fois une campagne de promotion de la marche à l’attention du grand public : Les Pieds.“Les pieds : disponibles 24h/24 en bas de vos chevilles… batterie très longue durée… une technologie du passé, pensée pour le futur… 100% naturel, produit localement” : dans cette campagne pleine de seconds degrés, Bruxelles Mobilité entend sensibiliser de manière décalée à la mobilité piétonne. Avec 37% des trajets effectués à pied, la marche est le premier moyen de déplacement à Bruxelles. Depuis quelques années, de nouvelles solutions de mobilité sont apparues à Bruxelles pour effectuer de petits trajets : trottinettes, scooters électriques et vélos partagés. Pourtant, la marche reste, à bien des égards, le mode de déplacement le plus efficace, le plus fiable et le plus durable pour parcourir de courtes distances. Bonne pour la santé, pour l’environnement, mais aussi pour la convivialité de la ville, la marche est prise en compte dans les travaux de rénovation notamment au niveau du confort des infrastructures piétonnes et de l’accessibilité de l’espace public.', 'In May 2021, Brussels Mobility is launching its first campaign to promote walking to the general public: Les Pieds (The Feet). "The feet: available 24 hours a day at the bottom of your ankles... very long battery life... technology from the past, designed for the future... 100% natural, locally produced": in this tongue-in-cheek campaign, Brussels Mobility aims to raise awareness of pedestrian mobility in an offbeat way. With 37% of journeys made on foot, walking is the primary means of transportation in Brussels. In recent years, new mobility solutions have emerged in Brussels for short journeys: scooters, electric scooters, and shared bicycles. However, walking remains, in many ways, the most efficient, reliable, and sustainable way to travel short distances. Good for your health, the environment, and the city''s livability, walking is taken into account in renovation work, particularly in terms of the comfort of pedestrian infrastructure and the accessibility of public spaces.', 'Cédric Carles',
  'Bruxelles', 'Brussels', 50.8551025, 4.3510915,
  'images/Capturedcran2026-03-06152742.png', '', '', '2026-03-10', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1773130723504', 'mecanique');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1773130732998', 'GESTION ALTERNATIVE DES EAUX PLUVIALES', 'ALTERNATIVE RAINWATER MANAGEMENT', '2022',
  'La politique du « tout-tuyau » issue du mouvement hygiéniste du XIXe siècle, qui a conduit à la création de canalisations afin d’évacuer l’eau vers aval, montre aujourd’hui ses limites. La saturation des réseaux due à l’extension de l’urbanisation provoque des risques d’inondation ou encore de pollution du milieu récepteur. \n\nL’adoption d’une gestion alternative des eaux pluviales peut permettre d’apporter des solutions à ces problématiques et même favoriser, en surface, le développement de la biodiversité, grâce à des aménagements parfois très simples. Parmi ces aménagements on peut citer la chaussée à structure réservoir, la tranchée drainante, la noue, le puits d’infiltration, les bassins, les revêtements perméables, la toiture verte, l’espace vert inondable, la récupération et l’utilisation des eaux pluviales. Si la mise en place de ces techniques se développe aujourd’hui, celle-ci reste encore trop légère, du fait d’un manque de connaissances et de pratiques.', 'The "all-pipe" policy that emerged from the 19th-century hygiene movement, which led to the creation of pipes to carry water downstream, is now showing its limitations. The saturation of networks due to urban expansion is causing risks of flooding and pollution of the receiving environment. \n\nThe adoption of alternative stormwater management can provide solutions to these problems and even promote the development of biodiversity on the surface, thanks to sometimes very simple measures. These measures include reservoir-structured pavements, drainage trenches, swales, infiltration wells, basins, permeable surfaces, green roofs, floodable green spaces, and rainwater harvesting and reuse. Although the implementation of these techniques is growing today, it is still too limited due to a lack of knowledge and practice.', 'Anna Perroux',
  '', '', NULL, NULL,
  'images/Capturedcran2026-03-06152941.png', '', '', '2026-03-10', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1773130732998', 'h2o');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1773130742367', 'RÉNOVER PLUTÔT QUE DÉTRUIRE', 'RENOVATE RATHER THAN DEMOLISH', '2022',
  'La France produit chaque année 325 millions de tonnes de déchets et 70% de ces déchets sont issus du secteur du bâtiment, soit 228 millions de tonnes. Plus de 90% de ces déchets sont inertes (gravats, terre non polluée, béton, brique, tuile, etc.) et souvent considérés comme "valorisés" en sous-couches routières et en remblais de carrière. Cependant la part de déchets du second œuvre (bois, plâtre, verre, isolants…) reste extrêmement importante. Ceux-ci sont d’ailleurs principalement visés par les obligations légales parues le 1er juillet 2021, destinées à éradiquer les décharges sauvages. Les professionnels devront faire figurer dans leurs devis un poste déchets et se procurer un bordereau attestant de leur dépôt dans une décharge autorisée sinon ils feront face à de lourdes sanctions. \n\nMais l’enjeu est beaucoup plus large, le taux de recyclage de certains produits utilisés dans le bâtiment doit aussi être amélioré. Il y a des matériaux qu’on continue à enfouir alors que l’on sait les recycler, par exemple, les plaques de plâtre ont un taux de recyclage de seulement 15% et le verre plat, uniquement de quelques pourcents. Il y a urgence, dans le secteur du bâtiment, d’envisager la démolition uniquement comme ultime recours, de réemployer les matériaux massivement et de réaliser des constructions frugales. ', 'France produces 325 million tons of waste every year, 70% of which comes from the construction sector, representing 228 million tons. Over 90% of this waste is inert (rubble, uncontaminated soil, concrete, brick, tiles, etc.) and is often considered "recycled" in road sub-bases and quarry backfills. However, the proportion of waste from finishing work (wood, plaster, glass, insulation, etc.) remains extremely high. This waste is mainly targeted by the legal obligations published on July 1, 2021, which are intended to eradicate illegal dumping. Professionals will have to include a waste item in their estimates and obtain a receipt certifying that they have deposited it in an authorized landfill, otherwise they will face heavy penalties. But the issue is much broader: the recycling rate of certain products used in construction must also be improved. There are materials that we continue to bury even though we know how to recycle them. For example, plasterboard has a recycling rate of only 15% and flat glass only a few percent. There is an urgent need in the construction sector to consider demolition only as a last resort, to reuse materials on a massive scale, and to build frugally. ', 'Cédric Carles',
  'France', 'France', 46.603354, 1.8883335,
  'images/Capturedcran2026-03-06153139.png', '', '', '2026-03-10', 'published', 1, '2026-03-12 12:57:17', '2026-03-12 12:57:17'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1773130742367', 'gestion-des-dechets');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1773130742367', 'construction');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1773130752653', 'L’URBANISME TRANSITOIRE', 'TRANSITIONAL URBAN PLANNING', '2022',
  'Depuis la fin des années 2000, on a vu apparaître progressivement, sur tout le territoire, le phénomène de vacance immobilière, c’est-à-dire l’inoccupation de bâtiments par cessation d’activité. Ce phénomène a fortement augmenté depuis le début de la crise sanitaire notamment avec le développement du télétravail. La première conséquence est économique, elle se traduit par des pertes de revenus pour les propriétaires. La vacance joue aussi un rôle négatif sur l’image et l’attractivité des quartiers ainsi que sur leur cadre de vie. Le manque d’entretien engendré conduit à une détérioration progressive du bâti. Face à ce phénomène, l’une des interventions les plus répandues est le renouvellement urbain : la démolition massive de vastes sites désaffectés en vue de leurs reconversions. Mais ce n’est plus une réponse adaptée, notamment à cause de la vacance disséminée dans des ensembles urbains encore en fonctionnement.\n\nL’urbanisme transitoire, développé récemment, est une solution dans la réactivation de ces sites inoccupés. Il vise à la réutilisation, de manière temporaire, d’un espace en attente d’un projet de requalification, par des associations, des entreprises d’économie sociale et solidaire, des organisateurs d’événements artistiques et festifs, qui bénéficient ainsi de loyers peu élevés. Les exemples se sont multipliés au cours des dernières années, dont le plus emblématique est celui des Grands Voisins, à Paris, sur le site de l’hôpital Saint-Vincent-de-Paul.', 'Since the late 2000s, we have seen a gradual increase in property vacancy rates across the country, i.e., buildings left unoccupied due to the cessation of business activity. This phenomenon has increased significantly since the start of the health crisis, particularly with the rise of remote working. The first consequence is economic, resulting in loss of income for property owners. Vacancies also have a negative impact on the image and attractiveness of neighborhoods, as well as on their living environment. The resulting lack of maintenance leads to the gradual deterioration of the buildings. One of the most common responses to this phenomenon is urban renewal: the large-scale demolition of vast disused sites with a view to their conversion. However, this is no longer an appropriate response, particularly because of the scattered vacancy in urban areas that are still in use.\n\nTransitional urban planning, developed recently, is one solution for reactivating these unoccupied sites. It aims to temporarily reuse spaces awaiting redevelopment projects by associations, social and solidarity economy enterprises, and organizers of artistic and festive events, who thus benefit from low rents. There have been many examples of this in recent years, the most emblematic being Les Grands Voisins in Paris, on the site of the Saint-Vincent-de-Paul hospital.', 'Cédric Carles',
  '', '', NULL, NULL,
  'images/Capturedcran2026-03-06153414.png', '', '', '2026-03-10', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1773130752653', 'construction');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1773130765101', 'ARCHITECTURE BIOCLIMATIQUE', 'BIOCLIMATIC ARCHITECTURE', '2022',
  'L''architecture bioclimatique est une discipline de l''architecture dont l''objectif est de tirer parti des conditions d''un site et de son environnement. Cette architecture s''adapte aux caractéristiques et particularités propres au lieu d''implantation: son climat, son microclimat, sa géographie et sa géomorphologie. Ceci dans le but d''améliorer le confort et l''efficacité énergétique du bâtiment. L''architecture bioclimatique fait appel à des stratégies, techniques et constructions simples qui permettent de chauffer, rafraîchir, ventiler l''intérieur d''une construction\n\nObjectif : conception de bâtiment passif\nexemple Bâtiment 2226 de l''agence BAUMSCHLAGER EBERLE', 'Bioclimatic architecture is a discipline of architecture that aims to take advantage of the conditions of a site and its environment. This type of architecture adapts to the characteristics and specific features of the location: its climate, microclimate, geography, and geomorphology. The goal is to improve the comfort and energy efficiency of the building. Bioclimatic architecture uses simple strategies, techniques, and constructions to heat, cool, and ventilate the interior of a building. Objective: passive building design example Building 2226 by the BAUMSCHLAGER EBERLE agency', 'Alexandre Lecointre',
  '', '', NULL, NULL,
  'images/Capturedcran2026-03-06154202.png', 'Bâtiment 2226 de l''agence BAUMSCHLAGER EBERLE', 'https://www.batiactu.com/edito/batiment-2226-41015.php', '2026-03-10', 'published', 1, '2026-04-03 09:15:34', '2026-04-03 09:15:34'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1773130765101', 'construction');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1773130852305', 'Rendre les cultures plus résistantes à la sécheresse', 'Making crops more drought-resistant', 'XXI siècle',
  'Dans un contexte de changement climatique, des recherches en génétique sont menées pour essayer de rendre les cultures plus résistantes aux sécheresses. Par exemple, en 2020, deux nouvelles variétés de niébé, plante riche en protéines, ont été distribuées à 800 agriculteurs zambiens avec le soutien de l''Organisation des Nations unies pour l’Alimentation et l’agriculture et de l’Agence internationale de l''énergie atomique. Ces deux variétés, nommées Lunkhwakwa et Lukusuzi, ont été créées par irradiation, ce qui a pour effet d''accélérer le processus naturel de mutation génétique. Les plantes vont mûrir plus vite et donc nécessiter moins d’eau et être plus résistantes à la sécheresse. Ces variétés sont également plus résistantes aux maladies. ', 'In the context of climate change, genetic research is being conducted to try to make crops more resistant to drought. For example, in 2020, two new varieties of cowpea, a protein-rich plant, were distributed to 800 Zambian farmers with the support of the Food and Agriculture Organization of the United Nations and the International Atomic Energy Agency. These two varieties, named Lunkhwakwa and Lukusuzi, were created through irradiation, which accelerates the natural process of genetic mutation. The plants will mature faster and therefore require less water and be more resistant to drought. These varieties are also more resistant to disease. ', 'Anastasia Guéguen',
  '', '', NULL, NULL,
  'images/Image_6_-_Rcolte_du_nib_dans_le_champs_scolaire_OBDAGA.jpg', 'Champ de niébé au Burkina Faso, 19/04/22, Fasouagadougou, Wikimedia Commons, https://commons.wikimedia.org/wiki/File:Image_6_-_R%C3%A9colte_du_ni%C3%A9b%C3%A9_dans_le_champs_scolaire_OBDAGA.jpg', 'https://www.iaea.org/fr/newscenter/news/cultures-tolerantes-a-la-secheresse-lappui-de-laiea-et-de-la-fao-permet-a-la-zambie-daugmenter-sa-production-agricole-et-dameliorer-les-revenus-de-ses-agriculteurs', '2026-03-09', 'published', 1, '2026-03-09 14:34:42', '2026-03-09 14:34:42'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1773130852305', 'h2o');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1773130852305', 'agriculture');
