INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1773134866777', ' Réutilisation de l’ ”eau de vache” dans l’industrie laitière', ' Reuse of "cow water" in the dairy industry', 'XXI siècle',
  'Le lait est constitué de près de 90% d’eau. Lorsque le lait est déshydraté et transformé en poudre pour divers usages, une partie de l’eau peut être récupérée. Cela permet de limiter la consommation en eau de l’usine. L’eau peut être utilisée pour laver les camions ou, après traitement, transféré dans les chaudières. L’usine de FrieslandCampina à Aalter (Belgique) utilise ce système depuis 2013, le groupe Nestlé l’a également mis en place dans certaines de ses usines, en commençant par celle de Lagos de Moreno au Mexique. En France l’usine Malo (Saint-Malo) a réduit de 10% sa consommation en eau depuis la mise en place du système en 2019. Les possibilités de réutilisation de cette eau sont définies dans un décret de 2024. \n', 'Milk consists of nearly 90% water. When milk is dehydrated and processed into powder for various uses, some of the water can be recovered. This helps to limit the factory''s water consumption. The water can be used to wash trucks or, after treatment, transferred to boilers. The FrieslandCampina factory in Aalter (Belgium) has been using this system since 2013, and the Nestlé group has also implemented it in some of its factories, starting with the one in Lagos de Moreno, Mexico. In France, the Malo plant (Saint-Malo) has reduced its water consumption by 10% since the system was introduced in 2019. The possibilities for reusing this water are defined in a 2024 decree. ', 'Anastasia Guéguen',
  '', '', NULL, NULL,
  'images/FrieslandCampina_in_Aalter_in_2012-02.jpg', 'Usine FrieslandCampina à Aalter, 25/06/12, Spotter2, Wikimedia Commons, https://commons.wikimedia.org/wiki/File:FrieslandCampina_in_Aalter_in_2012-02.jpg', 'https://www.abcbourse.com/marches/dans-les-laiteries-reutiliser-l-eau-de-vache-pour-moins-pomper-dans-le-reseau_639649', '2026-03-09', 'published', 1, '2026-03-09 16:12:03', '2026-03-09 16:12:03'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1773134866777', 'h2o');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1773154227590', 'Récupération de l’eau de betterave à Bazancourt', 'Beet water recovery in Bazancourt', '2009',
  'Le groupe Cristal Union est parmi les premiers producteurs de sucre, bioéthanol et alcool en Europe. Depuis 2009, dans leur usine de Bazancourt (Marne), l’eau récupérée lors de la transformation des betteraves est captée puis utilisée dans l’usine. Lors de la production, deux postes sont particulièrement gourmands en eau : le nettoyage des betteraves et l’extraction du sucre. Aujourd’hui, 100 % de l’eau récupérée dans les betteraves, qui en contiennent 70 %, est réutilisée. Ainsi, Cristal Union Bazancourt n’utilise aujourd’hui plus d’eau de forage pour ces activités. Une fois la campagne betteravière terminée, l’eau excédentaire est stockée dans des bassins à proximité de l’usine et sert aux agriculteurs pour irriguer leurs champs, dans une zone fréquemment confrontée aux problématiques de stress hydrique. \n', 'The Cristal Union group is one of Europe''s leading producers of sugar, bioethanol, and alcohol. Since 2009, at their plant in Bazancourt (Marne), water recovered during beet processing has been collected and reused in the plant. During production, two stages are particularly water-intensive: cleaning the beets and extracting the sugar. Today, 100% of the water recovered from the beets, which contain 70% water, is reused. As a result, Cristal Union Bazancourt no longer uses borehole water for these activities. Once the beet harvest is complete, the excess water is stored in basins near the factory and used by farmers to irrigate their fields in an area that frequently faces water stress issues. ', 'Anastasia Guéguen',
  'Bazancourt', 'Bazancourt', 49.5536604, 1.7356494,
  'images/Kalkar_Zuckerrben_PM171014_06.jpg', 'Betterave sucrière, 14/10/17, Pieter Deliccat, Wikimedia Commons, https://commons.wikimedia.org/wiki/File:Kalkar_Zuckerr%C3%BCben_PM171014_06.jpg', 'https://elementsindustriels.fr/economie-circulaire-utiliser-leau-de-pressage-des-betteraves-un-choix-gagnant-gagnant/', '2026-03-10', 'published', 1, '2026-03-10 11:06:49', '2026-03-10 11:06:49'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1773154227590', 'h2o');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1773154227590', 'agriculture');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1773154258552', 'L''arrosage au goutte-à-goutte', 'Drip irrigation', '1959',
  'Dès 1860, en Allemagne, se développe les premiers systèmes d’irrigation au goutte-à-goutte à partir de tuyaux d’argile. C’est, cependant, dans les années 1950 et 1960 que se développe le système de goutte-à-goutte moderne, avec des tuyaux percés. L’ingénieur Simcha Blass et son fils Yeshayahu mettent au point une première version expérimentale en 1959. Le goutte-à-goutte a permis de réaliser des cultures dans des climats arides en économisant de l’eau par rapport aux méthodes d’irrigation traditionnelles. L’arrosage se fait sans tasser le sol et sans mouiller les feuilles, ce qui évite les infections fongiques. \n', 'In 1860, the first drip irrigation systems were developed in Germany using clay pipes. However, it was in the 1950s and 1960s that the modern drip system was developed, using perforated pipes. Engineer Simcha Blass and his son Yeshayahu developed an initial experimental version in 1959. Drip irrigation made it possible to grow crops in arid climates while saving water compared to traditional irrigation methods. Watering is done without compacting the soil or wetting the leaves, which prevents fungal infections. ', 'Anastasia Guéguen',
  '', '', NULL, NULL,
  'images/Thse-la-Romaine_Loir-et-Cher_53893037993.jpg', 'arrosage au goutte-à-goutte dans le Loir-et-Cher, 25/07/2024, Daniel Jolivet, Wikimedia Commons, https://commons.wikimedia.org/wiki/File:Th%C3%A9s%C3%A9e-la-Romaine_(Loir-et-Cher)_(53893037993).jpg', 'https://www.microdrips.com/fr/blogue/arrosage-goutte-a-goutte/micro-irrigation/', '2026-03-10', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1773154258552', 'h2o');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1773154258552', 'agriculture');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1773154258552', 'conservation-alimentaire');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1773409108315', 'Panier filtrant pour les eaux pluviales', 'Rainwater Filter Basket', '1990-2000',
  'Le panier filtrant est l’une des méthodes de filtration la plus simple à installer et à entretenir. Il fonctionne comme un filtre à café et empêche les impuretés d’être entraînées avec l’eau de pluie dans les cuves de récupération. Un panier filtrant peut être installé dans le regard d’une gouttière ou bien à l’entrée d’une cuve de récupération des eaux pluviales. Cela empêche l’accumulation de dépôts dans la cuve de récupération, facilitant son entretien. L’eau ainsi récupérée peut ensuite être utilisée dans le jardin, pour l’arrosage des plantes par exemple. ', 'A filter basket is one of the easiest filtration methods to install and maintain. It works like a coffee filter and prevents debris from being carried along with the rainwater into the collection tanks. A filter basket can be installed in a gutter outlet or at the inlet of a rainwater collection tank. This prevents the buildup of debris in the collection tank, making it easier to maintain. The collected water can then be used in the garden, for watering plants, for example. ', 'Anastasia Guéguen',
  '', '', NULL, NULL,
  'images/tout-savoir-filtres-recuperation-eau-pluie-panier-filtrant.jpg', 'Panier filtrant, https://lacentrale-eco.com/conseils/recuperer-eau-de-pluie/tout-savoir-filtres-recuperation-eau-pluie.html', 'https://lacentrale-eco.com/conseils/recuperer-eau-de-pluie/tout-savoir-filtres-recuperation-eau-pluie.html', '2026-03-13', 'published', 1, '2026-03-17 14:41:01', '2026-03-17 14:41:01'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1773409108315', 'h2o');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1773409138404', 'Eco-Trône: les toilettes sèches design', 'Eco-Trône: Stylish Dry Toilets', '2009',
  'Eco-trône est une marque de toilettes sèches 100% recyclables, 100% personnalisables et design. Les toilettes sont disponibles dans différents modèles, en carton à 60% recyclé ou encore en bois issus de forêts certifiées PEFC, avec toujours un saut en inox de 15 litres. L’acier inoxydable se caractérise par une grande résistance à la corrosion et une facilité d’entretien. L’installation de toilettes sèches permet d’économiser de l’eau, une toilette classique pouvant consommer 11 à 16 m3 par an et par personne. Les toilettes Eco-trône peuvent être installées pour quelques centaines d’euros. ', 'Eco-trône is a brand of dry toilets that are 100% recyclable, 100% customizable, and stylish. The toilets are available in various models, made from 60% recycled cardboard or wood sourced from PEFC-certified forests, and always feature a 15-liter stainless steel tank. Stainless steel is characterized by high corrosion resistance and ease of maintenance. Installing dry toilets saves water, as a conventional toilet can consume 11 to 16 cubic meters per year per person. Eco-trône toilets can be installed for a few hundred euros. ', 'Anastasia Guéguen',
  'France', 'France', NULL, NULL,
  'images/3ecotrones.jpg', 'Eco-trône, https://www.habibois.com/itw/ecotrone-toilettes-seches-carton.php', 'https://www.habibois.com/itw/ecotrone-toilettes-seches-carton.php', '2026-03-13', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1773409138404', 'h2o');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1773409166572', 'L''eliodomestico : un dessalinisateur solaire', 'The Eliodomestico: A Solar Desalination System', '2012',
  'Eliodomestico est un dessalinisateur solaire inventé par le designer italien Gabriele Diamanti. L’appareil est d’une conception assez simple, il est constitué de deux récipients superposés. Celui du dessus est rempli d’eau de mer et celui du dessous est laissé vide. Grâce à une exposition au soleil, l’eau s’évapore, mais pas le sel. La vapeur ainsi produite ne peut pas s’échapper dans l’atmosphère à cause d’un couvercle et est redirigée vers le récipient du bas grâce à un tuyau. L’eliodomestico est un système assez simple à reproduire soit même, d’autant que les plans sont en opensource (libres de droits). \n', 'Eliodomestico is a solar desalination device invented by Italian designer Gabriele Diamanti. The device has a fairly simple design, consisting of two stacked containers. The top one is filled with seawater, while the bottom one is left empty. When exposed to sunlight, the water evaporates, but the salt does not. The steam produced cannot escape into the atmosphere because of a lid and is redirected to the lower container via a tube. The Eliodomestico is a system that is fairly easy to build yourself, especially since the plans are open-source (royalty-free). ', 'Anastasia Guéguen',
  '', '', NULL, NULL,
  'images/eliodomestico.jpg', 'eliodomestico, eau-nature.fr, https://www.eau-nature.fr/leliodomestico-un-dessalinisateur-solaire-a-fabriquer-soi-meme/', 'https://www.eau-nature.fr/leliodomestico-un-dessalinisateur-solaire-a-fabriquer-soi-meme/', '2026-03-13', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1773409166572', 'h2o');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1773409166572', 'solaire');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1773409195482', 'Les urinoirs sans eau Ti''Pi', 'Ti''Pi Waterless Urinals', '2019',
  'L’entreprise Ves Bat Eco, implantée à Saint-Jean-de-Luz, commercialise des urinoirs sans eau, fabriquée en France en plastique recyclé et recyclable. Un système de valve breveté empêche la remontée d’odeur. Le modèle existe pour les hommes et les femmes et est relié à une cuve. Ce système sans chasse d’eau permet d’économiser 100 000 l d’eau par an et par urinoir. ', 'Ves Bat Eco, a company based in Saint-Jean-de-Luz, sells waterless urinals made in France from recycled and recyclable plastic. A patented valve system prevents odors from rising. The model is available for both men and women and is connected to a tank. This flushless system saves 100,000 liters of water per year per urinal. ', 'Anastasia Guéguen',
  '', '', NULL, NULL,
  'images/urinoirstipi.jpeg', 'Urinoirs du club de rugby de La Réole, Toopi Organics, https://www.20minutes.fr/bordeaux/2966667-20210201-gironde-urinoirs-eau-installes-stade-transformer-urine-engrais', 'https://tipi.eco/categorie-produit/produits/urinoir/', '2026-03-13', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1773409195482', 'h2o');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1773410021162', 'La douche cyclique Ilya', 'The Ilya Cyclic Shower', '2022',
  'La douche constitue le premier poste de consommation en eau du foyer, et le deuxième en énergie. Pour essayer d’économiser eau et électricité, Simon Buoro et Antoine Escande développent une douche cyclique, qui réutilise plusieurs fois la même eau. La douche d’Ilya permet à l’utilisateur de démarrer un mode cyclique, lorsque la phase de nettoyage est terminée, afin de pouvoir rester sous la douche pour se réchauffer et se détendre. L’eau est stockée dans un bac puis nettoyée avec un filtre et une lampe UV avant d’être réchauffée et renvoyée par le pommeau de douche. Cela permet d’économiser jusqu’à 70 % de l’eau et de l''électricité. En effet, renvoyer l’eau filtrée dans la douche dépense moins d''énergie que le ballon d’eau chaude en dépense pour la chauffer. Lors de la phase de nettoyage, la douche fonctionne de manière classique en évacuant l’eau sale. L’invention a été récompensée en 2024 par une médaille d’or au concours Lépine. ', 'The shower is the biggest source of water consumption in the home and the second-biggest source of energy consumption. To help save water and electricity, Simon Buoro and Antoine Escande are developing a recirculating shower that reuses the same water multiple times. Ilya’s shower allows the user to switch to a recirculating mode once the washing phase is complete, so they can stay in the shower to warm up and relax. The water is stored in a tank, then cleaned using a filter and a UV lamp before being heated and recirculated through the showerhead. This saves up to 70% on water and electricity. In fact, recirculating filtered water through the shower uses less energy than a hot water tank does to heat it. During the cleaning phase, the shower operates in the traditional manner, draining the dirty water. The invention was awarded a gold medal at the Lépine competition in 2024. ', 'Anastasia Guéguen',
  'France', 'France', 46.603354, 1.8883335,
  'images/doucheilya.jpg', 'Douche Ilya, https://bigmedia.bpifrance.fr/nos-actualites/la-douche-cyclique-dilya-economise-eau-et-electricite', 'https://bigmedia.bpifrance.fr/nos-actualites/la-douche-cyclique-dilya-economise-eau-et-electricite', '2026-03-13', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1773410021162', 'h2o');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1773410021162', 'electricite');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1773412023412', 'drinkpure', 'drinkpure', '2015',
  'DrinkPure est un embout qui peut se visser sur une bouteille en plastique ou une gourde afin de rendre l’eau potable. Il fonctionne à l’aide de trois filtres qui retiennent les polluants et les séparent de l’eau. L’invention est celle de Jeremy Nussbaumer, un étudiant suisse. L’outil, facile d’utilisation, est destiné principalement aux populations n’ayant pas accès à de l’eau potable. Vendu quelques dizaines d’euros, ce système peut permettre de faciliter la vie de nombreuses personnes. Il existe également un filtre DrinkPure adapté pour les robinets. ', 'DrinkPure is a filter cap that screws onto a plastic bottle or water bottle to make the water safe to drink. It works using three filters that trap pollutants and separate them from the water. The invention was created by Jeremy Nussbaumer, a Swiss student. The easy-to-use device is primarily intended for people who lack access to safe drinking water. Sold for a few dozen euros, this system has the potential to make life easier for many people. There is also a DrinkPure filter designed for use with faucets. ', 'Anastasia Guéguen',
  '', '', NULL, NULL,
  'images/DrinkPure-1.jpg.webp', 'Jeremy Nussbaumer utilisant DrinkPure, https://www.consoglobe.com/drinkpure-eau-potable-cg/2', 'https://www.consoglobe.com/drinkpure-eau-potable-cg/2', '2026-03-13', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1773412023412', 'h2o');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1773412023412', 'sante');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1773412035351', 'L''eliodomestico : un dessalinisateur solaire', 'The Eliodomestico: A Solar Desalination System', '2012',
  'Eliodomestico est un dessalinisateur solaire inventé par le designer italien Gabriele Diamanti. L’appareil est d’une conception assez simple, il est constitué de deux récipients superposés. Celui du dessus est rempli d’eau de mer et celui du dessous est laissé vide. Grâce à une exposition au soleil, l’eau s’évapore, mais pas le sel. La vapeur ainsi produite ne peut pas s’échapper dans l’atmosphère à cause d’un couvercle et est redirigée vers le récipient du bas grâce à un tuyau. L’eliodomestico est un système assez simple à reproduire soit même, d’autant que les plans sont en opensource (libres de droits). \n', 'Eliodomestico is a solar desalination device invented by Italian designer Gabriele Diamanti. The device has a fairly simple design, consisting of two stacked containers. The top one is filled with seawater, while the bottom one is left empty. When exposed to sunlight, the water evaporates, but the salt does not. The steam produced cannot escape into the atmosphere because of a lid and is redirected to the lower container via a tube. The Eliodomestico is a system that is fairly easy to build yourself, especially since the plans are open-source (royalty-free). ', 'Anastasia Guéguen',
  '', '', NULL, NULL,
  'images/eliodomestico.jpg', 'eliodomestico, eau-nature.fr, https://www.eau-nature.fr/leliodomestico-un-dessalinisateur-solaire-a-fabriquer-soi-meme/', 'https://www.eau-nature.fr/leliodomestico-un-dessalinisateur-solaire-a-fabriquer-soi-meme/', '2026-03-13', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1773412035351', 'h2o');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1773412035351', 'solaire');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1773412047609', 'Solvatten', 'Solvatten', '2006',
  'L’inventrice suédoise Petra Wadstrom a tenté, avec son invention, de s’attaquer au problème du manque d’alimentation en eau potable, qui touche plus de 2 milliards de personnes dans le monde. Pour purifier l’eau, beaucoup de personnes la font bouillir en utilisant comme combustible du bois ou du charbon. Cela crée des gaz à effet de serre et alimente la déforestation. Solvatten est un dispositif transportable qui permet de potabiliser l''eau avec l’énergie du soleil. L’invention se présente sous la forme d’un jerrican de 10 litres qui s’ouvre en deux pour augmenter la surface d’exposition au soleil. En deux à six heures, suivant l''ensoleillement, les micro-organismes sont tués et l’eau est rendue potable. Solvatten est aujourd’hui utilisé par plus de 200 000 personnes pour remplir leurs besoins en eau quotidiens. ', 'Swedish inventor Petra Wadstrom has sought, through her invention, to address the problem of the lack of access to clean drinking water, which affects more than 2 billion people worldwide. To purify water, many people boil it using wood or charcoal as fuel. This creates greenhouse gases and contributes to deforestation. Solvatten is a portable device that purifies water using solar energy. The invention takes the form of a 10-liter jerry can that opens in half to increase the surface area exposed to the sun. In two to six hours, depending on sunlight, microorganisms are killed and the water is made safe to drink. Solvatten is now used by more than 200,000 people to meet their daily water needs. ', 'Anastasia Guéguen',
  '', '', NULL, NULL,
  'images/Solvatten_unit.jpg', 'Solvatten, 27/06/14, Tmrl84, Wikimedia Commons, https://commons.wikimedia.org/wiki/File:Solvatten_unit.jpg', 'https://www.parisglobalforum.org/2018/12/12/solvatten-rend-leau-potable-grace-au-soleil/', '2026-03-13', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1773412047609', 'h2o');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1773412047609', 'solaire');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1773412063145', 'Le programme OCAPI', 'The OCAPI Program', '2014',
  'OCAPI (Organisation des cycles en azote et phosphore dans les territoires) est un programme de recherche-action porté par le Laboratoire Eau Environnement et systèmes urbains. Le programme s’intéresse particulièrement à la gestion des sécrétions humaines dans l’agriculture. En effet, l’urine peut être un engrais naturel efficace. L’une des solutions pour collecter cette urine est d’utiliser des toilettes à séparation, dans lesquelles les matières solides et liquides sont séparées. Des collectes d’urines ont, par exemple, été organisées à Clichy et Achères par le Syndicat Interdépartemental d’Assainissement de l’Agglomération Parisienne. ', 'OCAPI (Organization of Nitrogen and Phosphorus Cycles in Regions) is an action-research program led by the Water, Environment, and Urban Systems Laboratory. The program focuses specifically on the management of human waste in agriculture. Indeed, urine can be an effective natural fertilizer. One solution for collecting this urine is to use split-flush toilets, in which solid and liquid waste are separated. Urine collection initiatives have, for example, been organized in Clichy and Achères by the Interdepartmental Sanitation Authority of the Paris Metropolitan Area. ', 'Anastasia Guéguen',
  'France', 'France', 46.603354, 1.8883335,
  'images/Urine-diversion_dehydration_toilet_UDDT_Model_EcoDry_top_view_3330209129.jpg', 'Toilette à séparation, Wostman Ecology, Wikimedia Commons, https://commons.wikimedia.org/wiki/File:Urine-diversion_dehydration_toilet_(UDDT)_Model_EcoDry_top_view_(3330209129).jpg', 'https://www.eau-seine-normandie.fr/urine_ocapi_CC_decembre_2018', '2026-03-13', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1773412063145', 'h2o');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1773412074047', 'Eco-Trône: les toilettes sèches design', 'Eco-Trône: Stylish Dry Toilets', '2009',
  'Eco-trône est une marque de toilettes sèches 100% recyclables, 100% personnalisables et design. Les toilettes sont disponibles dans différents modèles, en carton à 60% recyclé ou encore en bois issus de forêts certifiées PEFC, avec toujours un saut en inox de 15 litres. L’acier inoxydable se caractérise par une grande résistance à la corrosion et une facilité d’entretien. L’installation de toilettes sèches permet d’économiser de l’eau, une toilette classique pouvant consommer 11 à 16 m3 par an et par personne. Les toilettes Eco-trône peuvent être installées pour quelques centaines d’euros. ', 'Eco-trône is a brand of dry toilets that are 100% recyclable, 100% customizable, and stylish. The toilets are available in various models, made from 60% recycled cardboard or wood sourced from PEFC-certified forests, and always feature a 15-liter stainless steel tank. Stainless steel is characterized by high corrosion resistance and ease of maintenance. Installing dry toilets saves water, as a conventional toilet can consume 11 to 16 cubic meters per year per person. Eco-trône toilets can be installed for a few hundred euros. ', 'Anastasia Guéguen',
  'France', 'France', NULL, NULL,
  'images/3ecotrones.jpg', 'Eco-trône, https://www.habibois.com/itw/ecotrone-toilettes-seches-carton.php', 'https://www.habibois.com/itw/ecotrone-toilettes-seches-carton.php', '2026-03-13', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1773412074047', 'h2o');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1773412085638', 'La maison autonome en eau de Dominique et Didier Prudon', 'Dominique and Didier Prudon''s Water-Self-Sufficient Home', '2012-2013',
  '\nEntre 2012 et 2013, Dominique et Didier Prudon ont aménagé leur propriété pour être autonomes en eau. L’eau qui ruisselle sur le toit est amenée vers des cuves de récupération, filtrée et réutilisée dans la maison et dans le jardin, où le couple cultive son potager agroécologique et en permaculture. La cuve de 18 m3 permet, quand elle est pleine, de couvrir 50 % de leurs besoins en eau annuels. Les eaux usées sont, quant à elles, traitées en phytoépuration (filtrées par les plantes). Le prix des travaux ? 11 656 euros. \n\n', '\nBetween 2012 and 2013, Dominique and Didier Prudon renovated their property to achieve water self-sufficiency. Rainwater running off the roof is channeled into collection tanks, filtered, and reused in the house and garden, where the couple tends their agroecological and permaculture vegetable garden. When full, the 18-cubic-meter tank covers 50% of their annual water needs. Wastewater, meanwhile, is treated through phytoremediation (filtered by plants). The cost of the work? 11,656 euros. ', 'Anastasia Guéguen',
  'Gers', 'Gers', 43.6955276, 0.4101019,
  'images/maisonprudon.jpg', 'Jardin de Dominique et Didier Prudon, 2019, La Depeche, https://www.ladepeche.fr/2019/06/07/le-verger-galadriel-ouvre-ses-portes-demain,8243396.php', 'https://boutique.lamaisonecologique.com/produit/collector-eau-2024', '2026-03-13', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1773412085638', 'h2o');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1773412106268', 'Filtre d''eau de pluie pour chute de gouttière', 'Rainwater Filter for Gutter Downspouts', 'XXI siècle',
  'Un filtre peut être intégré directement sur la gouttière. Dans le cadre d’un système de récupération des eaux pluviales, il permet de capter une eau sans trop d’impuretés. Un filtre peut être installé pour quelques centaines d’euros et s''entretien facilement, avec des contrôles mensuels de l''élément filtrant. \n', 'A filter can be installed directly on the gutter. As part of a rainwater harvesting system, it helps collect water with minimal impurities. A filter can be installed for a few hundred euros and is easy to maintain, requiring only monthly checks of the filter element. ', 'Anastasia Guéguen',
  '', '', NULL, NULL,
  'images/filtre-descente-de-gouttiere-gep-500-microns.webp', 'Filtre de descente de gouttière, https://www.celesto.fr/filtres-avant-cuve/23-filtre-descente-de-gouttiere-gep-500-microns.html', 'https://www.celesto.fr/filtres-avant-cuve/23-filtre-descente-de-gouttiere-gep-500-microns.html', '2026-03-13', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1773412106268', 'h2o');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1773412118709', 'Le clapet de gouttière', 'The Gutter Flap', '1990-2000',
  'Ce clapet peut être installé sur une gouttière pour orienter l’eau de pluie vers un récupérateur. En cas de longue période sans averse, le clapet peut être refermé pour éviter de récupérer l’eau sale de lessivage du toit. L’eau ainsi interceptée peut être utilisée pour les usages extérieurs ou l’arrosage des plantes par exemple. Sur certains modèles, une grille permet d’arrêter les feuilles. Ce système peut être installé pour quelques dizaines d’euros, sans soudure. ', 'This valve can be installed on a gutter to direct rainwater into a collection tank. During long periods without rain, the valve can be closed to prevent the collection of dirty runoff water from the roof. The water collected in this way can be used for outdoor purposes or for watering plants, for example. On some models, a screen helps keep leaves out. This system can be installed for a few dozen euros, without any welding required. ', 'Anastasia Guéguen',
  '', '', NULL, NULL,
  'images/tuyau-a-clapet-zinc-titane-o.jpg', 'Collecteur d''eau à clapet en zinc, https://www.gouttiere-expert.fr/collecteur-a-clapet-zinc-tuyau.html', 'https://www.gouttiere-expert.fr/collecteur-a-clapet-zinc-tuyau.html', '2026-03-13', 'published', 1, '2026-03-17 14:36:32', '2026-03-17 14:36:32'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1773412118709', 'h2o');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1773418738947', 'La phytoépuration de l’eau', 'Conservation of Water Through Aquatic Plants', '1970-1980',
  'La phytoépuration, ou épuration par les plantes, est un procédé naturel. La phytoépuration moderne, sous forme de filtres plantés, s’est développée au cours des années 1970 et 1980. Il s’agit d’un système d’épuration écologique qui utilise les plantes et les microorganismes pour purifier l’eau. Elle est autorisée en France depuis 2009 et peut convenir aussi bien pour des maisons individuelles que pour des lotissements. Généralement, les systèmes de phytoépuration se composent généralement de plusieurs bassins plantés de roseaux, joncs, iris et autres espèces végétales ayant pour capacité d’absorber les polluants. \n', 'Constructed wetlands, or plant-based water treatment, is a natural process. Modern constructed wetlands, in the form of planted filters, were developed during the 1970s and 1980s. It is an ecological treatment system that uses plants and microorganisms to purify water. It has been authorized in France since 2009 and is suitable for both single-family homes and housing developments. Generally, constructed wetland systems consist of several ponds planted with reeds, rushes, irises, and other plant species capable of absorbing pollutants. ', 'Anastasia Guéguen',
  '', '', NULL, NULL,
  'images/Constructed_wetland_5547195530.jpg', 'Phytoépuration au Pérou, Heike Hoffmann, 04/05/09, Wikimedia Commons, https://commons.wikimedia.org/wiki/File:Constructed_wetland_(5547195530).jpg', 'https://www.lefigaro.fr/jardin/phytoepuration-ce-qu-il-faut-savoir-sur-cet-assainissement-ecologique-20240104', '2026-03-13', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1773418738947', 'h2o');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1773418738947', 'gestion-des-dechets');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1773752009745', 'LE CHARIOT DE REPASSAGE SOLAIRE', 'THE SOLAR-POWERED IRONING CART', '2021',
  'Imaginé par Vinisha Umashankar, une jeune innovatrice indienne âgée de seulement 14 ans lors de sa nomination au prix Earthshot, ce chariot de repassage à l''énergie solaire vise à remplacer les fers traditionnels fonctionnant au charbon de bois. En Inde, des millions de vendeurs ambulants utilisent au quotidien ce combustible polluant, responsable non seulement de graves maladies respiratoires dues aux fumées toxiques, mais également d''une déforestation massive liée à sa production. Le dispositif de Vinisha s''affranchit de ces contraintes : cinq heures d''ensoleillement suffisent à charger les batteries et alimenter le fer électrique pendant six heures. Pensé pour les travailleurs, ce chariot offre une plus grande mobilité permettant le porte-à-porte, et intègre même des points de recharge pour téléphones mobiles afin de générer un revenu complémentaire pour les utilisateurs.', 'Designed by Vinisha Umashankar, a young Indian innovator who was just 14 years old when she was nominated for the Earthshot Prize, this solar-powered ironing cart aims to replace traditional charcoal-fired irons. In India, millions of street vendors use this polluting fuel daily, which is responsible not only for serious respiratory illnesses caused by toxic fumes but also for massive deforestation linked to its production. Vinisha’s device overcomes these challenges: five hours of sunlight are enough to charge the batteries and power the electric iron for six hours. Designed for workers, this cart offers greater mobility for door-to-door service and even includes mobile phone charging stations to generate additional income for users.', 'Cédric Carles',
  'Tamil Nadu', 'Tamil Nadu', 11.3323723, 78.6098639,
  'images/IMG_4082.jpg', 'https://earthshotprize.org/winners-finalists/vinisha-umashankar/', 'https://earthshotprize.org/winners-finalists/vinisha-umashankar/', '2026-03-17', 'published', 1, '2026-03-17 12:53:29', '2026-03-17 12:53:29'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1773752009745', 'solaire');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1773752009745', 'electricite');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1773934305800', 'Le serveur solaire du low tech magazine', 'The Solar Server from Low Tech Magazine', '2018',
  'Le Low tech magazine est un blog, fondé par Kris de Decker, qui propose des articles sur des usages plus respectueux de la technologie. Si le site existe depuis 2009, en 2018 est créée une version alternative qui fonctionne grâce à un serveur solaire. Cette volonté de réduire sa consommation en énergie vient du constat que, depuis l’invention d’Internet, la taille moyenne des pages web n’a fait qu’augmenter. Les sites demandent donc de plus en plus d''énergie pour être maintenus. Cette version solaire du site est une version allégée : la taille a été considérablement réduite. Le site est fixe (et non pas dynamique comme la plupart), on retrouve moins d’images, pas de logo trop lourd, pas de publicité, etc. Le serveur qui alimente le site est situé à Barcelone. Lorsque plusieurs jours de mauvais temps s''enchaînent, le site peut se retrouver hors ligne. ', 'Low Tech Magazine is a blog founded by Kris de Decker that features articles on more sustainable uses of technology. While the site has been around since 2009, an alternative version powered by a solar-powered server was launched in 2018. This effort to reduce energy consumption stems from the observation that, since the invention of the Internet, the average size of web pages has only increased. Websites therefore require more and more energy to maintain. This solar-powered version of the site is a streamlined version: its size has been significantly reduced. The site is static (rather than dynamic like most), featuring fewer images, no heavy logos, no ads, etc. The server powering the site is located in Barcelona. When several days of bad weather occur in a row, the site may go offline. ', 'Anastasia Guéguen',
  '', '', NULL, NULL,
  'images/lowtechmagazine.png', 'Interface du site solaire du low tech magazine, https://solar.lowtechmagazine.com/fr/about/the-solar-website/', 'https://www.numerama.com/tech/424983-ce-site-est-tellement-low-tech-quil-est-hors-ligne-quand-il-ny-a-pas-de-soleil.html', '2026-03-19', 'published', 1, '2026-03-19 15:31:45', '2026-03-19 15:31:45'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1773934305800', 'solaire');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1773934305800', 'technologie');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1773934305800', 'numerique');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1773936395104', 'Fairphone', 'Fairphone', '2010',
  'Fairphone est une entreprise néerlandaise qui se donne pour mission de créer le smartphone le plus durable et équitable possible. Depuis 2010, l’entreprise conçoit des téléphones, mais également d’autres types d’appareils électroniques tels que des écouteurs ou des casques audio. Les fairphones sont fabriqués de tels manières que les différentes pièces (appareil photo, batterie, écran, etc.) sont facilement remplaçable en cas de casse afin de pouvoir allonger la durée de vie de l’appareil. D’autre part, les matériaux utilisés dans la fabrication des appareils ne proviennent pas de pays en guerre ni de mines qui font travailler des enfants. ', 'Fairphone is a Dutch company whose mission is to create the most sustainable and ethically produced smartphone possible. Since 2010, the company has been designing phones as well as other types of electronic devices, such as earbuds and headphones. Fairphones are manufactured in such a way that individual components (camera, battery, screen, etc.) can be easily replaced if broken, thereby extending the device’s lifespan. Furthermore, the materials used in the devices’ production do not come from war-torn countries or mines that employ child labor. ', 'Anastasia Guéguen',
  'Pays-Bas', 'Netherlands', 52.2434979, 5.6343227,
  'images/Fairphone_3_Modularity_48858510338.jpg', 'Fairphone 3, 07/10/19, Wikimedia Commons, https://www.lemonde.fr/economie/article/2019/08/27/fairphone-mise-sur-ses-smartphones-durables-pour-se-demarquer_5503386_3234.html', 'https://www.lemonde.fr/economie/article/2019/08/27/fairphone-mise-sur-ses-smartphones-durables-pour-se-demarquer_5503386_3234.html', '2026-03-19', 'published', 1, '2026-03-19 16:06:35', '2026-03-19 16:06:35'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1773936395104', 'technologie');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1773936395104', 'numerique');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1773936395104', 'electronique');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1774349619994', 'MUR EN PISÉ - TERRE CRUE', 'STAMPED EARTH WALL - RAW EARTH', '2022',
  'Réintégrer dans les constructions, les protections des murs en terre crue pour les parois intérieures au lieu d’utiliser du béton carboné. \n\nLes avantages d’un mur en terre crue sont tout d’abord environnementaux : \nLa terre est une matière omniprésente sur la totalité des surfaces constructibles. On peut dire que c’est une ressource inépuisable. Par comparaison aux autres constructions utilisant du béton par exemple, le mur en terre nécessitera moins d’eau. \n\nDu point de vue technique, la terre possède une grande inertie thermique et c’est un bon isolant phonique. ', 'Reintroduce earthen walls as interior partitions in construction projects instead of using carbon-intensive concrete. \n\nThe advantages of an earthen wall are primarily environmental: \nEarth is a material found everywhere on all buildable land. It can be said to be an inexhaustible resource. Compared to other constructions using concrete, for example, an earthen wall requires less water. \n\nFrom a technical standpoint, earth has high thermal inertia and is a good sound insulator. ', 'Groupama Immobilier',
  '', '', NULL, NULL,
  'images/IMG_4130.jpeg', '', '', '2026-03-24', 'published', 1, '2026-03-24 10:53:39', '2026-03-24 10:53:39'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1774349619994', 'construction');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1774349619994', 'isolation-thermique');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1774351567887', 'SANS PRESSION, RÉCUPÉRATION DE LA PLUIE', 'NO PRESSURE, RAINWATER HARVESTING', '2022',
  'Sans pression est une famille d’objets d’arrosage dessinée par Lucien Icard, permettant de rendre visible et de réguler sa consommation d’eau. Ces objets utilisent des principes physiques simples, comme la coupe de Pythagore, les vases communicants, le tourniquet hydraulique, pour se passer de l’eau du réseau et s’alimenter d’eau de pluie. À la frontière entre objets pédagogiques et techniques, ces dispositifs s’inscrivent dans une démarche de revalorisation des ressources naturelles au quotidien, pour permettre aux utilisateur·ices de devenir acteur·ices du changement.\n\nLe récupérateur se fixe sur une gouttière, récoltant l’eau de toiture, puis la redirige vers une cuve au centre du jardin. Cela réduit la distance à parcourir et permet l’usage d’outils simples et économes, comme l’arrosoir.\n\nLucien Icard développe aussi un arroseur rotatif activé par la pression de l’eau, des doseurs pour l’irrigation à la racine et un réseau d’irrigation par jarre.', 'Sans pression is a family of watering devices designed by Lucien Icard that make water consumption visible and allow users to regulate it. These devices use simple physical principles—such as the Pythagorean cup, communicating vessels, and the hydraulic wheel—to operate without mains water, relying instead on rainwater. Straddling the line between educational and technical tools, these devices are part of an effort to promote the reuse of natural resources in daily life, empowering users to become agents of change.\n\nThe collector attaches to a gutter, collecting rainwater from the roof, then redirects it to a tank in the center of the garden. This reduces the distance the water has to travel and allows for the use of simple, economical tools, such as a watering can.\n\nLucien Icard is also developing a water-pressure-activated rotating sprinkler, dispensers for root irrigation, and a jar-based irrigation system.', 'Simon Bouchaudy',
  '', '', NULL, NULL,
  'images/IMG_4131.jpeg', '', '', '2026-03-24', 'published', 1, '2026-03-24 11:26:07', '2026-03-24 11:26:07'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1774351567887', 'h2o');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1774351567887', 'agriculture');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1774351670199', 'TAILLE-HAIE MÉCANIQUE', 'MOTORIZED HEDGE TRIMMER', '2023',
  'Le taille-haie mécanique fait partie d’une série d’outils de coupe silencieux développés par Céline Deprez et Camille Chapuis, de l’atelier Super Solide.\n\nPensés pour les jardins domestiques de petite à moyenne taille, ces outils cherchent à apaiser les tensions liées à l’usage des machines motorisées : bruit, puissance, univers genré. Ici, pas de moteur, mais une mécanique simple et efficace, inspirée des cisailles à lames multiples. Le principe de coupe repose sur le glissement de lames articulées, actionnées par une poignée en acier à effet ressort.\n\nLe taille-haie se situe entre outil manuel et électrique : moins fatigant qu’une cisaille classique, plus léger et silencieux qu’un appareil motorisé. L’enjeu est de proposer un geste fluide, sans épuiser les bras. ', 'The mechanical hedge trimmer is part of a series of quiet cutting tools developed by Céline Deprez and Camille Chapuis of the Super Solide workshop.\n\nDesigned for small to medium-sized home gardens, these tools aim to alleviate the tensions associated with using motorized machines: noise, power, and gendered stereotypes. Here, there is no motor, but rather a simple and effective mechanism inspired by multi-blade shears. The cutting principle relies on the sliding of articulated blades, activated by a spring-loaded steel handle.\n\nThe hedge trimmer falls somewhere between a manual and an electric tool: less tiring than a traditional shears, lighter and quieter than a motorized device. The goal is to offer a fluid motion without tiring the arms. ', 'Clara Loisel',
  '', '', NULL, NULL,
  'images/IMG_4132.jpeg', '', 'https://super-solide.com/Taille-haie-mecanique', '2026-03-24', 'published', 1, '2026-03-24 11:27:50', '2026-03-24 11:27:50'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1774351670199', 'agriculture');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1774351670199', 'mecanique');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1774516147537', 'La citerne verte', 'The Green Tank', '2012',
  'La citerne verte se présente comme une alternative, moins onéreuse, à l’enfouissement d’une cuve de récupération des eaux pluviales. Cette citerne souple permet de récupérer l’eau de pluie et est proposée en différents formats, allant jusqu’à une capacité de 50 m3. L’installation de ce type de citerne peut réduire jusqu’à 57 % la consommation d’eau potable. Il est possible d’installer un filtre en entrée, mais, comme il est impossible de nettoyer l’intérieur du dispositif, il est conseillé de réserver l’eau récupérée à des usages comme l’arrosage des plantes ou le nettoyage des sols. Elle est fabriquée en France, avec des matériaux recyclables et peut être installée pour quelques centaines d’euros. ', 'The green tank offers a more affordable alternative to installing an underground rainwater harvesting tank. This flexible tank collects rainwater and is available in various sizes, with capacities up to 50 cubic meters. Installing this type of tank can reduce drinking water consumption by up to 57%. It is possible to install an inlet filter, but since it is impossible to clean the inside of the tank, it is recommended to reserve the collected water for uses such as watering plants or cleaning floors. It is manufactured in France using recyclable materials and can be installed for a few hundred euros. ', 'Anastasia Guéguen',
  '', '', NULL, NULL,
  'images/la_citerne_verte.webp', 'citerne verte, https://maison.com/brico-travaux/plomberie/citerne-verte-coffre-fort-tresor-naturel-pluie-8530/', 'https://www.la-citerne-verte.com/concept-recuperateur-eau-pluie', '2026-03-26', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1774516147537', 'h2o');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1775051113956', 'Trompe Hydraulique', 'Hydraulic Horn', '1629',
  'La trompe hydraulique est une installation qui permet de créer de l’air comprimé à partir d’une chute d’eau. Par effet Venturi, l’air est aspiré dans un tube puis il est comprimé du fait de la hauteur de chute. On peut identifier plusieurs inventions de l’antiquité tardive comme des antécédents à la trompe hydraulique. Par exemple, le « soufflet à eau » est utilisé au IVe siècle par l’empire sassanide. Cependant, c’est au XVIe siècle, en Italie, que les premières mentions concernant son existence se multiplient. En 1629, Giovanni Branca publie Le Machine, dans lequel il illustre le principe de la trompe d’eau utilisée pour apporter du vent au foyer d’une forge ou alimenter un orgue. C’est à partir de ce moment que le principe de la trompe se diffuse chez les érudits de la Renaissance, puis un peu partout dans le monde. L’utilisation de la trompe hydraulique se généralise dans le secteur pyrénéen dans la deuxième moitié du XVIIe siècle. L’invention connaît son apogée dans l’Ariège (09), en devenant indissociable de la forge catalane. Son usage disparaît progressivement au début du XIXe siècle, en même temps que les bas fourneaux et les procédés d’acier naturel.', 'A hydraulic ram is a device that generates compressed air using a waterfall. Through the Venturi effect, air is drawn into a tube and then compressed by the force of the falling water. Several inventions from late antiquity can be identified as precursors to the hydraulic trumpet. For example, the “water bellows” was used in the 4th century by the Sassanid Empire. However, it was in 16th-century Italy that the first references to its existence began to multiply. In 1629, Giovanni Branca published *Le Machine*, in which he illustrated the principle of the water trumpet used to supply air to a forge’s firebox or to power an organ. It was from this point onward that the principle of the water trumpet spread among Renaissance scholars, and then throughout the world. The use of the water trumpet became widespread in the Pyrenees region during the second half of the 17th century. The invention reached its peak in Ariège (09), becoming inseparable from Catalan forges. Its use gradually disappeared in the early 19th century, along with low furnaces and natural steel processes.', 'Thierry Lagarde',
  '', '', NULL, NULL,
  'images/Trompe-hydraulique.jpg', 'Gravure de Giovanni Branca 1629, réimprimée en 1977, Wikimedia Commons, https://ca.wikipedia.org/wiki/Fitxer:BRANCA_TROMBA.jpg', 'https://fr.wikipedia.org/wiki/Trompe_hydraulique', '2026-04-01', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1775051113956', 'h2o');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1775051140321', 'Ecodomeo', 'Ecodomeo', '2009',
  'Ecodomeo commercialise des toilettes sèches adaptées à l’habitat d’aujourd’hui puisqu’elles s’utilisent comme des toilettes classiques et demande seulement 2 heures d’entretien par an. Il s’agit de toilettes sèches à séparation d’urine, grâce à un système de plancher incliné mis en action par une pédale. Les urines sont rejetées avec les eaux usées et les selles et le papier toilette sont transformés en compost grâce à des lombrics et des bactéries dans un local de compostage attenant. Ce compost ne s’évacue que tous les 3 à 10 ans. Les toilettes Ecodomeo sont ainsi sans eau, sans sciure et sans produits chimiques. Elles permettent ainsi d’économiser 15 000 litres d’eau par personne et par an et de générer 15 litres/personne/an d’un compost de très bonne qualité. ', 'Ecodomeo sells dry toilets designed for modern homes, as they are used just like conventional toilets and require only two hours of maintenance per year. These are urine-diverting dry toilets, thanks to a sloped floor system activated by a pedal. Urine is flushed away with wastewater, while feces and toilet paper are turned into compost by earthworms and bacteria in an adjacent composting unit. This compost is removed only every 3 to 10 years. Ecodomeo toilets are thus waterless, sawdust-free, and chemical-free. They save 15,000 liters of water per person per year and produce 15 liters of high-quality compost per person per year. ', 'Anastasia Guéguen',
  '', '', NULL, NULL,
  'images/ECODOMEO_-_Zircone_9067594784.jpg', 'Toilettes Ecodomeo, https://commons.wikimedia.org/wiki/File:ECODOMEO_-_Zircone_(9067594784).jpg', 'https://www.ecodomeo.com/concept-solution-toilettes-seches-design-lombricompostage/', '2026-04-01', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1775051140321', 'h2o');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1775051151339', 'Récupération de chaleur des serveurs infomaniak', 'Heat Recovery from Infomaniak Servers', '2025',
  'Infomaniak a inauguré un data center à Genève dans lequel 100 % de la chaleur produite est utilisée pour chauffer des logements. Ce centre, construit en sous-sol, n’a pas besoin de climatisation ni d’eau pour être refroidi. À l’année, cela permet de chauffer 6 000 logements et d’économiser 3 600 t CO2eq. ', 'Infomaniak has opened a data center in Geneva where 100% of the heat generated is used to heat homes. Built underground, the facility requires no air conditioning or water for cooling. Over the course of a year, this enables the heating of 6,000 homes and saves 3,600 metric tons of CO2 equivalents. ', 'Cédric Carles',
  'Genève', 'Geneva', 46.2017559, 6.1466014,
  'images/Virginia_Tech_-_data_center.jpg', 'https://commons.wikimedia.org/wiki/File:Virginia_Tech_-_data_center.jpg', 'https://news.infomaniak.com/infomaniak-inaugure-un-data-center-revolutionnaire-qui-revalorise-100-de-son-energie-pour-chauffer-des-batiments/', '2026-04-01', 'published', 1, '2026-04-08 11:57:42', '2026-04-08 11:57:42'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1775051151339', 'electricite');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1775051151339', 'rechauffer');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1775051151339', 'numerique');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1775051163499', 'Le plan Eau de la région Occitanie', 'The Occitanie Region Water Plan', '2023',
  'La région Occitanie est l’une des plus sensibles au dérèglement climatique, avec des épisodes de sécheresse et des incendies de plus en plus violents. En 2023, elle lance un ambitieux plan eau” qui consacre chaque année 40 millions d’euros dans la gestion de l’eau jusqu’à 2030. L’un de ses objectifs est notamment de réduire de 20 % la consommation en eau de ses lycées d’ici 2030. Le lycée d’enseignement général et technologique agricole Marie Durand de Rodilhan est l’un des lycées pilotes. Les économies d’eau reposent notamment sur des robinets et des chasses d’eau économes en eau installées dans les sanitaires.', 'The Occitanie region is one of the most vulnerable to climate change, experiencing increasingly severe droughts and wildfires. In 2023, it launched an ambitious “water plan” that allocates 40 million euros annually to water management through 2030. One of its key objectives is to reduce water consumption in its high schools by 20% by 2030. The Marie Durand General and Agricultural Technology High School in Rodilhan is one of the pilot schools. Water savings are achieved primarily through the installation of water-efficient faucets and toilet flush systems in the restrooms.', 'Anastasia Guéguen',
  'Occitanie', 'Occitanie', 43.6487851, 2.3435684,
  'images/lycemariedurandrodilhan.jpg', 'Lycée Marie Durand, 02/04/16, Midi Libre, https://www.midilibre.fr/2016/03/30/rodilhan-journee-portes-ouvertes-au-lycee-agricole-et-au-cfa,1308832.php', 'https://gazette-du-midi.fr/au-sommaire/entreprises/l-occitanie-se-dote-d-un-plan-eau', '2026-04-01', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1775051163499', 'h2o');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1775051175298', 'Une commune finance à 50 % de récupérateur d’eau de pluie', 'A municipality covers 50% of the cost of a rainwater harvesting system', '2023',
  'Dans l’Aube, la commune de Romilly-sur-Seine finance, depuis 2023, l’achat de récupérateur d’eau de pluie à hauteur de 50 %. Tous les propriétaires, de maison ou d’immeuble, sont éligibles à la mesure. Un récupérateur d’eau de pluie peut permettre de réaliser jusqu’à 50 % d’économies d’eau. L’eau n’est pas potable, mais peut permettre d’arroser les plantes, de laver la voiture ou encore, si on met en place un système pour les relier, d’être utilisée dans la chasse d’eau ou la machine à laver. Selon les estimations, si seulement 10 % des habitants de la commune, qui en compte près de quinze mille, l’équivalent de deux semaines de consommation en eau pourrait être économisé. ', 'In the Aube department, the municipality of Romilly-sur-Seine has been providing 50% funding for the purchase of rainwater harvesting systems since 2023. All homeowners and building owners are eligible for this program. A rainwater harvesting system can help save up to 50% on water usage. The water is not potable, but it can be used to water plants, wash the car, or—if a system is set up to connect them—in the toilet or washing machine. According to estimates, if just 10% of the town’s residents—numbering nearly fifteen thousand—were to install such systems, the equivalent of two weeks’ worth of water consumption could be saved. ', 'Anastasia Guéguen',
  'Romilly-sur-Seine', 'Romilly-sur-Seine', 48.5197475, 3.7263678,
  'images/Htel_de_ville_de_Romilly-sur-Seine.jpg', 'Hotel de ville de Romilly-sur-Seine, 19/09/16, Wikimedia Commons, https://commons.wikimedia.org/wiki/File:H%C3%B4tel_de_ville_de_Romilly-sur-Seine.jpg', 'https://www.lunion.fr/id544014/article/2023-11-28/une-commune-de-laube-finance-lachat-de-recuperateurs-deau-de-pluie', '2026-04-01', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1775051175298', 'h2o');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1775051188462', 'Réhabilitation des tuyaux sans tranchée', 'Trenchless Pipe Rehabilitation', '1971',
  'Les tuyaux, notamment ceux du réseau d’eau potable, nécessite un entretien pour palier aux fuites et dégradations. Certaines méthodes impliquent de creuser des tranchées afin de pouvoir accéder aux tuyaux et les remplacer. Il existe plusieurs méthodes, Eric Wood a, par exemple, développé en 1971 une technique utilisant une gaine en feutre imprégnée de résine insérée dans les tuyaux et qui durcit. D’autres méthodes ont depuis été développées. Il est possible d’injecter directement une résine qui se plaque directement aux parois de la canalisation. Une autre technique, l’éclatement, consiste à remplacer l’ancienne canalisation par une nouvelle de diamètre plus important. L’ancienne conduite est détruite. Enfin, il est également possible d’introduire une nouvelle canalisation dans l’ancienne, qui sert de fourreau. Ce type de réparations permet de limiter l’impact des travaux, sur les fermetures de routes par exemple. ', 'Pipes, particularly those in the drinking water system, require maintenance to address leaks and damage. Some methods involve digging trenches to access the pipes and replace them. There are several methods; for example, in 1971, Eric Wood developed a technique using a resin-impregnated felt liner inserted into the pipes that hardens. Other methods have since been developed. It is possible to inject resin directly, which adheres to the pipe walls. Another technique, pipe bursting, involves replacing the old pipe with a new one of larger diameter. The old pipe is destroyed. Finally, it is also possible to insert a new pipe into the old one, which serves as a sleeve. This type of repair helps minimize the impact of the work, such as road closures. ', 'Anastasia Guéguen',
  '', '', NULL, NULL,
  'images/Trenchless_sewer_relining_repairmen.jpg', 'Chemisage de canalisations sans tranchée, 14/10/14, Rachkay333, Wikimedia Commons, https://commons.wikimedia.org/wiki/File:Trenchless_sewer_relining_repairmen.jpg', 'https://www.eau17.fr/actualites/techniques-de-rehabilitation-sans-tranchee-des-reseaux-une-solution-alternative-pour', '2026-04-01', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1775051188462', 'h2o');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1775051199221', 'Les Eugènes pour nettoyer les poubelles', 'The Eugènes to clean out the trash cans', '2023',
  'L’entreprise Les Eugènes tire son nom du préfet de Paris Eugène Poubelle à qui on doit la création de contenant pour ramasser les déchets. L’entreprise dijonnaise a mis au point une solution pour le nettoyage des contenants à déchets en réalisant des économies en eau par rapport aux solutions de nettoyage classiques. Des stations de nettoyage ont été installées dans des camionnettes et utilisent un système karcher, sans produits chimiques, pour nettoyer les contenants. Ce système permet d’utiliser 800 litres d’eau par tournée, contre 4 000 en utilisant une méthode classique, qui consiste à faire intervenir un poids lourd. Les Eugènes nettoient aujourd’hui 5 000 bacs à déchets chaque semaine et interviennent dans des municipalités telles que Lyon, Grenoble ou encore Nantes. ', 'The company Les Eugènes takes its name from Eugène Poubelle, the prefect of Paris, who is credited with inventing the trash can. The Dijon-based company has developed a solution for cleaning trash cans that uses less water than traditional cleaning methods. Cleaning stations have been installed in vans and use a chemical-free Karcher system to clean the bins. This system uses 800 liters of water per route, compared to 4,000 liters using a traditional method, which involves a heavy-duty truck. Les Eugènes now clean 5,000 waste bins each week and operate in cities such as Lyon, Grenoble, and Nantes. ', 'Anastasia Guéguen',
  '', '', NULL, NULL,
  'images/les_eugnes.jpg', 'Nettoyage de bacs avec les Eugènes, LBP/A. C., https://www.bienpublic.com/economie/2023/05/22/les-eugene-les-nettoyeurs-qui-partent-a-la-conquete-des-bacs-a-biodechets', 'https://jhm.fr/les-eugene-une-solution-ecoresponsable-pour-nettoyer-les-contenants/', '2026-04-01', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1775051199221', 'h2o');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1775051216849', 'création de “La Cinégraphie documentaire” par Jean Painlevé', 'The creation of “Documentary Cinematography” by Jean Painlevé', '1930',
  'Jean Painlevé est un biologiste, considéré comme l’un des pères fondateurs du cinéma documentaire. Durant sa carrière, il a réalisé plus de 200 films et courts-métrages en mêlant les éléments scientifiques et artistiques. Une grande partie de ses films constitue une observation du monde aquatique, comme l’hippocampe (1934), un de ses plus grands succès. En 1930, il crée sa propre société de production, “La Cinégraphie documentaire”. Jean Painlevé, par ses films documentaires, a participé à la connaissance des animaux qu’il filmait, souvent en aquarium. Il a également ouvert la voie au développement du cinéma scientifique en étant l’un des premiers chercheurs à s’en servir comme outil. ', 'Jean Painlevé was a biologist considered one of the founding fathers of documentary film. Over the course of his career, he directed more than 200 films and short films, blending scientific and artistic elements. A large portion of his films focused on the aquatic world, such as *The Seahorse* (1934), one of his greatest successes. In 1930, he founded his own production company, “La Cinégraphie documentaire.” Through his documentary films, Jean Painlevé contributed to our understanding of the animals he filmed, often in aquariums. He also paved the way for the development of scientific cinema by being one of the first researchers to use it as a tool. ', 'Anastasia Guéguen',
  '', '', NULL, NULL,
  'images/M._Jean_Painlev_prs_dun_microscope_-_btv1b90250205.jpg', 'Jean Painlevé près d''un microscope, 12/01/1926, Wikimedia Commons, https://commons.wikimedia.org/wiki/File:M._Jean_Painlev%C3%A9_pr%C3%A8s_d%27un_microscope_-_btv1b90250205.jpg', 'https://www.telerama.fr/cinema/jean-painleve-l-homme-qui-a-plonge-le-documentaire-scientifique-dans-le-cinema-7010816.php', '2026-04-01', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1775051216849', 'imaginaire');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1775051231398', 'Régie publique Eau de Paris', 'Eau de Paris Public Utility', '2009',
  'Depuis 1985, la gestion de l’eau à Paris était gérée par deux entreprises privées : Suez sur la rive gauche et Veolia sur la rive droite. Cette gestion partagée était supposée bénéficier aux usagers. Cependant, entre 1985 et 2009 la part d’eau potable dans le prix de l’eau a augmenté deux fois plus vite que l’inflation. D’autre part, les entreprises se sont fortement enrichies et leur gestion a été jugée “opaque” par Anne Le Strat, directrice de la SAGEP (Société anonyme de gestion des eaux de Paris) puis d’Eau de Paris entre 2001 et 2014. La remunicipalisation est donc apparu comme une solution. Elle était l’une des promesses de campagne pour les municipales de 2008. La régie publique a été créée en 2009 et mise en exécution en 2010. Depuis sa création, le prix de la production et de la gestion de l’eau a été diminué et le prix de l’eau à Paris est globalement moins élevé que celui de la banlieue où l’eau est gérée par des acteurs privés. La régie publique Eau de Paris s’occupe de la distribution d’eau pour toute la ville de Paris. ', 'Since 1985, water management in Paris has been handled by two private companies: Suez on the Left Bank and Veolia on the Right Bank. This shared management was supposed to benefit users. However, between 1985 and 2009, the portion of the water bill attributable to drinking water rose twice as fast as inflation. Furthermore, the companies became significantly wealthier, and their management was deemed “opaque” by Anne Le Strat, director of SAGEP (Société anonyme de gestion des eaux de Paris) and later of Eau de Paris between 2001 and 2014. Remunicipalization therefore emerged as a solution. It was one of the campaign promises for the 2008 municipal elections. The public utility was established in 2009 and implemented in 2010. Since its creation, the cost of water production and management has decreased, and the price of water in Paris is generally lower than in the suburbs, where water is managed by private entities. The public utility Eau de Paris handles water distribution for the entire city of Paris. ', 'Anastasia Guéguen',
  'Paris', 'Paris', 48.8588897, 2.320041,
  'images/Paris_16e_-_Alle_Piltre_de_Rozier_-_Distributeur_Eau_de_Paris.jpg', 'Distributeur Eau de Paris, 16e arrondissement, 13/08/23, Romainbehard, Wikimedia Commons, https://commons.wikimedia.org/wiki/File:Paris_16e_-_All%C3%A9e_Pil%C3%A2tre_de_Rozier_-_Distributeur_Eau_de_Paris.jpg', 'https://reporterre.net/Comment-Paris-a-repris-le-controle-de-la-gestion-de-l-eau', '2026-04-01', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1775051231398', 'h2o');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1775051231398', 'politique-publique');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1775051231398', 'gouvernance-de-leau');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1775051247495', 'La quantité d’eau sur Terre', 'The Amount of Water on Earth', '2012',
  'Cette représentation de la Terre avec ces trois gouttes d’eau a été créée en 2012 par Howard Perlman, de l’Institut d’études géologiques des Etats Unis, Jack Cook de l’institut océanographique de Woods Hole et Adam Nieman et à l’aide de données de l’hydrologue russe Igor Shiklomanov. La première sphère, d''un diamètre 1 385 km et d''un volume d''1,38 milliards de km3, représente toute l’eau présente sur Terre. La seconde, d''un diamètre de 272,8 km, représente la quantité d’eau douce. Enfin, la dernière, d''un diamètre de 56,2 km, représente la quantité d’eau douce de surface (rivières et lacs). Cette représentation permet de se rendre compte du caractère rare et précieux de l’eau douce et, ainsi, de l’importance de protéger la ressource. \n', 'This representation of Earth as three drops of water was created in 2012 by Howard Perlman of the U.S. Geological Survey, Jack Cook of the Woods Hole Oceanographic Institution, and Adam Nieman, using data from Russian hydrologist Igor Shiklomanov. The first sphere, with a diameter of 1,385 km and a volume of 1.38 billion km³, represents all the water on Earth. The second, with a diameter of 272.8 km, represents the amount of freshwater. Finally, the last sphere, with a diameter of 56.2 km, represents the amount of surface freshwater (rivers and lakes). This representation helps us appreciate the rarity and preciousness of freshwater and, thus, the importance of protecting this resource. \n', 'Anastasia Guéguen',
  '', '', NULL, NULL,
  'images/quantitdeausurterre.jpg', 'Institut d''études géologique des Etas-Unis, The World''s Water', 'https://www.scientificamerican.com/article/its-a-water-full-world/', '2026-04-01', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1775051247495', 'h2o');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1775051247495', 'imaginaire');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1775051258845', 'Projet de transformation d’un château d’eau en pile thermique', 'Project to convert a water tower into a thermal storage facility', '2008',
  'À Montreuil, le château d’eau Bel Air, construit en 1936, n’est plus exploité par le Syndicat des eaux d''île de France depuis 2004 par manque de rentabilité. En 2008, la municipalité lance un appel à projets pour étudier les possibilités de valorisation sociale et environnementale du château d’eau. Un des projets qui a retenu le plus d’attention est celui de la conversion de l’édifice en une pile thermique permettant de chauffer une partie des bâtiments du quartier. En effet, le château d’eau a une grande capacité de stockage d’eau et une bonne inertie thermique. L’installation de panneaux solaires aurait permis de faire chauffer l’eau et l’installation d’une boucle de circulation d’eau chaude aurait permis de chauffer une quarantaine de logements. Le projet aurait permis d’économiser 75 tonnes de CO2 par an, mais il n’a jamais abouti. \n', 'In Montreuil, the Bel Air water tower, built in 1936, has not been operated by the Île-de-France Water Authority since 2004 due to a lack of profitability. In 2008, the municipality launched a call for proposals to explore options for the social and environmental repurposing of the water tower. One of the projects that garnered the most attention was the conversion of the structure into a thermal storage system capable of heating some of the neighborhood’s buildings. Indeed, the water tower has a large water storage capacity and good thermal inertia. Installing solar panels would have heated the water, and installing a hot water circulation loop would have heated about forty homes. The project would have saved 75 tons of CO2 per year, but it never came to fruition. \n', 'Anastasia Guéguen',
  'Montreuil', 'Montreuil', 50.4638918, 1.7631125,
  'images/pile_thermique.avif', 'Evolution de la température de l''eau au fil de l''année avec le projet de pile thermique, https://www.lemoniteur.fr/article/un-vieux-chateau-d-eau-pourrait-se-transformer-en-pile-thermique.1961924', 'https://www.lemoniteur.fr/article/un-vieux-chateau-d-eau-pourrait-se-transformer-en-pile-thermique.1961924', '2026-04-01', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1775051258845', 'h2o');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1775051258845', 'solaire');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1775051273151', 'MycelioTronics, des puces électroniques à base de champignons', 'MycelioTronics: Microchips Made from Mushrooms', '2022',
  'Les puces électroniques, que l’on retrouve dans énormément d’appareils de notre quotidien, sont composés d’un circuit électronique et d’un substrat, un matériau isolant et refroidissant, très souvent en plastique. Cependant, les chercheurs de l’Université Johannes Kepler de Linz en Autriche ont publié dans la revue Science Advances leurs recherches concernant la création de puces électroniques en utilisant un champignon. Leur matériau, baptisé MycelioTronics, est composé de la peau du champignon Ganoderma lucidum déshydratée. Les puces ainsi créées peuvent résister à la température de 200 °C et, à l''abri de l’humidité et des rayons UV, peuvent durer plusieurs décennies. Elles sont donc tout à fait capables de résister tout au long de la durée de vie de l’appareil. De plus, d’après des tests réalisés par les chercheurs, les puces ainsi réalisées sont presque aussi efficaces que les puces en plastique. Lorsqu’on l’a décidé, les puces se dégradent en deux semaines. ', 'Microchips, which are found in countless everyday devices, consist of an electronic circuit and a substrate—an insulating and heat-dissipating material, most often plastic. However, researchers at Johannes Kepler University in Linz, Austria, have published their findings in the journal *Science Advances* regarding the creation of microchips using a fungus. Their material, called MycelioTronics, is made from the dehydrated skin of the Ganoderma lucidum mushroom. The chips created in this way can withstand temperatures of 200 °C and, when protected from moisture and UV rays, can last for several decades. They are therefore fully capable of lasting for the entire lifespan of the device. Furthermore, according to tests conducted by the researchers, the chips made this way are nearly as effective as plastic chips. When the time comes, the chips degrade within two weeks. ', 'Anastasia Guéguen',
  'Linz', 'Linz', 48.3059078, 14.286198,
  'images/Ganoderma_lucidum_87540961.jpg', 'Ganoderma lucidum, 31/07/20, Tatiana, Wikimedia Commons, https://commons.wikimedia.org/wiki/File:Ganoderma_lucidum_87540961.jpg', 'https://trustmyscience.com/puce-electronique-peau-champignon/', '2026-04-01', 'published', 1, '2026-04-08 11:08:24', '2026-04-08 11:08:24'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1775051273151', 'technologie');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1775051273151', 'electricite');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1775051273151', 'electronique');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1775051273151', 'numerique');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1775051287012', 'Les Waru Waru', 'The Waru Waru', '300 av. J.-C.',
  'Les Waru Waru sont des techniques d’agriculture préhispanique sur les plateaux andins. Cette technique d’agriculture consiste en une alternance de canaux d’un mètre de profondeur et de plateformes qui reçoivent les semis. Les Waru Waru (terme qui provient du Quechua et signifie “litière”) sont installés préférentiellement dans les plaines alluviales, c’est-à-dire proche des rivières et susceptibles d’être inondées. Cette technique agricole rend les cultures moins sensibles à la sécheresse et au gel. En cas de fortes pluies, les cultures ne peuvent pas être inondées puisqu''un système draine l’eau dans la rivière. Les Waru Waru permettent au sol de s’oxygéner et de s’enrichir grâce à la présence de plantes aquatiques/ petits animaux. Ils avaient été délaissés par l''empire Inca (XVe siècle) mais ont commencé à être reconstruits dans les années 1990. ', 'Waru Waru refers to pre-Hispanic farming techniques used on the Andean plateaus. This farming method involves alternating one-meter-deep channels with raised platforms where seeds are planted. Waru Waru (a term derived from Quechua meaning “litter”) are typically established in alluvial plains, that is, near rivers and prone to flooding. This agricultural technique makes crops less susceptible to drought and frost. In the event of heavy rains, the crops cannot be flooded because a drainage system directs the water into the river. Waru Waru allow the soil to be oxygenated and enriched thanks to the presence of aquatic plants and small animals. They were abandoned by the Inca Empire (15th century) but began to be reconstructed in the 1990s. ', 'Raphaël Luciani-Galais',
  'Pérou', 'Peru', -6.8699697, -75.0458515,
  'images/waruwaru.avif', 'champ à Waru Waru dans l''altiplano péruvien, https://www.wmf.org/monuments/waru-waru-agricultural-fields-peru', 'https://www.geo.fr/environnement/les-waru-waru-technique-agricole-andine-contre-la-crise-climatique-218762', '2026-04-01', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1775051287012', 'h2o');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1775051287012', 'agriculture');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1775051287012', 'conservation-alimentaire');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1775051300678', 'La méthode SODIS', 'The SODIS Method', '1980-1990',
  'La méthode SODIS (solar water disinfection) a été développée dans les années 1980 par l’Institut fédéral suisse pour l’aménagement, l’épuration et la protection des eaux. Le principe est simple : les rayons UV ont la capacité de désinfecter l’eau et de la rendre potable. Dans les pays dans lesquels l’accès à l''eau potable est compliqué, la méthode est utilisée pour éviter les maladies diarrhéiques telles que la dysenterie ou le choléra. De l’eau claire, préférentiellement de pluie, est placée dans des bouteilles en plastique sans étiquette. Ces bouteilles sont ensuite placées à l''horizontale sur un support en métal ou réfléchissant pendant minimum 6 h. Les rayons du soleil tuent les bactéries, virus et parasites et rendent l’eau potable. Cette méthode est recommandée par les Institutions internationales telles que l’OMS. Elle a, par exemple, été utilisée en Indonésie après le tsunami de décembre 2004. Cette méthode ne permet pas, cependant, de traiter les pollutions chimiques. \n', 'The SODIS method (solar water disinfection) was developed in the 1980s by the Swiss Federal Institute for Water, Wastewater and Protection. The principle is simple: UV rays can disinfect water and make it safe to drink. In countries where access to safe drinking water is limited, this method is used to prevent diarrheal diseases such as dysentery or cholera. Clear water, preferably rainwater, is placed in unlabeled plastic bottles. These bottles are then laid flat on a metal or reflective surface for at least 6 hours. The sun’s rays kill bacteria, viruses, and parasites, making the water safe to drink. This method is recommended by international organizations such as the WHO. It was, for example, used in Indonesia following the December 2004 tsunami. However, this method cannot treat chemical contamination. \n', 'Loïc Rogard',
  '', '', NULL, NULL,
  'images/Indonesia-sodis-gross.jpg', 'Méthode SODIS utilisée en Indonésie, SODIS Eawag, Wikimedia Commons, https://commons.wikimedia.org/wiki/File:Indonesia-sodis-gross.jpg', 'https://www.nouvelobs.com/rue89/rue89-monde/20101129.RUE9664/la-desinfection-solaire-de-l-eau-pour-freiner-le-cholera.html', '2026-04-01', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1775051300678', 'sante');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1775051300678', 'h2o');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1775051317011', 'La forêt comestible de Fabrice Desjours', 'Fabrice Desjours'' Edible Forest', '2010',
  'Suite à des voyages, notamment dans les Comores, Fabrice Desjours a observé la pratique traditionnelle de l’agroforesterie. En revenant en France, il a acquis un terrain de 2,5 hectares dans la commune de Diconne en Saône-et-Loire et a commencé à planter diverses espèces de noix, fruits, légumes, champignons ou encore fleurs. Aujourd’hui, sa “forêt gourmande” compte plus de 1 000 espèces comestibles, pas d’irrigation ni de traitement. La forêt s’autogère. Les espèces plantées dans la forêt de Fabrice Desjours sont à la fois locales et exotiques, l’objectif étant qu’elle puisse s’adapter aux changements climatiques. Fabrice Desjours a été l’un des premiers en France à remettre au goût du jour cette pratique tombée en désuétude depuis la Révolution, prouvant que l’adaptation au changement climatique passe parfois par le recours à des savoirs anciens. \n', 'After traveling, particularly to the Comoros, Fabrice Desjours observed traditional agroforestry practices. Upon returning to France, he purchased a 2.5-hectare plot of land in the town of Diconne in Saône-et-Loire and began planting various species of nuts, fruits, vegetables, mushrooms, and flowers. Today, his “gourmet forest” is home to over 1,000 edible species, with no irrigation or treatment. The forest manages itself. The species planted in Fabrice Desjours’ forest are both local and exotic, with the goal of ensuring it can adapt to climate change. Fabrice Desjours was one of the first in France to revive this practice, which had fallen into disuse since the Revolution, proving that adapting to climate change sometimes requires drawing on ancient knowledge. \n', 'Somhack Limphakdy',
  'Diconne', 'They say', 46.7746376, 5.1347379,
  'images/foret-gourmande-3-2.jpg', 'Fabrice Desjours dans sa forêt gourmande, 2025, Xavier Ducordeaux, https://www.bourgognefranchecomte.fr/index.php/quand-la-foret-devient-gourmande', 'https://france3-regions.franceinfo.fr/bourgogne-franche-comte/saone-et-loire/la-foret-gourmande-quand-la-saone-et-loire-devient-un-modele-de-lutte-contre-le-rechauffement-climatique-2911625.html', '2026-04-01', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1775051317011', 'agriculture');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1775051317011', 'conservation-alimentaire');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1775051327641', 'Les yakhtchals', 'The Yakhtchals', 'IV siècle av. J.-C.',
  'Les yakhtchals sont des glacières qui étaient présentes dans tout l’Iran, là où les températures en hiver permettaient la congélation de l’eau. Des petits bassins, alimentés par des qanats (canaux),  pouvaient servir à former de la glace en hiver, qui étaient ensuite prélevée et placée dans les yakhtchals, des constructions en forme de dômes semi-enterrés. Ces constructions étaient enduites d’un mélange de boue, blancs d''œufs ou encore poils d’animaux pour en assurer l’isolation. La glace était utilisée pour conserver des aliments et boissons, et sans doute aussi occasionnellement pour refroidir des bâtiments. \n', 'Yakhtchals are icehouses that were found throughout Iran, in areas where winter temperatures allowed water to freeze. Small ponds, fed by qanats (canals), could be used to form ice in the winter, which was then harvested and placed in the yakhtchals, semi-underground dome-shaped structures. These structures were coated with a mixture of mud, egg whites, or animal hair to ensure insulation. The ice was used to preserve food and beverages, and likely also occasionally to cool buildings. \n', 'Raphaël Luciani-Galais',
  'Iran', 'I ran', 32.6475314, 54.5643516,
  'images/Yakhchal_of_Yazd_province.jpg', 'yakhtchal de la province de Yazd en Iran, 25/09/08, Pastaitaken, Wikimedia Commons, https://commons.wikimedia.org/wiki/File:Yakhchal_of_Yazd_province.jpg', 'https://www.stonybrook.edu/commcms/nacil/Iran/architecture/yakhchaal.php', '2026-04-01', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
