INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1775051341769', 'Le parking en architecture réversible de la ZAC Nouveau Saint-Roch', 'The Reversible Parking Structure in the Nouveau Saint-Roch Development Zone', '2015',
  'À Montpellier, un parking en silo pense déjà à la ville de demain. Le parking construit dans la ZAC Nouveau Saint-Roch a été construit selon les principes de l’architecture réversible afin de s’adapter à un avenir sans voiture. Ce parking, qui compte 800 places de stationnement, a une hauteur sous plafond de 2,60 à 3 m, contre 2,20 m requis. Les planchers sont pensés de telle façon que des gaines techniques peuvent être ajoutée au besoin. L’enveloppe extérieure peut également être retirée facilement. Le parking est donc construit de manière à pouvoir être transformé selon les besoins (bureaux, logements, etc.). Il permet d’envisager un avenir sans voiture à Montpellier. ', 'In Montpellier, a multi-story parking garage is already looking ahead to the city of tomorrow. The parking garage, built in the Nouveau Saint-Roch development zone, was designed according to the principles of reversible architecture to adapt to a car-free future. This garage, which has 800 parking spaces, features ceiling heights ranging from 2.60 to 3 meters, compared to the required 2.20 meters. The floors are designed so that utility shafts can be added as needed. The exterior envelope can also be easily removed. The parking garage is therefore built in such a way that it can be converted as needed (into offices, housing, etc.). It makes it possible to envision a car-free future in Montpellier. ', 'Anastasia Guéguen',
  'Montpellier', 'Montpellier', 43.6112422, 3.8767337,
  'images/Montpellier_-_Parking_Saint-Roch_29247787924.jpg', 'Parking Saint-Roch, Montpellier, 26/03/16, Fred Romero, Wikimedia Commons, https://commons.wikimedia.org/wiki/File:Montpellier_-_Parking_Saint-Roch_(29247787924).jpg', 'https://www.amc-archi.com/photos/archikubik-realise-un-parking-silo-transformable-a-montpellier,9166/parking-silo-transformable-a.1', '2026-04-01', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1775051341769', 'deplacement');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1775051341769', 'construction');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1775051355697', 'Le système agricole de Lanzarote', 'The Agricultural System of Lanzarote', 'XVIII siècle',
  'Entre 1730 et 1736 l’île espagnole de Lanzarote subit une série d’éruptions volcaniques. Ces volcans ont rejeté une grande quantité de cendres qui restent aujourd’hui très présentes dans les sols de l’île. Une dizaine d’années après les éruptions, une sécheresse a commencé et perdure depuis. Cependant, les habitants n’ont pas déserté l’île pour autant. Ils ont, au fil des décennies, développé des techniques leur permettant de continuer à cultiver malgré les conditions difficiles. Plusieurs méthodes, caractéristiques à l’île, existent. Par exemple, les cendres volcaniques peuvent être utilisées comme paillage et permettent de garder l’humidité dans le sol et de les enrichir de minéraux essentiels. On appelle cette technique “enarenado”. Un paillage peut également être réalisé à partir de sables très fins apportés de l’Atlantique par les vents. Les pierres volcaniques sont également utilisées pour construire des murets, les “zocos”, qui protègent les vignes des vents. Lanzarote peut ainsi produire du vin, des fruits, des céréales et des légumineuses sans irrigation dans cette région pourtant très sèche. ', 'Between 1730 and 1736, the Spanish island of Lanzarote experienced a series of volcanic eruptions. These volcanoes spewed a large amount of ash, which remains deeply embedded in the island’s soil to this day. About a decade after the eruptions, a drought began and has persisted ever since. However, the inhabitants did not abandon the island. Over the decades, they developed techniques that allowed them to continue farming despite the difficult conditions. Several methods, unique to the island, exist. For example, volcanic ash can be used as mulch, helping to retain moisture in the soil and enrich it with essential minerals. This technique is called “enarenado.” Mulch can also be made from very fine sand carried in from the Atlantic by the winds. Volcanic stones are also used to build low walls, known as “zocos,” which protect the vines from the wind. Lanzarote is thus able to produce wine, fruit, grains, and legumes without irrigation in this otherwise very dry region. ', 'Anastasia Guéguen',
  'Lanzarote', 'Lanzarote', 29.0397081, -13.6362916,
  'images/_Besuch_der_Bodega_La_Geria._01.jpg', 'Vignobles à Lanzarote, 16/03/22, Holger Uwe Schmitt, Wikimedia Commons, https://commons.wikimedia.org/wiki/File:%2B_Besuch_der_Bodega_La_Geria._01.jpg', 'https://www.fao.org/newsroom/story/lanzarotes-volcanic-miracle/fr', '2026-04-01', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1775051355697', 'agriculture');
