INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1775051373180', 'Vera da pozzo', 'Vera da Pozzo', 'XIV siècle',
  'Pendant plusieurs siècles, jusqu’à la construction d’un aqueduc au XIXe siècle, la ville de Venise reposait sur ses puits pour l’alimentation en eau potable. Le terme “vera da pozzo” désigne un type de citerne souterraine, typiquement vénitienne. L’eau stockée provient de la pluie. Elle est traitée en étant filtrée par une couche de sable et de graviers présents dans la citerne. Les parois de cette dernière sont en argile imperméable. Les vera da pozzo sont souvent surélevées pour éviter les infiltrations d’eau de mer lors des phénomènes de submersion marine.', 'For several centuries, until the construction of an aqueduct in the 19th century, the city of Venice relied on its wells for its drinking water supply. The term “vera da pozzo” refers to a type of underground cistern that is typical of Venice. The stored water comes from rain. It is treated by being filtered through a layer of sand and gravel inside the cistern. The walls of the cistern are made of impermeable clay. Vera da pozzo are often elevated to prevent seawater from seeping in during tidal flooding.', 'Anastasia Guéguen',
  'Venise', 'Venice', 45.4371908, 12.3345898,
  'images/Campo_San_Boldo_Venice.jpg', 'Campo San Boldo, Venise, 30/05/16, Didier Descouens, Wikimedia Commons, https://commons.wikimedia.org/wiki/File:Campo_San_Boldo_(Venice).jpg', 'https://www.venise-serenissime.com/planinteractif/puits_venise/puits_venise2.htm', '2026-04-01', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1775051373180', 'h2o');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1775140024087', 'les puquios', 'puquios', 'V siècle',
  'Les puquios sont des systèmes d’aqueducs souterrains, similaires au système des qanats en Iran. Ils ont été mis en place par la civilisation Nazca, au Pérou. Les puquios permettaient d’amener de l’eau depuis des sources situées dans les montagnes vers les régions les plus arides pour irriguer les cultures. Deux types de canaux existent : des fossés recouverts de pierres et des galeries souterraines enterrées de 10 à 15 m. On retrouve également le long de ces galeries des puits en spirales pouvant atteindre jusqu’à 15 m de diamètre, les ojos. Ces derniers servaient de puits, d''accès aux canaux souterrains pour l’entretien et le nettoyage, mais permettait également au vent de s’engouffrer et ainsi de faire circuler l’eau avec plus de puissance. \n', 'Puquios are underground aqueduct systems, similar to the qanat system in Iran. They were built by the Nazca civilization in Peru. Puquios were used to bring water from mountain springs to the driest regions to irrigate crops. There are two types of channels: stone-lined ditches and underground tunnels buried 10 to 15 meters deep. Along these tunnels, there are also spiral wells up to 15 meters in diameter, known as ojos. These served as wells and provided access to the underground channels for maintenance and cleaning, but they also allowed wind to rush in, thereby circulating the water with greater force. \n', 'Anastasia Guéguen',
  'Pérou', 'Peru', -6.8699697, -75.0458515,
  'images/Acueductos_subterrneos_de_Cantalloc_Nazca_Per_2015-07-29_DD_09.jpg', '"Ojo" d''un des puquios de Cantalloc, Nasca, Pérou, 29/0715, Diego Delso, Wikimedia Commons, https://commons.wikimedia.org/wiki/File:Acueductos_subterr%C3%A1neos_de_Cantalloc,_Nazca,_Per%C3%BA,_2015-07-29,_DD_09.JPG', 'https://www.atlasobscura.com/places/puquios', '2026-04-02', 'published', 1, '2026-04-02 13:58:43', '2026-04-02 13:58:43'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1775140024087', 'h2o');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1775141095090', 'Le kit de rénovation THERMECO', 'The THERMECO Renovation Kit', '2026',
  'L’entreprise Enertech lance un kit permettant de réduire sa consommation d’énergie par 30 %. Le kit contient une jaquette d’isolation pour chauffe-eau, d’un thermostat qui s’installent en complément du thermostat existant, de mousseurs pour les principaux points de puisage et d’un guide éco-gestes. La jaquette du chauffe-eau permet à ce dernier de conserver une partie de sa chaleur et, ainsi, de dépenser moins d’énergie. Le thermostat est volontairement low-tech, sans fonctions smart ou connectées, là encore pour économiser de l’énergie. Pour le moment, ce kit n’est pas accessible à un particulier seul (minimum 8 kits par commande), ce qui sera le cas à terme.  ', 'Enertech is launching a kit designed to reduce energy consumption by 30%. The kit includes an insulation cover for water heaters, a thermostat that is installed alongside the existing thermostat, aerators for the main faucets, and a guide to energy-saving habits. The water heater cover helps the heater retain some of its heat, thereby reducing energy consumption. The thermostat is intentionally low-tech, with no smart or connected features, again to save energy. For now, this kit is not available to individual consumers (minimum order of 8 kits), though it will be in the future.  ', 'Cédric Carles',
  'France', 'France', 46.603354, 1.8883335,
  'images/thermeco.png', 'Jaquette de chauffe-eau THERMECO, https://www.enertech.fr/lancement-du-kit-de-renovation-pour-cumulus-electrique-thermeco/', 'https://www.enertech.fr/lancement-du-kit-de-renovation-pour-cumulus-electrique-thermeco/', '2026-04-02', 'published', 1, '2026-04-03 09:13:15', '2026-04-03 09:13:15'
);
