INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1775211484796', 'Création de la start-up Equium', 'Launch of the startup Equium', '2017',
  'Equium est une start-up française travaillant sur la thermoacoustique. Son objectif est de réaliser un système de pompe à chaleur écologique, sans fluide frigorigène et sans gaz réfrigérant nocifs. Le principe est d''utiliser des ondes sonores pour réchauffer et refroidir un gaz, ici l''hélium qui a été choisi pour son caractère non-inflammable. La chaleur et la fraîcheur générées par ces ondes sonores, qui sont produites à l’intérieur d’un tube fermé, sont ensuite récupérées et peuvent être utilisées pour réchauffer/ refroidir un logement. Une pompe à chaleur thermoacoustique consommerait moins d’énergie qu’une pompe à chaleur traditionnelle, et serait donc plus écologique et économique. De plus, une pompe à chaleur thermoacoustique ne dépendrait pas de la température extérieure pour fonctionner, contrairement à la solution classique qui consomme davantage lorsque les températures baissent. Les pompes thermoacoustiques ont donc une capacité à fonctionner dans des environnements extrêmes. Pour l’heure, la pompe Equium est en cours de développement, pour une commercialisation peut-être courant 2026.', 'Equium is a French startup working in the field of thermoacoustics. Its goal is to develop an eco-friendly heat pump system that uses no refrigerants or harmful cooling gases. The principle involves using sound waves to heat and cool a gas—in this case, helium, which was chosen for its non-flammable properties. The heat and cooling generated by these sound waves, which are produced inside a closed tube, are then recovered and can be used to heat or cool a home. A thermoacoustic heat pump would consume less energy than a traditional heat pump, making it both more eco-friendly and cost-effective. Furthermore, a thermoacoustic heat pump would not depend on outdoor temperatures to operate, unlike conventional systems, which consume more energy as temperatures drop. Thermoacoustic heat pumps are therefore capable of operating in extreme environments. Currently, the Equium pump is under development, with a potential launch in 2026.', 'Cédric Carles',
  'France', 'France', 46.603354, 1.8883335,
  'images/equium.jpeg', 'Cédric François, fondateur d''Equium et l''une de ses pompes à chaleur, 2024, DR, Ouest France, https://www.ouest-france.fr/economie/entreprises/lentreprise-nantaise-equium-invente-la-pompe-a-chaleur-acoustique-qui-carbure-au-son-adac136a-c4ff-11ee-9c4f-9be0695f50c2', 'https://www.axiclim.fr/pompe-a-chaleur-thermo-acoustique/', '2026-04-03', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1775211484796', 'rechauffer');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1775211484796', 'rafraichir');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1775211929841', 'Les stupas de glace', 'The Ice Stupas', '2014',
  '\nLes stupas de glaces, sorte de petits glaciers artificiels, ont été inventés par l’ingénieur indien Sonam Wangchuk en 2014. Ces glaciers répondent à un problème que rencontre la région indienne du Ladakh, situé dans l''himalaya. Cette dernière reçoit très peu de précipitations et il existe peu de nappes phréatiques. L’eau, nécessaire à la vie des habitants et à l''agriculture, vient essentiellement de l’eau de fonte des glaciers au printemps. Cependant, à cause du réchauffement climatique, les glaciers commencent à fondre dès la fin de l’hiver et les réserves sont déjà bien entamées quand la saison des plantations arrive. L’idée du stupa de glace est de détourner l’eau de petites rivières, de les relier à des canalisations souterraines et de les faire jaillir en contrebas. L’eau gèle instantanément sur une structure en bois conique, limitant son exposition au soleil et ralentissant sa fonte. L’eau fond lentement au printemps et peut alimenter les cultures. Les stupas tirent leur nom de l’architecture boudhiste : leur forme est similaire à celle de certains temples. Le premier stupa de glace a été inauguré en 2015 dans la vallée de Phyang. \n\n', '\nIce stupas, a type of small artificial glacier, were invented by Indian engineer Sonam Wangchuk in 2014. These glaciers address a problem faced by the Indian region of Ladakh, located in the Himalayas. The region receives very little rainfall and has few groundwater sources. The water, essential for the inhabitants’ livelihoods and agriculture, comes mainly from glacial meltwater in the spring. However, due to global warming, the glaciers begin to melt as early as the end of winter, and reserves are already significantly depleted by the time the planting season arrives. The idea behind the ice stupa is to divert water from small rivers, connect them to underground pipes, and have the water flow out below. The water freezes instantly on a conical wooden structure, limiting its exposure to the sun and slowing its melting. The water melts slowly in the spring and can irrigate crops. The stupas take their name from Buddhist architecture: their shape is similar to that of certain temples. The first ice stupa was inaugurated in 2015 in the Phyang Valley. \n\n', 'Raphaël Luciani-Galais',
  'Ladakh', 'Land of the Lads', 33.9456407, 77.6568576,
  'images/Ice-Stupaa.jpg', 'Etudiants de HIAL (Himalayan Institute of Alternatives, Ladakh) devant leur projet de stupa de glace, 19/10/21, Crb43, Wikimedia Commons, https://commons.wikimedia.org/wiki/File:Ice-Stupaa.jpg', 'https://www.geo.fr/environnement/ladakh-les-stupas-de-glace-une-idee-de-genie-pour-reboiser-la-montagne-178734', '2026-04-03', 'published', 1, '2026-04-03 10:25:29', '2026-04-03 10:25:29'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1775211929841', 'agriculture');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1775211929841', 'h2o');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1775654182495', 'Le packet radio', 'Le packet radio', '1978',
  'Le packet radio est un système de transmission de données numériques par ondes radio. Les informations sont découpées en petits “paquets” et transitent sur les ondes radio, sans fil. Ce type de communication permet d''envoyer des fichiers textuels, des coordonnées GPS ou encore des petits fichiers. Par le passé, le packet radio a pu être utilisé dans le cas de situation de crise pour faire transiter des informations sans surcharger les réseaux vocaux pour les secours. ', 'Packet radio is a system for transmitting digital data via radio waves. Information is divided into small “packets” and transmitted wirelessly via radio waves. This type of communication allows users to send text files, GPS coordinates, or small files. In the past, packet radio has been used in crisis situations to transmit information without overloading voice networks intended for emergency services. ', 'Raphaël Luciani-Galais',
  '', '', NULL, NULL,
  'images/Tnc2400-stardado.jpg', 'Terminal Node Controller 2400, 27/12/05, Denis Apel, Wikimedia Commons, https://commons.wikimedia.org/wiki/File:Tnc2400-stardado.JPG', 'https://www.radioamateurs-france.fr/wp-content/uploads/MODES-NUMERIQUES.pdf', '2026-04-08', 'published', 1, '2026-04-08 13:16:22', '2026-04-08 13:16:22'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1775654182495', 'technologie');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1775654182495', 'numerique');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1775731098880', 'Le Garoé', 'Le Garoé', 'XV siècle',
  'Le Garoé est un arbre de l’espèce Ocotea foetens, endémique des îles Canaries, qui était vénéré sur l’île d’El Hierro par les aborigènes Guanches. Cet arbre, planté dans une reculée, avait la particularité de collecter les gouttelettes d’eau sur son feuillage. Les habitants de l’île avaient construit des aménagements pour récupérer plus facilement l’eau. Les premières mentions du Garoé apparaissent au XVe siècle, à la conquête de l’île par les Espagnols. Le Garoé est déraciné en 1610 par une tempête, puis replanté en 1948 au même emplacement. Cet arbre est un peu l’ancêtre des filets capteurs de brouillard.\n', 'The Garoé is a tree of the species Ocotea foetens, native to the Canary Islands, which was revered on the island of El Hierro by the indigenous Guanches. This tree, planted in a remote valley, had the unique ability to collect water droplets on its foliage. The island’s inhabitants had built structures to make it easier to collect the water. The first mentions of the Garoé appear in the 15th century, during the Spanish conquest of the island. The Garoé was uprooted in 1610 by a storm, then replanted in 1948 at the same location. This tree is somewhat of a precursor to fog-collecting nets.\n', 'Anastasia Guéguen',
  'El Hierro', 'El Hierro', 27.7435084, -18.0381796,
  'images/Arbre_de_lIsle_de_Fer_Description_de_lUnivers_t._3_pl._82.jpg', 'L''arbre de l''isle de fer, Allain Manesson Mallet, Description de l''Univers, t. 3, Paris, Denys Thierry, 1683 https://commons.wikimedia.org/wiki/File:Arbre_de_l%27Isle_de_Fer_(Description_de_l%27Univers,_t._3,_pl._82).jpg', 'https://horizon.documentation.ird.fr/exl-doc/pleins_textes/ed-06-08/010044510.pdf', '2026-04-09', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1775731098880', 'h2o');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1775731098880', 'imaginaire');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1775731174510', 'Horus.ch, le pionnier du numérique solaire', 'Horus.ch, the pioneer in digital solar technology', '1996',
  'Horus Networks (devenue Horus Energy SA), créé en 1996 dans le canton de Neuchâtel, s’est imposée comme un précurseur mondial de l’informatique durable. Au fil des années, Horus a développé plusieurs services web alimentés par l’énergie solaire. Pour ce faire, Horus a développé ses propres installations photovoltaïques en Suisse. Aujourd’hui, ses 6 centrales produisent plus d''électricité que nécessaire pour alimenter tous ses services web, Horus est donc devenu également un producteur d’énergie renouvelable. Les différents services proposés vont de l’hébergement de site web (EcoWeb) aux services de messagerie (EcoMail et EcoSms) par exemple. La web-radio solar sound system est herbergé chez Horus.', 'Horus Networks (now Horus Energy SA), founded in 1996 in the canton of Neuchâtel, has established itself as a global pioneer in sustainable IT. Over the years, Horus has developed several web services powered by solar energy. To achieve this, Horus has built its own solar power facilities in Switzerland. Today, its six power plants generate more electricity than is needed to power all of its web services, so Horus has also become a producer of renewable energy. The various services offered range from website hosting (EcoWeb) to messaging services (EcoMail and EcoSms), for example. The Solar Sound System web radio is hosted by Horus.', 'Cédric Carles',
  'Suisse', 'Switzerland', 46.7985624, 8.2319736,
  'images/horus.ch-960px.png', 'Fonctionnement du serveur e-mail Horus, https://www.horus.ch/comment-ca-fonctionne/', 'https://www.horus.ch/2025/08/de-horus-networks-a-horus-energy-sa-un-nouveau-nom-la-meme-energie-solaire/', '2026-04-08', 'published', 1, '2026-04-08 11:04:43', '2026-04-08 11:04:43'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1775731174510', 'solaire');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1775731174510', 'electricite');
