INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1775746321439', 'Workshop « AI Action II : Decompression in the Latent Space »', 'Workshop « AI Action II : Decompression in the Latent Space »', '2025',
  'En février 2025, le château de Feÿ (Yonne) a accueilli l’atelier « AI Action II : Decompression in the Latent Space ». Ce dernier a rassemblé des experts de la tech, de l’enseignement supérieur et de la société civile pour discuter des enjeux de l’IA responsable. Cet atelier a abordé des thèmes tels que la gestion responsable des données d’entraînement de l’IA, la transformation des savoirs liée à l’IA ou encore les implications de l’autonomie de l’IA. Organisé après le Sommet IA Action à Paris, ce rassemblement met également l’accent sur les droits et la gestion des risques qui apparaissent avec cette nouvelle technologie. ', 'In February 2025, the Château de Feÿ (Yonne) hosted the workshop “AI Action II: Decompression in the Latent Space.” The event brought together experts from the tech industry, higher education, and civil society to discuss the challenges of responsible AI. The workshop addressed topics such as the responsible management of AI training data, the transformation of knowledge related to AI, and the implications of AI autonomy. Organized following the AI Action Summit in Paris, this gathering also emphasized the rights and risk management issues arising from this new technology. ', 'Cédric Carles',
  'Villecien', 'Villecien', 48.0056204, 3.3279296,
  'images/Chteau_du_Fey-FR-89-chteau-01.jpg', 'Château du Fey, 21/04/17, François Goglins, Wikimedia Commons, https://commons.wikimedia.org/wiki/File:Ch%C3%A2teau_du_Fey-FR-89-ch%C3%A2teau-01.jpg', 'https://medium.com/@alien.papers/ai-action-ii-workshop-at-chateau-du-fey-89cde086ccf8', '2026-04-09', 'published', 1, '2026-04-09 14:52:01', '2026-04-09 14:52:01'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1775746321439', 'numerique');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1775815624560', 'Jerry Do-It-Together', 'Jerry Do-It-Together  (Proposition)', '2011',
  'Le projet a été créé par Xavier Auffret, Laure Guillou et Chemsedine Herriche et a été primé lors du challenge HumaniTech en 2011. “Jerry Do-it-Together” est un ordinateur PC qui a la particularité d’être construit avec du matériel de réemploi, notamment un bidon en plastique de 20 litres (jerrycan en anglais). Ces ordinateurs sont assemblés en groupe, lors d’ateliers participatifs qui permettent de créer du lien. Les bidons, qui contiennent les composantes informatiques de réemploi, sont refermés avec des fermetures éclair pour permettre de mieux comprendre l’organisation de l''ordinateur. Les Jerry-Do-it-Together peuvent être décorés selon le bon vouloir des constructeurs. Ces ordinateurs ont été pensés pour réduire la fracture numérique, notamment dans certains pays dits “en développement”. \n', 'The project was created by Xavier Auffret, Laure Guillou, and Chemsedine Herriche and won an award at the HumaniTech Challenge in 2011. “Jerry Do-it-Together” is a PC that is unique in that it is built using reused materials, specifically a 20-liter plastic container (a “jerrycan”). These computers are assembled in groups during participatory workshops that help build connections. The jerrycans, which contain the reused computer components, are sealed with zippers to help users better understand the computer’s internal layout. Jerry-Do-it-Together computers can be decorated however the builders choose. These computers were designed to bridge the digital divide, particularly in certain so-called “developing” countries. \n', 'Raphaël Luciani-Galais',
  '', '', NULL, NULL,
  'images/Un__Mignon__Jerry-can..jpg', 'Jerrys au FacLab de Gennevilliers, 06/04/14, Vallade, Wikimedia Commons, https://commons.wikimedia.org/wiki/File:Un_%22Mignon%22_Jerry-can..JPG', 'https://hardware.developpez.com/actu/100150/Jerry-Do-It-Together-une-solution-ingenieuse-pour-reprendre-la-main-sur-la-technologie-construire-un-ordinateur-dans-un-bidon-en-plastique/', '2026-04-10', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1775815624560', 'numerique');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1775815636487', 'Qarnot computing', 'Qarnot computing', '2010',
  'Qarnot computing est une entreprise française basée à Montrouge. Elle est spécialisée Cloud HPC (high performance computing), c''est -à -dire dans la fourniture de puissance de calcul informatique de haute performance.  Ces calculs numériques génèrent une grande quantité de chaleur, normalement perdue. Les data centers classiques dépensent beaucoup d’énergie pour refroidir les serveurs informatiques. Qarnot computing, de son côté, réutilisent cette chaleur pour chauffer des logements en développant des chaudières et radiateurs numériques. Cela permet de réduire l’empreinte carbone des calculs informatiques et de chauffer gratuitement des logements pour des personnes parfois en précarité énergétique. ', 'Qarnot Computing is a French company based in Montrouge. It specializes in cloud HPC (high-performance computing), meaning the provision of high-performance computing power. These digital calculations generate a large amount of heat, which is normally wasted. Traditional data centers consume a great deal of energy to cool their servers. Qarnot Computing, on the other hand, reuses this heat to heat homes by developing digital boilers and radiators. This reduces the carbon footprint of computing operations and provides free heating for homes, particularly for those facing energy poverty. ', 'Cédric Carles',
  'Montrouge', 'Montrouge', 48.8188544, 2.3194375,
  'images/qarnot_computing.jpg', 'Paul Benoit, fondateur de Qarnot computing, https://greenfilmshooting.net/blog/en/2016/02/26/heating-with-the-hot-spot/', 'https://numeum.fr/numerique-responsable/actu-informatique-qarnot-computing-solution-calcul-verte/', '2026-04-10', 'published', 1, '2026-04-15 10:21:59', '2026-04-15 10:21:59'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1775815636487', 'numerique');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1775824223761', 'L''encre électronique', 'E-ink', '1997',
  'L’encre électronique, ou E-ink, est un système qui permet d’afficher des textes et des images sur un support semblable au papier, mais tout en ayant la possibilité de changer les choses affichées. C’est, notamment, le système utilisé pour certaines liseuses. Ce système a la particularité de dépenser très peu d’énergie. Contrairement aux écrans d’affichage classique qui nécessitent de l’énergie en continu pour éclairer l’écran, ce “papier électronique” ne dépense de l’énergie que lorsque une page charge. Cela fonctionne avec des microparticules noires et blanches qui sont suspendues dans un liquide contenu dans un film. L’application d’un champ électrique permet de faire remonter, soit des particules noires, soit des particules blanches, pour faire apparaître des textes ou des images. \n', 'E-ink is a system that displays text and images on a paper-like surface while allowing the content to be changed. It is, in particular, the system used in some e-readers. This system is notable for its extremely low energy consumption. Unlike traditional display screens, which require a constant power supply to illuminate the screen, this “electronic paper” only consumes energy when a page is loaded. It works using black and white microparticles suspended in a liquid contained within a film. Applying an electric field causes either black or white particles to rise to the surface, displaying text or images. \n', 'Raphaël Luciani-Galais',
  '', '', NULL, NULL,
  'images/Ereader.jpg', 'Liseuse qui fonctionne avec de l''encre électronique, 31/01/21, 117PXL, Wikimedia Commons, https://commons.wikimedia.org/wiki/File:Ereader.jpg', 'https://www.assured-systems.com/fr/faq/quest-ce-que-la-technologie-de-lencre-electronique/', '2026-04-10', 'published', 1, '2026-04-10 12:30:23', '2026-04-10 12:30:23'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1775824223761', 'numerique');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1775824223761', 'electronique');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1775824223761', 'technologie');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1776074843404', 'Stockage d''informations sur de l''ADN', 'Storing information on DNA', '2012',
  'Le stockage d’informations numériques, réalisé dans des data centers, est très énergivore et génère une grande quantité de chaleur. En 2025, à eux seuls, ils représentent 2 % de la consommation électrique mondiale. Ce problème est d’autant plus important dans un contexte de changement climatique et de développement de l’intelligence artificielle. Face à ces défis, le stockage de données informatiques sur ADN se développe. En 2012, le professeur George Church, d’Harvard, a fait une première démonstration convaincante en encodant un livre. L’ADN synthétique peut contenir une très grande quantité d’informations pour un très petit volume. De plus, l’ADN est également très durable dans le temps du moment qu’il est protégé de l’air et de la lumière. Cette technologie est aujourd’hui mise au point par plusieurs start-ups, en France et à l’étranger, notamment les Etats-Unis. Elle pourrait permettre d’aider à décarboner la filière. \n', 'The storage of digital information in data centers consumes a great deal of energy and generates a large amount of heat. By 2025, data centers alone will account for 2% of global electricity consumption. This problem is all the more significant in the context of climate change and the development of artificial intelligence. In response to these challenges, the storage of computer data on DNA is gaining traction. In 2012, Harvard professor George Church gave a compelling initial demonstration by encoding a book. Synthetic DNA can store a very large amount of information in a very small volume. Furthermore, DNA is also highly durable over time as long as it is protected from air and light. This technology is currently being developed by several startups, both in France and abroad, particularly in the United States. It could help decarbonize the industry. \n', 'Raphaël Madoré',
  '', '', NULL, NULL,
  'images/I-Ilustrim_i_stilizuar_i_ADN-s.jpg', '24/11/25, Ilustratori, Wikimedia Commons, https://commons.wikimedia.org/wiki/File:I-Ilustrim_i_stilizuar_i_ADN-s%C3%AB.png', 'https://www.sorbonne-universite.fr/actualites/le-stockage-des-donnees-sur-ladn-une-technologie-revolutionnaire', '2026-04-13', 'published', 1, '2026-04-13 10:07:23', '2026-04-13 10:07:23'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1776074843404', 'numerique');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1776074843404', 'technologie');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1776074843404', 'biomimetisme');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1776077885106', 'One Laptop Per Child', 'One Laptop Per Child', '2005',
  'Le programme OLPC, one laptop per child (un ordinateur portable par enfant) est un programme et une organisation à but non lucratif né en 2005 à l’initiative de l’architecte Nicholas Negroponte. L’idée était de créer des ordinateurs portables les moins chers possibles (100 dollars) pour pouvoir permettre aux enfants nés dans des milieux défavorisés d’avoir accès à l’information. L’objectif est de réduire la fracture numérique entre les enfants issus de milieux défavorisés et ceux issus de milieux aisés. Le programme a donc lancé une recherche pour créer l’ordinateur au coût le plus bas possible. En 2007, l’ordinateur OLPC XO a été fabriqué. Fin 2007, c’étaient 600 000 ordinateurs qui avaient été distribués et vendus. \n', 'The OLPC (One Laptop per Child) program is a nonprofit initiative and organization founded in 2005 by architect Nicholas Negroponte. The idea was to create laptops as inexpensive as possible (100 dollars) to enable children from disadvantaged backgrounds to access information. The goal is to bridge the digital divide between children from disadvantaged backgrounds and those from affluent backgrounds. The program therefore launched a research effort to create a laptop at the lowest possible cost. In 2007, the OLPC XO laptop was manufactured. By the end of 2007, 600,000 laptops had been distributed and sold. \n', 'Raphaël Luciani-Galais',
  '', '', NULL, NULL,
  'images/XO-Beta1-mikemcgregor-2.jpg', 'Prototype OLPC XO-1, 10/12/06, Mike McGregor, Wikimedia Commons, https://commons.wikimedia.org/wiki/File:XO-Beta1-mikemcgregor-2.jpg', 'https://sid.onlinelibrary.wiley.com/doi/full/10.1002/msid.1552', '2026-04-13', 'published', 1, '2026-04-13 10:58:05', '2026-04-13 10:58:05'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1776077885106', 'numerique');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1776077885106', 'technologie');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1776077885106', 'electronique');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1776080247749', 'Framework computer', 'Framework computer', '2019',
  'Framework computer est une entreprise étasunienne qui a été créée en 2019 et a commercialisé en 2021 son premier ordinateur portable modulable. L’ordinateur est entièrement démontable et personnalisable. Cela permet de pouvoir le réparer en cas de panne d’un des composants, et donc d’allonger sa durée de vie. En outre, 50 % de l’aluminium et 30 % du plastique utilisé par la start-up sont recyclés. Une des meilleures façons de réduire l’impact environnemental du numérique est, en effet, d’allonger la durée de vie des appareils électroniques. ', 'Framework Computer is a U.S. company founded in 2019 that launched its first modular laptop in 2021. The laptop is fully disassemblable and customizable. This makes it possible to repair it if any component fails, thereby extending its lifespan. In addition, 50% of the aluminum and 30% of the plastic used by the startup are recycled. One of the best ways to reduce the environmental impact of digital technology is, in fact, to extend the lifespan of electronic devices. ', 'Raphaël Luciani-Galais',
  '', '', NULL, NULL,
  'images/Framework_laptop_AMD_13_DIY_setup.jpg', 'Framework Laptop DIY 13 AMD, 13/02/24, Thcipriani, Wikimedia Commons, https://commons.wikimedia. org/wiki/File:Framework_laptop_AMD_13_DIY_setup.jpg', 'https://wanda-techs.com/pc/framework-un-pc-portable-personnalisable-a-volonte-est-en-cour/', '2026-04-13', 'published', 1, '2026-04-13 11:37:27', '2026-04-13 11:37:27'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1776080247749', 'electronique');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1776080247749', 'numerique');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1776080247749', 'technologie');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1776085350404', 'Les puces neuromorphiques', 'Neuromorphic chips', '2011',
  'Les puces neuromorphiques sont des puces électroniques qui imitent le fonctionnement du cerveau humain, avec des interactions entre des neurones artificiels. Ces puces sont très performantes et fonctionnent avec un système de capteurs (les neurones). Ces neurones sont indépendants et ne s’activent que lorsqu’ils reçoivent une information. Cela permet à ces puces électroniques de consommer très peu d’énergie, comparées aux puces électroniques classiques. Des chercheurs du MIT ont, en 2011, développé une puce imitant le chemin de communication entre des neurones. Aujourd’hui, avec le développement de l’intelligence artificielle, ce type de puces permet d’imaginer une IA plus frugale. \n', 'Neuromorphic chips are microchips that mimic the functioning of the human brain, with interactions between artificial neurons. These chips are highly efficient and operate using a network of sensors (the neurons). These neurons are independent and activate only when they receive information. This allows these electronic chips to consume very little energy compared to conventional electronic chips. In 2011, researchers at MIT developed a chip that mimics the communication pathways between neurons. Today, with the development of artificial intelligence, this type of chip makes it possible to envision a more energy-efficient AI. \n', 'Raphaël Luciani-Galais',
  '', '', NULL, NULL,
  'images/Rseau_de_neurones.jpg', 'Réseau de neurones humains, 19/03/16, Else If Then, Wikimedia Commons, https://commons.wikimedia.org/wiki/File:R%C3%A9seau_de_neurones.jpg', 'https://www.techniques-ingenieur.fr/actualite/articles/des-puces-neuromorphiques-imitent-le-cerveau-pour-etre-plus-performantes-125565/', '2026-04-13', 'published', 1, '2026-04-13 13:02:30', '2026-04-13 13:02:30'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1776085350404', 'numerique');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1776085350404', 'biomimetisme');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1776085350404', 'electronique');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1776085350404', 'technologie');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1776087661300', 'L''apprentissage fédéré', 'Federated learning', '2016',
  'Pour se former, les modèles d’intelligence artificielle ont besoin d’utiliser de grandes bases de données. Dans le cas de l''apprentissage centralisé, toutes les données sont envoyées vers un serveur central. Ces méthodes consomment une grande quantité d’énergie. Des chercheurs de l’université du Massachusetts ont calculé, en 2019, que l''entraînement d’un modèle IA de grande taille pouvait rejeter autant de CO2 que cinq voitures durant toute leur durée de vie. En 2016-2017 se développe une nouvelle technique, l’apprentissage fédéré. Il permet aux modèles IA de travailler de manière locale sur des appareils électroniques tels que des smartphones. Cette méthode comporte plusieurs avantages. Il permet de mieux protéger les données des utilisateurs et également d’économiser de l’énergie par rapport au modèle d’apprentissage centralisé. ', 'To be trained, artificial intelligence models require large databases. In the case of centralized learning, all data is sent to a central server. These methods consume a significant amount of energy. In 2019, researchers at the University of Massachusetts calculated that training a large AI model could emit as much CO2 as five cars over their entire lifetimes. In 2016–2017, a new technique emerged: federated learning. It allows AI models to operate locally on electronic devices such as smartphones. This method offers several advantages. It provides better protection for user data and also saves energy compared to the centralized learning model. ', 'Raphaël Luciani-Galais',
  '', '', NULL, NULL,
  'images/apprentissagefedere.png', 'Diagrame représentant l''apprentissage fédéré centralisé, 11/02/23, MarcT0K, Wikimedia Commons, https://commons.wikimedia.org/wiki/File:Centralized _federated_learning_protocol.png', 'https://www.cam.ac.uk/research/news/can-federated-learning-save-the-world', '2026-04-13', 'published', 1, '2026-04-13 13:41:01', '2026-04-13 13:41:01'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1776087661300', 'technologie');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1776087661300', 'numerique');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1776087661300', 'electronique');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1776090168899', 'PlantVillage: reconnaitre des maladies grâce à l''IA', 'PlantVillage: Detecting Diseases Using AI', '2016',
  'PlantVillage est une intelligence artificielle capable de diagnostiquer des maladies aux plantes à l’aide de simples photos. Elle permet également de reconnaître les invasions de parasites, de prévoir leur évolution et d’aider à les combattre. Elle a, par exemple, aidé les producteurs d’Afrique de l’Est à se prémunir contre l’invasion des acridiens en 2021. Ce modèle IA est, notamment, destiné aux petits producteurs afin de pouvoir les aider à garantir leur sécurité alimentaire. PlantVillage se base sur une base de données regroupant, notamment, des milliers de photos de plantes afin de pouvoir diagnostiquer efficacement. Une application sur smartphone permet de rendre cette innovation relativement accessible.', 'PlantVillage is an artificial intelligence system capable of diagnosing plant diseases using simple photos. It can also detect pest infestations, predict their progression, and help combat them. For example, it helped farmers in East Africa prepare for the locust swarm in 2021. This AI model is specifically designed for small-scale farmers to help them ensure food security. PlantVillage relies on a database containing thousands of plant photos to make effective diagnoses. A smartphone app makes this innovation relatively accessible.', 'Cédric Carles',
  '', '', NULL, NULL,
  'images/WhatsAppImage2026-04-13at16.20.57.jpeg', 'Liaisons liées à la septoriose sur du blé, 06/05/19, Lucky K. Mehra, Urmila Adhikari, Christina Cowger et Peter S. Ojiambo, Wikimedia Commons, https://commons.wikimedia.org/ wiki/File:Septoria_nodorum_blotch_on_wheat_glumes.png', 'https://www.actuia.com/actualite/focus-sur-plantvillage-une-solution-dintelligence-artificielle-developpee-pour-sauver-les-cultures-en-afrique/', '2026-04-13', 'published', 1, '2026-04-13 14:22:48', '2026-04-13 14:22:48'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1776090168899', 'numerique');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1776090168899', 'technologie');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1776090168899', 'agriculture');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1776090168899', 'conservation-alimentaire');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1776092589818', 'Les écrans OLED', 'OLED displays', '1987',
  'Les écrans OLED sont composés de différentes diodes électroluminescentes. Chaque pixel d’un écran OLED fonctionne indépendamment les uns des autres. Cela signifie que lorsqu''un pixel affiche la couleur noire, il est simplement éteint. Aujourd’hui, la quasi-totalité des écrans sont à cristaux liquides (ou LCD). Ces derniers consomment de l’énergie de manière constante, à l’aide d’un système de rétroéclairage (éclairage par l’arrière) continu. Cette différence de fonctionnement peut permettre à un écran OLED de consommer moins d’énergie qu’un écran LCD dans certaines conditions (lorsque le contenu affiché contient des éléments sombres et suivant le niveau de luminosité de l’écran LCD). ', 'OLED screens are made up of individual light-emitting diodes. Each pixel on an OLED screen operates independently of the others. This means that when a pixel displays black, it is simply turned off. Today, almost all screens are liquid crystal displays (or LCDs). These screens consume energy constantly, using a continuous backlighting system. This difference in operation can allow an OLED screen to consume less energy than an LCD screen under certain conditions (when the displayed content includes dark elements and depending on the brightness level of the LCD screen). ', 'Anastasia Guéguen',
  '', '', NULL, NULL,
  'images/Close_UP_photo_of_lg_c1_oled.jpg', 'Gros plan sur un écran OLED, 03/12/23, Wikimedia Commons, https://commons.wikimedia.org/wiki/File:Close_UP_photo_of_lg_c1_oled.jpg', 'https://www.aixdisplay.com/fr/blog/how-does-oled-screen-compare-to-lcd-in-energy-consumption', '2026-04-13', 'published', 1, '2026-04-13 15:03:09', '2026-04-13 15:03:09'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1776092589818', 'numerique');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1776092589818', 'electronique');
