INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1776155644383', 'les small language models', 'les small language models', '2021',
  'Les small language models (petits modèles de langage) ou SLM sont des modèles IA désignés pour répondre de manière ciblée aux besoins des utilisateurs. Ils utilisent significativement moins de paramètres que les Large language models (grands modèles de langage) ou LLM. Pour donner un ordre de grandeur, les SLM ont généralement moins de 10 milliards de paramètres contre plusieurs centaines pour les LLM. Les petits modèles sont davantage personnalisables et leur plus petite taille permet de les utiliser sur smartphones. Les SML dépensent également moins d’énergie que les LLM, les rendant plus durables. ', 'Small language models (SLMs) are AI models designed to address specific user needs. They use significantly fewer parameters than large language models (LLMs). To give an idea of the scale, SLMs typically have fewer than 10 billion parameters, compared to several hundred billion for LLMs. Small models are more customizable, and their smaller size allows them to be used on smartphones. SLMs also consume less energy than LLMs, making them more sustainable. ', 'Raphaël Luciani-Galais',
  '', '', NULL, NULL,
  'images/Man_with_smartphone_and_laptop_Unsplash.jpg', '07/05/13, Alejandro Escamilla, Wikimedia Commons, https://commons.wikimedia.org/wiki/File:Man_with_smartphone_and_laptop_(Unsplash).jpg', 'https://www.journaldunet.com/intelligence-artificielle/1539545-l-ia-de-demain-comment-les-small-et-medium-language-models-repondent-aux-enjeux-de-performance-et-d-ecologie/', '2026-04-14', 'published', 1, '2026-04-14 08:34:04', '2026-04-14 08:34:04'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1776155644383', 'numerique');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1776156063415', 'M-Pesa', 'Mobile money', '2007',
  'M-Pesa est un service de transfert d’argent et de microfinance par téléphone mobile, lancé au Kenya en 2007. Ce système repose sur l’envoi de codes et de SMS sécurisés (via la technologie USSD), permettant à ses utilisateurs d’échanger de l’argent à l''aide d''un simple téléphone portable classique, sans nécessiter de smartphone ni de connexion Internet.\nAu-delà de favoriser l''inclusion financière des populations non bancarisées, ce service encourage l''utilisation de terminaux au coût environnemental beaucoup plus faible. En effet, la surenchère technologique des smartphones a un prix écologique lourd : selon l''ADEME, la fabrication d''un smartphone nécessite d''extraire près de 200 kg de matières premières pour un appareil d''à peine 200 grammes. Ces téléphones intelligents requièrent l''utilisation d''environ 70 matériaux différents, dont une cinquantaine de métaux incluant des terres rares (néodyme, yttrium) et des minerais critiques (cobalt, tantale), dont l''extraction est très coûteuse en énergie et en eau.\n', 'M-Pesa is a mobile money transfer and microfinance service launched in Kenya in 2007. The system relies on the use of secure codes and text messages (via USSD technology), allowing users to transfer money using a standard mobile phone, without the need for a smartphone or an internet connection.\nBeyond promoting financial inclusion for the unbanked, this service encourages the use of devices with a much lower environmental cost. Indeed, the technological arms race in smartphones comes at a heavy ecological price: according to ADEME, manufacturing a smartphone requires the extraction of nearly 200 kg of raw materials for a device weighing barely 200 grams. These smartphones require the use of approximately 70 different materials, including about 50 metals such as rare earth elements (neodymium, yttrium) and critical minerals (cobalt, tantalum), the extraction of which is highly energy- and water-intensive.\n', 'Raphaël Madoré',
  'Kenya', 'Enter', 1.4419683, 38.4313975,
  'images/An_M-Pesa_Payment_Till.jpg', 'Signe à un restaurant qui autorise M-Pesa comme moyen de paiement, 30/06/12, Raidarmax, Wikimedia Commons, https://commons.wikimedia.org/wiki/File:An_M-Pesa_Payment_Till.JPG', 'https://fr.wikipedia.org/wiki/M-Pesa', '2026-04-14', 'published', 1, '2026-04-14 08:41:03', '2026-04-14 08:41:03'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1776156063415', 'numerique');
