INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1776159289113', 'Panka', 'Book', 'VI siècle av. J.-C.',
  'Un panka, punka ou ponka est un grand éventail originaire d’Orient consistant en un écran de toile que l’on suspend à un plafond et que l’on actionne ensuite au moyen d’une corde et d’une poulie.\n\nDans son sens originel sur le sous-continent indien, le terme pankha (mot hindi) désigne généralement un ventilateur portatif fabriqué à partir d’une seule feuille de palmier ou d’un carré tissé de lamelles de bambou, de rotin ou d’autres fibres végétales, que l’on peut faire tourner ou ventiler. Ces petits appareils portatifs sont encore utilisés par des millions de personnes lorsque les ventilateurs de plafond tombent en panne lors de fréquentes coupures de courant.\n\nÀ l’époque coloniale, le mot a été utilisé en Inde britannique et ailleurs dans le monde tropical et subtropical pour désigner un grand ventilateur oscillant, fixé au plafond et actionné par temps chaud. Pour couvrir une zone plus vaste, comme l’intérieur d’un bureau ou d’un palais de justice, plusieurs punkas pouvaient être reliés par des cordes afin qu’ils oscillent à l’unisson. Le matériau utilisé pouvait aller du rotin utilitaire aux tissus coûteux.\n\nLa date de cette invention est inconnue, mais elle était familière aux Arabes dès le VIIIe siècle. Son utilisation en Inde n’était pas courante avant la fin du XVIIIe siècle.\n\nLe ventilateur électrique l’a largement supplanté dans les casernes et autres grands bâtiments au début du XXe siècle.', 'A panka, punka, or ponka is a large fan originating in the East, consisting of a canvas screen that is suspended from the ceiling and operated by means of a rope and a pulley.\n\nIn its original sense on the Indian subcontinent, the term pankha (a Hindi word) generally refers to a portable fan made from a single palm leaf or a square woven from strips of bamboo, rattan, or other plant fibers, which can be rotated or waved to create a breeze. These small portable devices are still used by millions of people when ceiling fans break down during frequent power outages.\n\nDuring the colonial era, the word was used in British India and elsewhere in the tropical and subtropical world to refer to a large oscillating fan, mounted on the ceiling and operated during hot weather. To cover a larger area, such as the interior of an office or courthouse, several punkas could be connected by ropes so that they oscillated in unison. The materials used ranged from utilitarian rattan to expensive fabrics.\n\nThe date of this invention is unknown, but it was familiar to the Arabs as early as the 8th century. Its use in India was not widespread until the late 18th century.\n\nThe electric fan largely supplanted it in barracks and other large buildings in the early 20th century.', 'Marcel Robert',
  '', '', NULL, NULL,
  'images/A_woman_reading_under_a_punkah_1863_-_BL_WD_2904.jpg', 'Femme lisant sous un panka, 1863, Wikimedia Commons, https://commons.wikimedia.org/wiki/File:A_woman_reading_under_a_punkah,_1863_-_BL_WD_2904.jpg', 'https://fr.wikipedia.org/wiki/Panka', '2026-04-14', 'published', 1, '2026-04-14 09:34:49', '2026-04-14 09:34:49'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1776159289113', 'eolien');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1776160064412', 'LA TRADITION DU KORSI EN IRAN', 'THE TRADITION OF KORSI IN IRAN', 'III-VII siècles',
  'Le Korsi est une sorte de table basse couramment utilisée en Iran, avec un chauffage en dessous et des couvertures jetées par-dessus. C''est un meuble traditionnel dans la culture iranienne. Les membres de la famille s''assoient par terre autour du korsi pendant les repas et les événements spéciaux.\nLe korsi servait à l''origine à réunir les membres de la famille, mais il est également utilisé comme chauffage pendant la saison froide.\nLes gens mettaient des chauffages sous le korsi : au charbon, puis au pétrole et plus tard à l''électricité. Les familles qui n''avaient pas les moyens de s''offrir un chauffage utilisaient plutôt un trou sous le korsi : elles y faisaient du feu.\nLe tout créait une atmosphère chaleureuse pour des rencontres amicales et des bavardages.\n', 'The korsi is a type of low table commonly used in Iran, featuring a heating element underneath and blankets draped over the top. It is a traditional piece of furniture in Iranian culture. Family members sit on the floor around the korsi during meals and special occasions.\nThe korsi was originally used to bring family members together, but it is also used for heating during the cold season.\nPeople placed heaters under the korsi: first coal-fired, then oil-fired, and later electric. Families who could not afford a heater instead used a hole under the korsi, where they lit a fire.\nAll of this created a warm atmosphere for friendly gatherings and conversation.\n', 'Cédric Carles',
  'Iran', 'I ran', 32.6475314, 54.5643516,
  'images/korsi.png', 'Célébration de la fête de Yalda autour d''un korsi', 'https://en.wikipedia.org/wiki/Korsi', '2026-04-14', 'published', 1, '2026-04-14 09:47:44', '2026-04-14 09:47:44'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1776160064412', 'rechauffer');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1776160567522', 'RAFRAÎCHISSEMENT NATUREL AVEC LE KHUS EN INDE', 'NATURAL REFRESHMENT WITH KHUS IN INDIA', 'VI siècle av. J.-C.',
  'Les racines parfumées du vétiver, également connues sous le nom de khus (nom biologique Chrysopogon zizanioides), sont utilisées pour refroidir l’eau des matkas. Ils sont également tissés dans des nattes appelées Khus tatties qui sont accrochées aux fenêtres et aux portes, refroidissant ainsi l’air qui les traversait.\n\nJusque dans les années 1990, les climatiseurs étaient trop chers. Les climatiseurs à évaporation, installés en équilibre précaire sur des pilotis ou des rebords de fenêtre, constituaient la meilleure protection que de nombreuses familles de la classe moyenne pouvaient exercer contre la chaleur estivale.\n\nCes refroidisseurs étaient des engins métalliques distinctifs avec des tapis de vétiver intégrés dans leurs côtés à lattes et des ventilateurs intégrés remplissaient l’air d’un bourdonnement fort. Une partie de l’appareil était remplie d’eau, imbibant les nattes de vétiver. L’air chaud extérieur se refroidissait en traversant les nattes humides et en pénétrant dans la cage, et le ventilateur soufflait cet air frais et humide dans la pièce.\n\nIl est intéressant de noter qu’Abul Fazl, dans son livre « Ain-i-Akbari », dit que c’est l’empereur moghol Akbar lui-même qui a été le premier à concevoir le concept d’utilisation de tapis khus comme écrans de refroidissement. Cependant, c’est à l’époque coloniale que l’idée a pris de l’ampleur.', 'The fragrant roots of vetiver, also known as khus (scientific name Chrysopogon zizanioides), are used to cool the water in matkas. They are also woven into mats called khus tatties, which are hung over windows and doors to cool the air passing through them.\n\nUntil the 1990s, air conditioners were too expensive. Evaporative coolers, precariously balanced on stilts or window sills, offered the best protection many middle-class families could muster against the summer heat.\n\nThese coolers were distinctive metal contraptions with vetiver mats woven into their slatted sides, and built-in fans filled the air with a loud hum. Part of the unit was filled with water, soaking the vetiver mats. The hot outside air cooled as it passed through the damp mats and entered the cage, and the fan blew this cool, moist air into the room.\n\nIt is interesting to note that Abul Fazl, in his book “Ain-i-Akbari,” states that it was the Mughal Emperor Akbar himself who first conceived the idea of using khus mats as cooling screens. However, it was during the colonial era that the idea gained widespread adoption.', 'Rameez Sayed',
  'Inde', 'Inside', 22.3511148, 78.6677428,
  'images/khus.png', '', 'https://sencessa.com/blogs/news/khus-the-timeless-cool-in-india-s-brutal-summer-grip', '2026-04-14', 'published', 1, '2026-04-14 09:56:07', '2026-04-14 09:56:07'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1776160567522', 'rafraichir');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1776162187814', 'Presse à énergie solaire A. Mouchot & A. Pifre', 'Solar-powered press by A. Mouchot & A. Pifre', '1882',
  'L’ingénieur Abel Pifre, d’abord assistant puis collaborateur d’Augustin Mouchot, est proche des travaux de ce dernier, et s’inspire de ses concentrateurs solaires. Lors du meeting de l’Union Française de la Jeunesse au jardin des Tuileries le 6 août 1882, il utilise un concentrateur solaire pour alimenter en force mécanique une presse Marinoni capable de tirer jusqu’à 500 exemplaires par heure d’un journal, nommé pour l’occasion « Soleil-Journal ».\nL’équipe de recherche Paléo-énergétique est en recherche active d’un exemplaire du Soleil-Journal imprimé lors de la démonstration au jardin des Tuileries. Cette pièce à conviction d’une transition énergétique d’avant garde fait partie d’un patrimoine à retrouver impérativement. \nMerci de signaler à l’équipe de l’Atelier 21 tout indice ou piste de recherche sérieuse à notre rédaction : hello@paleo-energetique.org.\n\n\n', 'Engineer Abel Pifre, who began as an assistant to Augustin Mouchot and later became his colleague, was closely involved in Mouchot’s work and drew inspiration from his solar concentrators. During the meeting of the Union Française de la Jeunesse in the Tuileries Garden on August 6, 1882, he used a solar concentrator to power a Marinoni press capable of printing up to 500 copies per hour of a newspaper named for the occasion “Soleil-Journal.”\nThe Paleo-Energy research team is actively searching for a copy of the Soleil-Journal printed during the demonstration at the Tuileries Garden. This artifact, evidence of a pioneering energy transition, is part of a heritage that must be recovered. \nPlease report any clues or serious leads to the Atelier 21 team at our editorial office: hello@paleo-energetique.org.\n\n\n', 'Eric Boros',
  'Paris', 'Paris', 48.8534951, 2.3483915,
  'images/Mouchot1878x.jpg', 'Concentrateur solaire d''Augustin Mouchot, 19/10/1878, Jules Férat, Le Monde illustré, https://commons.wikimedia.org/wiki/File:Mouchot1878x.jpg', 'https://fr.wikipedia.org/wiki/Augustin_Mouchot', '2026-04-14', 'published', 1, '2026-04-14 10:23:07', '2026-04-14 10:23:07'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1776162187814', 'solaire');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1776164550312', 'Les marmites norvégiennes', 'Norwegian cooking pots', 'Fin XIX siècle',
  'La marmite norvégienne, ou cuiseur inertiel passif, est un dispositif de cuisson économe en énergie. Son principe consiste à chauffer des aliments de manière traditionnelle pendant une courte période, puis à les placer dans un contenant isolant (caisse garnie de foin, couverture, polystyrène, etc.), où ils continuent de cuire lentement sans apport supplémentaire de chaleur. \n\nUtilisée depuis des siècles dans diverses cultures, cette méthode a été particulièrement popularisée durant les deux guerres mondiales. Elle avait déjà suscité un intérêt notable à la fin du XIXe siècle, époque à laquelle un brevet fut déposé pour des "cuisines automatiques norvégiennes". \n\nLa marmite norvégienne permet de réduire la consommation d''énergie liée à la cuisson, tout en préservant les nutriments et les saveurs des aliments. ', 'The Norwegian pot, or passive inertial cooker, is an energy-efficient cooking device. It works by heating food in the traditional way for a short period, then placing it in an insulated container (a box lined with hay, a blanket, polystyrene, etc.), where it continues to cook slowly without any additional heat. \n\nUsed for centuries in various cultures, this method became particularly popular during the two world wars. It had already attracted significant interest by the late 19th century, when a patent was filed for "Norwegian automatic cookers." \n\nThe Norwegian pot reduces energy consumption associated with cooking while preserving the nutrients and flavors of the food. ', 'Clara Loisel',
  '', '', NULL, NULL,
  'images/Gpelschauermuseum_Seestermhe_09_cropped.jpg', 'Marmite norvégienne, 24/09/10, Huhu Uet, Wikimedia Commons, https://commons.wikimedia.org/wiki/File:G%C3%B6pelschauermuseum_Seesterm%C3%BChe_09_(cropped).jpg', 'https://reporterre.net/La-marmite-norvegienne-la-cuisson-ecolo-qui-ringardise-le-Thermomix', '2026-04-14', 'published', 1, '2026-04-14 11:02:30', '2026-04-14 11:02:30'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1776164550312', 'conservation-de-lenergie');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1776165326062', 'I.S.A. BRIQUES EN TERRE CUITE IMPRIMÉES EN 3D', 'I.S.A. 3D-Printed Clay Bricks', '2023',
  'Les briques biodiversitaires I.S.A., Isolantes, Structurantes, Accueillantes sont des prototypes en terre cuite réalisés en impression 3D pour constituer par assemblage un nouveau type de mur biodiversitaire.\n\nLa nouveauté du concept de paroi biodiversitaire réside dans la capacité du végétal à s’implanter de manière pérenne dans une épaisseur de substrat intégrée dans la composition du mur.\n\nPour que les façades incarnent non seulement l’aspect extérieur de nos bâtiments mais puissent également être support de vivant, dans une conception plus vaste sur l’intégration de la nature dans l’architecture.\n\nLes briques biodiversitaires I.S.A. sont inspirées d’éléments de construction en terre cuite répandus comme les briques alvéolées type « monomur » qui allient des caractéristiques structurelles et isolantes. \n\nCette recherche a été menée dans le cadre du projet de master de Nathanaël Zbynovsky à l’ENSCI-Les Ateliers, accueilli en contrat de professionnalisation au Pôle Recherche de l’agence ChartierDalix.\n', 'The I.S.A. biodiversity bricks—Insulating, Structuring, and Welcoming—are 3D-printed terracotta prototypes designed to be assembled into a new type of biodiversity wall.\n\nThe innovation of the biodiversity wall concept lies in the ability of plants to take root permanently within a layer of substrate integrated into the wall’s structure.\n\nSo that facades not only embody the exterior appearance of our buildings but can also serve as a medium for living organisms, within a broader vision of integrating nature into architecture.\n\nThe I.S.A. biodiversity bricks are inspired by common terracotta building elements such as “Monomur”-type hollow bricks, which combine structural and insulating properties. \n\nThis research was conducted as part of Nathanaël Zbynovsky’s master’s project at ENSCI-Les Ateliers, carried out under a professional training contract at the Research Division of the ChartierDalix agency.\n', 'Simon Bouchaudy',
  '', '', NULL, NULL,
  'images/isa-briques-terre-cuite-imprimees-3d-parois-vivantes-07.jpg', 'Briques I.S.A., https://www.chartier-dalix.com/fr/ressources/isa-briques-terre-cuite-imprimees-3d-parois-vivantes', 'https://www.chartier-dalix.com/fr/ressources/isa-briques-terre-cuite-imprimees-3d-parois-vivantes', '2026-04-14', 'published', 1, '2026-04-14 11:15:26', '2026-04-14 11:15:26'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1776165326062', 'construction');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1776165326062', 'conservation-de-lenergie');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1776176174285', 'S’INSPIRER DU VIVANT POUR ADAPTER L’ARCHITECTURE', 'DRAWING INSPIRATION FROM THE NATURAL WORLD TO ADAPT ARCHITECTURE', '1996',
  'Le pôle d''excellence en biomimétisme marin est un projet qui a été lancé par la Communauté d''agglomération du Pays Basque qui demandait une construction biomimétique. Le projet est inspiré d''Epleuctella aspergillum, une éponge de verre. Les éponges de verre génèrent un squelette adapté aux conditions environnementales. Ce squelette permet de filtrer, absorber, oxygéner l''eau et d''apporter des nutriments.\n\nInspiré du même principe, une brique de terre crue est utilisée et assemblée sous forme de voûtes maçonnées. La forme de ces voûtes permet la circulation de l''eau, sa filtration, sa rétention, son traitement pour la rendre propre à l''océan, et permettre d''avoir une régulation de la température, de l''hygrométrie, de l''ensoleillement.\n', 'The Center of Excellence in Marine Biomimicry is a project launched by the Basque Country Urban Community, which requested a biomimetic structure. The project is inspired by Epleuctella aspergillum, a glass sponge. Glass sponges generate a skeleton adapted to environmental conditions. This skeleton filters, absorbs, and oxygenates water while providing nutrients.\n\nInspired by the same principle, raw earth bricks are used and assembled into masonry vaults. The shape of these vaults allows for water circulation, filtration, retention, and treatment to make it suitable for the ocean, while also regulating temperature, humidity, and sunlight.\n', 'Cédric Carles',
  '', '', NULL, NULL,
  'images/eponge.png', '', '', '2026-04-14', 'published', 1, '2026-04-14 14:16:14', '2026-04-14 14:16:14'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1776176174285', 'biomimetisme');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1776176174285', 'construction');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1776244083385', 'LA LOI REEN ET L''INDICE DE RÉPARABILITÉ', 'THE REEN LAW AND THE REPAIRABILITY INDEX', '2021',
  'Description : En 2021, la France s''est illustrée comme pionnière dans la régulation de l''impact écologique des technologies avec la promulgation de la loi REEN (Réduction de l''Empreinte Environnementale du Numérique). Cette législation vise à responsabiliser l''ensemble des acteurs face à la surproduction et au gaspillage électronique liés à nos usages technologiques.\n\nL''une des mesures phares de cette loi est l''instauration de l''« indice de réparabilité ». Ce dispositif impose aux constructeurs d''afficher obligatoirement une note sur 10 sur plusieurs catégories de produits, notamment les smartphones, les ordinateurs portables et les téléviseurs. Ce score évalue de manière transparente des critères tels que : la facilité de démontage de l''appareil, l''accessibilité de la documentation technique ou la disponibilité et le prix des pièces détachées. En orientant l''acte d''achat, cet indice combat l''obsolescence (qu''elle soit programmée ou non) et encourage la conception d''équipements réparables.\n\nLa loi REEN  oblige également l''État, les mairies et les collectivités territoriales à consacrer au moins 20 % de leurs achats d''équipements informatiques et de télécommunications à du matériel reconditionné ou de seconde main. Par ces mesures, cette loi marque une transition décisive d''une économie numérique linéaire (extraire, fabriquer, jeter) vers une économie circulaire favorisant activement le réemploi et l''allongement de la durée de vie du matériel.\n', 'Description: In 2021, France emerged as a pioneer in regulating the environmental impact of technology with the enactment of the REEN Act (Reduction of the Digital Environmental Footprint). This legislation aims to hold all stakeholders accountable for the overproduction and electronic waste associated with our use of technology.\n\nOne of the key measures of this law is the introduction of the “repairability index.” This system requires manufacturers to display a score out of 10 for several product categories, including smartphones, laptops, and televisions. This score transparently evaluates criteria such as: how easy the device is to disassemble, the accessibility of technical documentation, and the availability and price of replacement parts. By influencing purchasing decisions, this index combats obsolescence (whether planned or not) and encourages the design of repairable equipment.\n\nThe REEN Act also requires the federal government, city governments, and local authorities to allocate at least 20% of their IT and telecommunications equipment purchases to refurbished or secondhand equipment. Through these measures, this law marks a decisive transition from a linear digital economy (extract, manufacture, discard) to a circular economy that actively promotes reuse and extends the lifespan of equipment.\n', 'Raphaël Madoré',
  'France', 'France', 46.603354, 1.8883335,
  'images/loireen.png', 'Loi REEN, https://www.appyuser.com/guide/loi-reen-impact-numerique/', 'https://www.appyuser.com/guide/loi-reen-impact-numerique/', '2026-04-15', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1776244083385', 'numerique');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1776244083385', 'politique-publique');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1776244096073', 'L''ARCHITECTURE X-ROAD ET LE PRINCIPE « DITES-LE-NOUS UNE FOIS »', 'THE X-ROAD ARCHITECTURE AND THE "TELL US ONCE" PRINCIPLE', '2001',
  'Reconnue comme l''État le plus numérisé au monde, l''Estonie a fondé son administration électronique sur un principe légal d''une grande efficacité : le « Dites-le-nous une fois » (Once-Only). La loi interdit formellement à une administration de demander à un citoyen une information qu''il a déjà fournie à un autre service public.\n\nPour rendre ce principe opérationnel, le pays a déployé dès 2001 l''architecture réseau X-Road. Contrairement aux modèles informatiques traditionnels, il n''existe aucune gigantesque base de données centrale stockant l''ensemble des données de la population. Le système repose au contraire sur un réseau d''échange décentralisé : les informations restent réparties sur une multitude de petits serveurs locaux appartenant aux différentes institutions. Ces serveurs communiquent entre eux de manière sécurisée et chiffrée, s''échangeant la donnée en pair-à-pair et uniquement lorsque cela est strictement nécessaire à une démarche.\n\nCe modèle d''infrastructure est un cas d''école de frugalité numérique et de minimisation de la donnée. En empêchant la duplication systématique et le stockage massif d''informations redondantes, l''Estonie s''épargne la construction et la maintenance de centres de données (data centers) surdimensionnés et énergivores. L''architecture X-Road prouve ainsi qu''une numérisation généralisée peut parfaitement s''aligner avec une démarche d''efficience logicielle et de sobriété matérielle.\n', 'Recognized as the most digitized country in the world, Estonia has based its e-government on a highly effective legal principle: “Tell us once” (Once-Only). The law expressly prohibits any government agency from asking a citizen for information that they have already provided to another public service.\n\nTo put this principle into practice, the country deployed the X-Road network architecture as early as 2001. Unlike traditional IT models, there is no massive central database storing all of the population’s data. Instead, the system relies on a decentralized exchange network: information remains distributed across a multitude of small local servers belonging to different institutions. These servers communicate with each other securely and in an encrypted manner, exchanging data peer-to-peer and only when strictly necessary for a specific process.\n\nThis infrastructure model is a textbook example of digital frugality and data minimization. By preventing the systematic duplication and massive storage of redundant information, Estonia avoids the construction and maintenance of oversized, energy-intensive data centers. The X-Road architecture thus demonstrates that widespread digitization can be perfectly aligned with an approach focused on software efficiency and hardware frugality.\n', 'Raphaël Madoré',
  'Estonie', 'Estonia', 58.7523778, 25.3319078,
  'images/Hands-woman-laptop-notebook_24217008462.jpg', 'Wikimedia Commons, https://commons.wikimedia.org/wiki/File:Hands-woman-laptop-notebook_(24217008462).jpg', 'https://loti.london/blog/estonia-insights/', '2026-04-15', 'published', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1776244096073', 'numerique');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1776244894070', 'Apprentissage Continu : Contre l''amnésie écologique de l''IA', 'Continuous Learning: Combating AI''s Ecological Amnesia', '2025',
  'L’''un des plus grands défis de l''intelligence artificielle est ce que les chercheurs nomment l''« oubli catastrophique ». Si un modèle est entraîné à reconnaître des chiens, puis qu''on lui enseigne ensuite à identifier des chats, la mise à jour de ses paramètres écrase ses connaissances précédentes : il oublie ce qu''est un chien. Pour pallier cette amnésie logicielle, la méthode standard consiste à ré-entraîner la machine entièrement depuis le début, en lui fournissant simultanément les images de chiens et de chats.\n\nCette obligation de repartir de zéro à chaque nouvelle compétence a un coût environnemental fort. L''entraînement des algorithmes modernes nécessite de faire tourner des milliers de processeurs à plein régime pendant des semaines, engloutissant des quantités colossales d''électricité et générant une empreinte carbone massive.\n\nL''apprentissage continu (Continual Learning) est un domaine de recherche novateur qui s''attaque à cette aberration énergétique. En s''inspirant de la plasticité du cerveau humain, cette approche permet aux modèles d''IA d''assimiler de nouvelles informations « à la volée » tout en verrouillant leurs acquis antérieurs. Cette évolution est un pilier fondamental de l''éco-conception en intelligence artificielle : en évitant les ré-entraînements perpétuels, elle promet de rendre le développement technologique beaucoup plus sobre et durable.', 'One of the biggest challenges in artificial intelligence is what researchers call “catastrophic forgetting.” If a model is trained to recognize dogs and is then taught to identify cats, updating its parameters overwrites its previous knowledge: it forgets what a dog is. To overcome this software amnesia, the standard method is to retrain the machine entirely from scratch, simultaneously providing it with images of both dogs and cats.\n\nThis requirement to start from scratch with every new skill comes at a significant environmental cost. Training modern algorithms requires running thousands of processors at full capacity for weeks, consuming colossal amounts of electricity and generating a massive carbon footprint.\n\nContinual Learning is an innovative field of research that addresses this energy-intensive issue. Inspired by the plasticity of the human brain, this approach allows AI models to assimilate new information “on the fly” while retaining their prior knowledge. This development is a fundamental pillar of eco-design in artificial intelligence: by avoiding perpetual retraining, it promises to make technological development much more efficient and sustainable.', 'Raphaël Madoré',
  'Etats-Unis', 'United States', 39.7837304, -100.445882,
  'images/continuallearning.webp', 'https://spotintelligence.com/2023/10/03/continual-learning/', 'https://medium.com/@istabrak.abbes_65953/what-is-continual-learning-491ed9e3874d', '2026-04-15', 'published', 1, '2026-04-15 09:21:34', '2026-04-15 09:21:34'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1776244894070', 'numerique');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1776245761863', 'datafarm', 'data farm', '2025',
  'Face à l''impact environnemental croissant du secteur numérique (les centres de données génèrent environ 3 % des émissions mondiales de gaz à effet de serre, un chiffre amené à doubler), l''entreprise française Datafarm a imaginé une synergie inédite entre technologie et agriculture. Le concept consiste à installer des data centers directement au sein d''exploitations agricoles équipées de méthaniseurs.\n\nCe système repose sur une boucle énergétique d''économie circulaire grâce à la cogénération. Les biodéchets de la ferme (effluents d''élevage, résidus végétaux) alimentent un méthaniseur qui fabrique du biogaz, générant ainsi de l''électricité et de la chaleur. L''électricité sert à faire fonctionner les serveurs informatiques, tandis que la chaleur perdue du moteur est transformée pour produire le froid nécessaire à la climatisation du data center. En retour, la chaleur émise par les serveurs fonctionnant en continu est entièrement restituée à l''agriculteur pour ses propres besoins en chauffage.\n\nEn associant la bouse de vache à l''hébergement de données, ce procédé permet de faire passer le rendement énergétique de l''installation de 40 % à 80 %. Au-delà de proposer une puissance de calcul neutre en carbone et décentralisée, cette innovation offre aux agriculteurs un complément de revenus et conditionne l''arrivée de la fibre optique dans les campagnes, participant ainsi à la revitalisation des territoires ruraux.\n', 'In response to the growing environmental impact of the digital sector (data centers generate about 3% of global greenhouse gas emissions, a figure expected to double), the French company Datafarm has devised a unique synergy between technology and agriculture. The concept involves installing data centers directly on farms equipped with anaerobic digesters.\n\nThis system relies on a circular economy energy loop enabled by cogeneration. The farm’s bio-waste (livestock manure, plant residues) feeds a digester that produces biogas, thereby generating electricity and heat. The electricity is used to power the computer servers, while the waste heat from the engine is converted to produce the cooling needed for the data center’s air conditioning. In return, the heat emitted by the continuously running servers is entirely returned to the farmer for their own heating needs.\n\nBy combining cow manure with data hosting, this process increases the facility’s energy efficiency from 40% to 80%. Beyond providing carbon-neutral and decentralized computing power, this innovation offers farmers a source of supplemental income and facilitates the rollout of fiber-optic infrastructure in rural areas, thereby contributing to the revitalization of rural communities.\n', 'Raphaël Madoré',
  'Evry ', 'Evry ', 48.6241665, 2.4289667,
  'images/Unit_de_mthanisation_au_Garrit_Haut.jpg', 'Unité de méthanisation à Mayrac (Lot), 24/09/17, GrandBout, Wikimedia Commons, https://commons.wikimedia.org/wiki/File:Unit%C3%A9_de_m%C3%A9thanisation_au_Garrit_Haut.jpg', 'https://www.techelevage.fr/datafarm-methanisation/', '2026-04-15', 'published', 1, '2026-04-15 09:36:01', '2026-04-15 09:36:01'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1776245761863', 'numerique');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1776245761863', 'agriculture');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1776247891506', 'Réseau radio maillé', 'Mesh radio network', 'Années 2000',
  'Un réseau radio maillé est un réseau constitué de nœuds (émetteurs radios) qui échangent des informations sans fil (sur les ondes radio). Des informations peuvent être échangées entre chaque émetteur, et un appareil peut être connecté directement au réseau s’il est à portée. Cela permet de créer un système très résilient : si un émetteur est indisponible, l’information passe par un autre chemin disponible. Aujourd’hui, ce genre de réseau est utilisé pour la communication de drones ou de robots par exemple. ', 'A mesh radio network is a network consisting of nodes (radio transmitters) that exchange information wirelessly (via radio waves). Information can be exchanged between each transmitter, and a device can connect directly to the network if it is within range. This creates a highly resilient system: if one transmitter is unavailable, the information takes another available route. Today, this type of network is used for communication by drones or robots, for example. ', 'Anastasia Guéguen',
  '', '', NULL, NULL,
  'images/mesh.png', 'Réseau maillé, 24/01/26, Superspritz, Wikimedia Commons, https://commons.wikimedia.org/wiki/File:802.11s_Meshed_Network_Architecture.svg', 'https://mobilicom.com/insight/mesh-radio-networks-how-they-work-and-why-they-matter/', '2026-04-15', 'published', 1, '2026-04-15 10:11:31', '2026-04-15 10:11:31'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1776247891506', 'numerique');

