INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1770988261628', 'Lancement d’une étude pour étudier le potentiel de récupération de chaleur provenant des eaux usées en Seine-Saint-Denis', '', '2013',
  'Les eaux usées ont une température stable pendant l''année, ce qui permet d’envisager de récupérer une partie de cette chaleur pour chauffer ou climatiser des bâtiments. Cette technologie est déjà utilisée en Suisse (ex: maison de retraite Hofmatt près de Bâle) et en Allemagne notamment.  Pour que cette technologie soit économiquement viable, le débit des eaux usées ne doit pas être inférieur à 10 à 12 l/s. Ce débit est souvent atteint proche des stations d’épuration, dans des zones éloignées des agglomérations. La chaleur est donc transmise à un échangeur de chaleur avant d’être réutilisée par des pompes à chaleur classiques. Une étude pour déterminer le potentiel de récupération de chaleur en Seine Saint-Denis a été réalisée en 2013, suivie d’une seconde étude en 2018. En 2019, une cartographie des réseaux où de la récupération de chaleur est envisageable a été réalisée. \n', '', 'Groupama',
  'Seine-Saint-Denis', '', 48.9098125, 2.4528635,
  '', '', 'https://astee-tsm.fr/articles/tsm-1-2-2020-petrucci/', '2026-02-13', 'draft', 0, '2026-02-13 13:11:01', '2026-02-13 13:11:01'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1770988261628', 'h2o');
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1770988261628', 'rechauffer');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1770988552186', 'Programme TVGEP « Conception des Toitures Végétalisées pour la Gestion des Eaux Pluviales urbaines »', '', '2010',
  'L’agglomération parisienne est l’espace avec la plus grande proportion de sols artificialisés de France. Cela a pour effet de renforcer les dynamiques de ruissellements et d’augmenter le risque d’inondation. La végétalisation des toitures est un moyen de limiter ces ruissellements. En effet, lors des épisodes de précipitations, une partie de l’eau est évapotranspirée, une autre s’écoule et une autre reste dans l’horizon végétale et sera évapotranspirée ou écoulée ultérieurement. La présence d’une toiture végétalisée réduit donc la quantité d’eau ruisselée.  Le programme TVGEP “Conception des toitures Végétalisées pour la Gestion des Eaux Pluviales urbaines” encourage la mise en place de ce genre de toitures. Un exemple intéressant est la toiture de la Direction de l’Eau et de l’Assainissement du conseil général de la Seine-Saint-Denis à Rosny-sous-Bois qui est recouvert de 20cm de terre végétale et des graminés. Cette toiture permet de retenir 70% des précipitations annuelles. ', '', 'Anastasia Guéguen',
  'France', '', 46.603354, 1.8883335,
  '', '', 'https://www.cerema.fr/system/files/documents/2023/11/guide_des_toitures_terrasses_vegetalisees_et_gestion_des_eaux_pluviales_-_2017.pdf', '2026-02-13', 'draft', 0, '2026-02-13 13:15:52', '2026-02-13 13:15:52'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1770988552186', 'h2o');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1771240444443', 'Lancement de la collection BERGVATTNET par IKEA', '', '2025',
  'En 2025, l’enseigne suédoise IKEA lance la collection BERGVATTNET, centrée sur l’économie d’eau dans nos salles de bain. Dans cette gamme, on retrouve par exemple un saut de 8 litres, proposé par la designer Hanna-Kaarina Heikkilä et destiné à recueillir l’eau non-utilisée lorsqu’on attend que notre douche chauffe. Cette eau peut ensuite être réemployée, pour arroser des plantes par exemple. On retrouve également un compteur de douche indiquant, par le designer Marcus Arvonen, indiquant la consommation d’eau ainsi que la température. L’objectif est d’inviter les utilisateurs à prendre des douches plus courtes. ', '', 'Loïc Rogard',
  'Suède', '', 59.6749712, 14.5208584,
  '', '', 'https://www.ikea.com/fr/fr/new/collection-bergvattnet-pub373fc620/', '2026-02-16', 'draft', 0, '2026-02-16 11:14:04', '2026-02-16 11:14:04'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771240444443', 'h2o');

INSERT INTO cartels (id, titre, titre_en, annee, description, description_en, exhume_par, location, location_en, lat, lng, image_path, image_credit, url_qr, date, status, visible, created_at, updated_at) VALUES (
  '1771518840487', 'HUMUS44, location de toilettes sèches pour des évènements festifs', '', '2001',
  'HUMUS44 est une association qui propose la location de toilettes sèches pour des évènements festifs en Loire-Atlantique. Cette solution permet d’économiser de l’eau dans un contexte de changement climatique, mais également d’apporter une réponse pour les endroits avec un approvisionnement en eau difficile. Par ailleurs, l’association propose des fiches pédagogiques sur l’écologie et organise également depuis 2003 un festival annuel d’écologie appelé “Nature en Fête”. \n', '', 'Atelier étudiants Paris 1',
  'Loire-Atlantique', '', 47.3481615, -1.8727461,
  'images/toilettesscheshumus44.jpg', 'Humus 44,https://www.bioetbienetre.fr/association-humus-44/s25520.html', 'https://www.bioetbienetre.fr/association-humus-44/s25520.html', '2026-02-19', 'draft', 0, '2026-02-19 16:34:00', '2026-02-19 16:34:00'
);
INSERT INTO cartel_categories (cartel_id, category_id) VALUES ('1771518840487', 'h2o');

